-- Poems batch 335
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('9d598550-9a4d-49d4-b38e-f393b37ad72a','再用前韵酬達夫  其三','劉弇','宋','宋诗','song-poetry','','[]','擷蘂攀枝得似狂，未拚身世事乾忙。',32,'全唐诗/poet.song.59000.json','["擷蘂攀枝得似狂，未拚身世事乾忙。", "羽翰不借還家夢，鑰牡銜魚抱繚牆。"]'),
('68b20ebe-68a5-45c3-97de-c0ab37bf4694','再用前韵酬達夫  其四','劉弇','宋','宋诗','song-poetry','','[]','花爲妝成長近妬，水將藍比不多爭。',32,'全唐诗/poet.song.59000.json','["花爲妝成長近妬，水將藍比不多爭。", "陽和滅裂窮塗望，獨許侯家擅四并。"]'),
('eaefc096-917c-434a-86fa-1952e3b484a5','再用前韵酬達夫  其五','劉弇','宋','宋诗','song-poetry','','[]','百鬼揶揄成故態，一胸塊磊信重圍。',32,'全唐诗/poet.song.59000.json','["百鬼揶揄成故態，一胸塊磊信重圍。", "沉清酇白平治得，請傍東皇振旅歸。"]'),
('93b6e052-21e4-41d2-bf51-7e1aaa8611d1','再用前韵酬達夫  其六','劉弇','宋','宋诗','song-poetry','','[]','岸柳禁持人學舞，牆花勾引客窺鄰。',32,'全唐诗/poet.song.59000.json','["岸柳禁持人學舞，牆花勾引客窺鄰。", "速將事當悠悠夢，剩買歡歸衮衮身。"]'),
('97dafb08-6a50-42b8-a143-c0331cdf3c9a','再用前韵酬達夫  其七','劉弇','宋','宋诗','song-poetry','','[]','直取浩歌論纂纂，肯容三爵徑油油。',32,'全唐诗/poet.song.59000.json','["直取浩歌論纂纂，肯容三爵徑油油。", "送花明月憐人殺，怗體紅波凝不流。"]'),
('1dd36319-078b-40b7-a35a-f3b781aa5b07','再用前韵酬達夫  其八','劉弇','宋','宋诗','song-poetry','','[]','露房霞頰迎人笑，訂訂芳菲第幾流。',32,'全唐诗/poet.song.59000.json','["露房霞頰迎人笑，訂訂芳菲第幾流。", "黄四娘家無數夢，玄都觀裏一番愁。"]'),
('ecbddc25-4f7d-4e61-b912-bfc153da3bcf','再用前韵酬達夫  其九','劉弇','宋','宋诗','song-poetry','','[]','罰籌滿把槽仍滴，鱠手千刀刃必迎。',32,'全唐诗/poet.song.59000.json','["罰籌滿把槽仍滴，鱠手千刀刃必迎。", "春若背教花不老，恣挨紅陣燥瑶觥。"]'),
('f7dc95b5-0785-4b83-b179-e757f22da162','再用前韵酬達夫  其一○','劉弇','宋','宋诗','song-poetry','','[]','闊疏未可輕愚叟，放浪多應學漫郎。',32,'全唐诗/poet.song.59000.json','["闊疏未可輕愚叟，放浪多應學漫郎。", "待挽春工醉鄉去，隨教蜂蝶笑雄張。"]'),
('515ac719-51c8-4cfb-93ff-ca6e6e0fe8ba','三用前韵酬達夫  其一','劉弇','宋','宋诗','song-poetry','','[]','掠風社燕窺簾入，閣雨溪桃結子慵。',32,'全唐诗/poet.song.59000.json','["掠風社燕窺簾入，閣雨溪桃結子慵。", "莫笑嫵眉等閑畫，藁砧情地勝春醲。"]'),
('8ed67bd2-b094-4fc1-b047-a2052ed434ce','三用前韵酬達夫  其二','劉弇','宋','宋诗','song-poetry','','[]','花氣曛曛活逼樓，十分大白直須浮。',32,'全唐诗/poet.song.59000.json','["花氣曛曛活逼樓，十分大白直須浮。", "自憐短髮如烟薄，敢買鈿車貯莫愁。"]'),
('cfe2a685-f1e0-45e7-8eea-a13b9643100a','三用前韵酬達夫  其三','劉弇','宋','宋诗','song-poetry','','[]','柳挽花搴獨自狂，鼓催鐘趁幾人忙。',32,'全唐诗/poet.song.59000.json','["柳挽花搴獨自狂，鼓催鐘趁幾人忙。", "重城特解春將閉，時放紅英笑女牆。"]'),
('bcb9e721-6c6d-4929-86a5-18b06ef38f0a','三用前韵酬達夫  其四','劉弇','宋','宋诗','song-poetry','','[]','得喪三分徒鼎峙，是非兩角謾蝸爭。',32,'全唐诗/poet.song.59000.json','["得喪三分徒鼎峙，是非兩角謾蝸爭。", "人情不似春情好，一氣無私見合并。"]'),
('656091c3-d1cf-43af-b0d6-a1b8d8b8b927','三用前韵酬達夫  其五','劉弇','宋','宋诗','song-poetry','','[]','閑殺篩風釀雨時，可憐腰带漸寬圍。',32,'全唐诗/poet.song.59000.json','["閑殺篩風釀雨時，可憐腰带漸寬圍。", "何因徑作江南夢，泛取圖中竹葉歸。"]'),
('344e6755-2d63-47dd-8c6e-ec16c5019c1e','三用前韵酬達夫  其六','劉弇','宋','宋诗','song-poetry','','[]','關關柳幄鶑懷友，曳曳花房蝶乞鄰。',32,'全唐诗/poet.song.59000.json','["關關柳幄鶑懷友，曳曳花房蝶乞鄰。", "未羨西園冠蓋客，稍關南浦別離身。"]'),
('5d9cf216-095f-46db-a54d-52c527e6fb08','三用前韵酬達夫  其七','劉弇','宋','宋诗','song-poetry','','[]','蹀驄草媚障泥錦，結妓花烘壓杏油。',32,'全唐诗/poet.song.59000.json','["蹀驄草媚障泥錦，結妓花烘壓杏油。", "梁父吟輸醉鄉客，拋毬樂稱曲家流。"]'),
('777fc46e-6427-4013-a7e9-b8019e8c5451','三用前韵酬達夫  其八','劉弇','宋','宋诗','song-poetry','','[]','駢棘重關不自由，橫將匏繫代萍流。',32,'全唐诗/poet.song.59000.json','["駢棘重關不自由，橫將匏繫代萍流。", "飛絲莫罥林塘興，留與騷人作四愁。"]'),
('19c3859d-e2f8-4af6-8396-6c1f25b98ebe','三用前韵酬達夫  其九','劉弇','宋','宋诗','song-poetry','','[]','酒徒博醉貂龜解，社老賽神簫鼓迎。',32,'全唐诗/poet.song.59000.json','["酒徒博醉貂龜解，社老賽神簫鼓迎。", "未省撥忙酬燥吻，壁端贏得掛空觥。"]'),
('bed79487-f6d1-4c08-8845-c8bc5f418f30','三用前韵酬達夫  其一○','劉弇','宋','宋诗','song-poetry','','[]','它日江淹曾賦恨，幾人顔駟尚潜郎。',32,'全唐诗/poet.song.59000.json','["它日江淹曾賦恨，幾人顔駟尚潜郎。", "年來春事稠于髮，莫把哀絲爲急張。"]'),
('d542ca75-1720-414d-b937-05c1c3ee81c9','四用前韵酬達夫  其一','劉弇','宋','宋诗','song-poetry','','[]','怯思酣魂九十中，蠶苗鳳子學人慵。',32,'全唐诗/poet.song.59000.json','["怯思酣魂九十中，蠶苗鳳子學人慵。", "來來不會春工意，醖造風光抵死醲。"]'),
('8e589ed2-d982-4e18-bd69-4074741dba88','四用前韵酬達夫  其二','劉弇','宋','宋诗','song-poetry','','[]','黄金遲日蟻成樓，翠色紅光一樣浮。',32,'全唐诗/poet.song.59000.json','["黄金遲日蟻成樓，翠色紅光一樣浮。", "短殺五更無客夢，小垂雙手有人愁。"]'),
('18446dde-61eb-49a3-b22c-4efe7b1febee','四用前韵酬達夫  其三','劉弇','宋','宋诗','song-poetry','','[]','高陽門巷有人狂，金谷園林數日忙。',32,'全唐诗/poet.song.59000.json','["高陽門巷有人狂，金谷園林數日忙。", "多事正堪憐考父，不尋花去却循牆。"]'),
('bc018a42-8ba5-4270-9792-ce44e5d0b388','四用前韵酬達夫  其四','劉弇','宋','宋诗','song-poetry','','[]','雀緣底事兒童戲，蛙爲何人口舌爭。',32,'全唐诗/poet.song.59000.json','["雀緣底事兒童戲，蛙爲何人口舌爭。", "待割金明一尋碧，恨無霜剪快如并。"]'),
('45a4cc3c-f097-4589-9b9d-858cd5c1c835','四用前韵酬達夫  其五','劉弇','宋','宋诗','song-poetry','','[]','葉底蜂兒拋蜜桶，花邊猧子亂棋圍。',32,'全唐诗/poet.song.59000.json','["葉底蜂兒拋蜜桶，花邊猧子亂棋圍。", "一綳周昉新番畫，擬就勾芒乞取歸。"]'),
('d88efb24-30fd-4fd6-97b7-818dc597327f','四用前韵酬達夫  其六','劉弇','宋','宋诗','song-poetry','','[]','夢草客兒成底句，貪杯吏部覓誰鄰。',32,'全唐诗/poet.song.59000.json','["夢草客兒成底句，貪杯吏部覓誰鄰。", "雪衣女軟留茶舌，金十奴慵刺繡身。"]'),
('10e5101f-e1f3-4779-a55d-31b659d487bd','四用前韵酬達夫  其七','劉弇','宋','宋诗','song-poetry','','[]','樓臺半蘸浮天水，燈火頻乾繼晷油。',32,'全唐诗/poet.song.59000.json','["樓臺半蘸浮天水，燈火頻乾繼晷油。", "桃李不須連夜賞，牡丹它日有高流。"]'),
('21278c51-97fa-4a75-85ea-e930a93c02a3','四用前韵酬達夫  其八','劉弇','宋','宋诗','song-poetry','','[]','稍喜濁醪扶病頭，强看狂絮點清流。',32,'全唐诗/poet.song.59000.json','["稍喜濁醪扶病頭，强看狂絮點清流。", "王鱣叔鮪成何事，不似吞書鯉破愁。"]'),
('8a812811-970c-4afe-be53-cee777a14ea6','四用前韵酬達夫  其九','劉弇','宋','宋诗','song-poetry','','[]','提壺蘆能送好聲，客來長是及門迎。',32,'全唐诗/poet.song.59000.json','["提壺蘆能送好聲，客來長是及門迎。", "惜花待著連天幕，賭酒須翻卷海觥。"]'),
('96eb2232-9e48-4439-9dd9-6fe9c15ca66a','四用前韵酬達夫  其一○','劉弇','宋','宋诗','song-poetry','','[]','折柳愁生灞陵岸，射鵰閑殺羽林郎。',32,'全唐诗/poet.song.59000.json','["折柳愁生灞陵岸，射鵰閑殺羽林郎。", "長安不禁花時夜，京兆于今有趙張。"]'),
('cfa86e74-1979-4d21-b524-65210a8f1797','題建州富沙門樓安濟橋十絕呈太守黄彥發 富沙門樓五絕 其一','劉弇','宋','宋诗','song-poetry','','[]','通莊一日踴青鴛，目極須知剩得天。',32,'全唐诗/poet.song.59000.json','["通莊一日踴青鴛，目極須知剩得天。", "競秀溪山歸筆助，撥忙風月看觴傳。"]'),
('d48a7b01-f25a-475d-9065-0020fdddcf79','題建州富沙門樓安濟橋十絕呈太守黄彥發 富沙門樓五絕 其二','劉弇','宋','宋诗','song-poetry','','[]','文榱繡栱切浮雲，喜色先開萬井春。',32,'全唐诗/poet.song.59000.json','["文榱繡栱切浮雲，喜色先開萬井春。", "未俯欄干窺獨鳥，已驚衽席度游人。"]'),
('d6e4ed51-115f-4cf3-8a53-c15e617b2b55','題建州富沙門樓安濟橋十絕呈太守黄彥發 富沙門樓五絕 其三','劉弇','宋','宋诗','song-poetry','','[]','撲閈行人衮底流，闉闍縹緲到三休。',32,'全唐诗/poet.song.59000.json','["撲閈行人衮底流，闉闍縹緲到三休。", "霜魂月魄交光夜，十二冰簾不上鈎。"]'),
('8013d9b8-3c8e-4b3f-8607-501acb48e33b','題建州富沙門樓安濟橋十絕呈太守黄彥發 富沙門樓五絕 其四','劉弇','宋','宋诗','song-poetry','','[]','王粲登臨端不負，庾公興味故應清。',32,'全唐诗/poet.song.59000.json','["王粲登臨端不負，庾公興味故應清。", "廣寒約酌無多地，取取仙風洗骨生。"]'),
('5cd463e3-7d25-4a66-8a3d-38310943b46c','題建州富沙門樓安濟橋十絕呈太守黄彥發 富沙門樓五絕 其五','劉弇','宋','宋诗','song-poetry','','[]','曾聞仙者好樓居，樓外仙山入指呼。',32,'全唐诗/poet.song.59000.json','["曾聞仙者好樓居，樓外仙山入指呼。", "聊作上游新粉澤，使君不爲貯羅敷。"]'),
('bf5ab158-a301-4bbe-91e1-4d9214b3dc71','題建州富沙門樓安濟橋十絕呈太守黄彥發 安濟橋五絕 其一','劉弇','宋','宋诗','song-poetry','','[]','誰把靈楂接飲牛，主人瀟灑古東甌。',32,'全唐诗/poet.song.59000.json','["誰把靈楂接飲牛，主人瀟灑古東甌。", "玉清夜半開冰箔，暗認方平別駕虯。"]'),
('f5a68fd0-26fd-449c-80fd-c7b1915b0c68','題建州富沙門樓安濟橋十絕呈太守黄彥發 安濟橋五絕 其二','劉弇','宋','宋诗','song-poetry','','[]','扶檻侏儒玉刻紅，斬新裝飾水精宮。',32,'全唐诗/poet.song.59000.json','["扶檻侏儒玉刻紅，斬新裝飾水精宮。", "武夷不信仙山近，十萬曾孫正踏虹。"]'),
('7f8bf5bc-1910-40e0-8f8f-1107a75a5513','題建州富沙門樓安濟橋十絕呈太守黄彥發 安濟橋五絕 其三','劉弇','宋','宋诗','song-poetry','','[]','跨海鼇身傳洛陽，貼波虹影老吳江。',32,'全唐诗/poet.song.59000.json','["跨海鼇身傳洛陽，貼波虹影老吳江。", "未如截取玻瓈去，穩卧箜篌白玉腔。"]'),
('53e4c1c9-fa3f-4f48-8b9d-ca07d8c19efc','題建州富沙門樓安濟橋十絕呈太守黄彥發 安濟橋五絕 其四','劉弇','宋','宋诗','song-poetry','','[]','擁翠拖青得要津，截波仙屐略無塵。',32,'全唐诗/poet.song.59000.json','["擁翠拖青得要津，截波仙屐略無塵。", "借令萬鵲填橋巧，何補褰裳一世人。"]'),
('cdcd8d91-efc5-45d5-a30e-66e65f7846df','題建州富沙門樓安濟橋十絕呈太守黄彥發 安濟橋五絕 其五','劉弇','宋','宋诗','song-poetry','','[]','江夏無雙自妙年，潁川第一早聞天。',32,'全唐诗/poet.song.59000.json','["江夏無雙自妙年，潁川第一早聞天。", "陽和自滿千桃李，更欲邦人識濟川。"]'),
('6f4c9d36-688a-4869-99db-dfa207d0b28f','送曾道者歸玉笥舊隠二首  其一','劉弇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','踏盡匡山十載雲，却抽秋鶴九皋身。',32,'全唐诗/poet.song.59000.json','["踏盡匡山十載雲，却抽秋鶴九皋身。", "明明似爲溪毛熟，笑整西風不屋巾。"]'),
('aa7594f1-c08c-4e7b-9567-68b1bc65f30f','送曾道者歸玉笥舊隠二首  其二','劉弇','宋','宋诗','song-poetry','','[]','道隠曾窺反接猱，急人尤喜施圭刀。',32,'全唐诗/poet.song.59000.json','["道隠曾窺反接猱，急人尤喜施圭刀。", "浮生不絓秋毫外，肯把長閑博暫勞。"]'),
('e6e63942-a206-4232-8276-05491fdff4ea','道旁見牛車因成二絕  其一','劉弇','宋','宋诗','song-poetry','','[]','由來得計在通津，蝕盡冥冥古道塵。',32,'全唐诗/poet.song.59000.json','["由來得計在通津，蝕盡冥冥古道塵。", "犢子掣轅疲欲死，須知作俑是椎輪。"]'),
('7071c6b1-b8fd-4b89-b775-1c5217a28088','道旁見牛車因成二絕  其二','劉弇','宋','宋诗','song-poetry','','[]','兼兩正緣勝任取，摧輈終忌大圓生。',32,'全唐诗/poet.song.59000.json','["兼兩正緣勝任取，摧輈終忌大圓生。", "尺塗寸潦皆吾病，何必羊腸九折行。"]'),
('7fd303f7-8fa9-4272-b842-8043d0d66d0c','送李德素罷官歸舒城三首  其一','劉弇','宋','宋诗','song-poetry','','[]','瀟灑由來物外姿，文章滿把盡珠璣。',32,'全唐诗/poet.song.59000.json','["瀟灑由來物外姿，文章滿把盡珠璣。", "飛黄蹀月終難絆，看取蘅皋手一揮。"]'),
('5d9469d9-05de-4e92-9e4f-f16c7af61274','送李德素罷官歸舒城三首  其二','劉弇','宋','宋诗','song-poetry','','[]','朔風吹眼水溶溶，白社回香杳靄中。',32,'全唐诗/poet.song.59000.json','["朔風吹眼水溶溶，白社回香杳靄中。", "千里滄洲帆一抹，遥知此日背冥鴻。"]'),
