('abed9ea1-9ffa-49a9-b26b-ee066a0aa1b0','龍雲觀稼','劉弇','宋','宋诗','song-poetry','','[]','黄雲撲撲擁千塍，惡歲嗷嗷比獨登。',32,'全唐诗/poet.song.59000.json','["黄雲撲撲擁千塍，惡歲嗷嗷比獨登。", "稍取快襟移遠岫，更從始擊見秋鷹。"]'),
('d553ed53-8428-4098-a1e1-4249b537eb4d','知府黄龍圖生辰五首  其一','劉弇','宋','宋诗','song-poetry','','[]','由來昭武勝天台，淑氣俄鍾命世材。',64,'全唐诗/poet.song.59000.json','["由來昭武勝天台，淑氣俄鍾命世材。", "天上月華方攝兔，人間春色已先梅。", "長庚夢白真無敵，嵩岳生申世有開。", "直恐龍陂清澈底，照人都入骨毛來。"]'),
('5f69ff2e-422d-47d7-ac52-706e4fceb086','知府黄龍圖生辰五首  其二','劉弇','宋','宋诗','song-poetry','','[]','早歲聲名動玉除，區區漢日謾嚴徐。',64,'全唐诗/poet.song.59000.json','["早歲聲名動玉除，區區漢日謾嚴徐。", "高將官况雲難學，清得才情水不如。", "端的好光親日月，分明有力是詩書。", "軒軒昭代文章伯，誰識麒麟下紫虛。"]'),
('3fc661a2-2bf8-43e6-a584-f96736739d30','知府黄龍圖生辰五首  其三','劉弇','宋','宋诗','song-poetry','','[]','豫章瀟洒古南州，偶屈天邊法從遊。',64,'全唐诗/poet.song.59000.json','["豫章瀟洒古南州，偶屈天邊法從遊。", "孺子榻塵終日少，曲江詩板有時留。", "千帆白雪艨艟浪，萬頃黄雲䆉稏秋。", "誰識使君經濟處，長年清怯爲民憂。"]'),
('24e61167-cbb7-49de-af8a-a8fa6989f913','知府黄龍圖生辰五首  其四','劉弇','宋','宋诗','song-poetry','','[]','從古無雙江夏黄，此身親簉玉宸傍。',64,'全唐诗/poet.song.59000.json','["從古無雙江夏黄，此身親簉玉宸傍。", "暫閑十載陶鈞手，猶勝一時鵷鷺行。", "况復唐虞新日月，不妨伊傅好舟航。", "願酬千里邦人祝，直築沙堤到大梁。"]'),
('5475c0f5-f97e-42d9-ae44-1ce8f346d412','知府黄龍圖生辰五首  其五','劉弇','宋','宋诗','song-poetry','','[]','迎春新酒撥鵝黄，獻壽爭持瀲灧觴。',64,'全唐诗/poet.song.59000.json','["迎春新酒撥鵝黄，獻壽爭持瀲灧觴。", "入夜台躔動符彩，拂星旌戶集簪裳。", "平時猥辱非常顧，賤子初無可錄長。", "獨有此心效芹塊，願先歌魯熾而昌。"]'),
('dab02c69-5c36-4281-8a5f-cd3fb8297b8b','知府熊公待制生辰','劉弇','宋','宋诗','song-poetry','','[]','天上麒麟瑞，人間杞梓良。',264,'全唐诗/poet.song.59000.json','["天上麒麟瑞，人間杞梓良。", "扶周崧孕秀，開漢昴騰芒。", "蓂月清和半，桑弧决拾傍。", "雲旌初驗昉，水渚忽臨張。", "汗血來西極，長離下女床。", "决科霄漢上，著姓斗牛鄉。", "伊昔聞遭遇，維時適凱康。", "輔臣推練達，天子賜輝光。", "政府初更贊，農曹亦薦揚。", "仰窺惟白日，穩步是銀潢。", "西液常楊筆，同天舜禹觴。", "岷峨欣惠字，邛筰入寥狼。", "襦袴謠南海，韜鈐肅桂陽。", "有爲皆稷契，無地不龔黄。", "藩服今連楚，江城故壓章。", "熊憑新傳軾，雞馥舊含香。", "賈召行前席，曹歸定束裝。", "鈞中揮造化，川際起舟航。", "賤子慚庥庇，佳晨倍激昂。", "松椿先衆禱，芹塊止誠將。", "和逐薰弦遠，歡同畏日長。", "椒漿持滿斝，何計上公堂。"]'),
('50791670-f9e7-49d7-bd39-4cb8aa60e772','上熊待制生辰二首  其一','劉弇','宋','宋诗','song-poetry','','[]','雅什曾歌嶽降神，今看天上玉麒麟。',64,'全唐诗/poet.song.59000.json','["雅什曾歌嶽降神，今看天上玉麒麟。", "舜弦一弄均和氣，堯莢三收得令辰。", "池到鳳凰須指日，符分魚竹未妨身。", "祈公戩穀終何擬，星有元台木有椿。"]'),
('acb714bd-2d4f-43dc-af11-81339524fc55','上熊待制生辰二首  其二','劉弇','宋','宋诗','song-poetry','','[]','往歲曾看九萬飛，日邊親得好光輝。',64,'全唐诗/poet.song.59000.json','["往歲曾看九萬飛，日邊親得好光輝。", "西清儤直荷爲橐，左蜀宣風繡作衣。", "直使聲名過紫塞，剩留功業到黄扉。", "蒼生久繫爲霖望，早晚追鋒合北歸。"]'),
('84d4f54e-a492-4774-a7c1-45adaa6cea97','王運判生辰二十韵','劉弇','宋','宋诗','song-poetry','','[]','高躡明昌會，全收傑俊聲。',240,'全唐诗/poet.song.59000.json','["高躡明昌會，全收傑俊聲。", "慶緣庚入夢，粹是昴騰精。", "梁日麒麟下，周年鸑鷟鳴。", "門庭諸謝美，襟韵七閩深。", "姓字黄金榜，才華白玉京。", "五車經目盡，一賦未晡成。", "在昔聞開泰，于時契陟明。", "經綸真主識，風采滿朝傾。", "迅擊方秋隼，橫騎上漢鯨。", "激昂孤立氣，魁壘並遊英。", "决指西清邁，俄優左省行。", "堯天窺日月，漢陛右公卿。", "豸脫臺冠舊，軺馳使傳輕。", "瘡痍瘳物瘵，荆枳斸姦萌。", "范轡歸餘事，萊衣萃極榮。", "陋儒何幸會，慶誕適親更。", "芹塊慚無補，牋毫浪有情。", "凉颸來翠帟，嘉氣動雕楹。", "瀲灧千分酒，翂𦑉萬里程。", "祈公此心切，立欲壽如彭。"]'),
('b3c3f47c-8d9a-4181-a058-0265e4cce54d','冬至上王丞相生日黄鍾歌','劉弇','宋','宋诗','song-poetry','','[]','乾坤變化造萬物，十有一月生黄鍾。',128,'全唐诗/poet.song.59000.json','["乾坤變化造萬物，十有一月生黄鍾。", "黄鍾資養太和氣，上賢稟受爲三公。", "至音鏗鏘儀鳳凰，播在簡冊成文章。", "權衡度量立大法，朝廷四海聲洋洋。", "往時霜木立如束，原野焦枯無紫綠。", "自從緹室一陽生，半夜萌芽動寒谷。", "登堂請獻眉壽杯，願同律管容葭灰。", "玉鉉金鼎調鹽梅，年年陽德先春來。"]'),
('1a49f323-6fb0-48fc-9d36-4f67c1020bc2','狄大夫生辰二十韵','劉弇','宋','宋诗','song-poetry','','[]','一指斗魁天陸北，五新蓂葉帝階傍。',320,'全唐诗/poet.song.59000.json','["一指斗魁天陸北，五新蓂葉帝階傍。", "降神山嶽全儲秀，遍射桑蓬驟發祥。", "廄暖共看駒汗血，玉靈爭記水流方。", "家臨人物先賢楚，祖擅功名大國梁。", "孝穆撫摩驚秀整，升卿標識見蕃昌。", "芝蘭庭戶真難得，雕鶚風雲自不常。", "頭角人間知有子，星辰天上早占郎。", "州緣綠髮臨來好，路到青梯上正長。", "濯濯柳姿今識緒，汪汪陂量舊傳黄。", "警虛比戶沉宵柝，愛結曾陰轉曉棠。", "座上藍田神更潤，匣中干越智彌藏。", "龜魚腰重黄金刻，珠玉胸開古錦囊。", "放雀籠樊饒奮翥，饋魚尊俎稱淋浪。", "旄倪芹塊懸私禱，譜牒松椿入短章。", "季諾往蒙新睠渥，膺門仍出舊恩光。", "昂頭竟類田方馬，賀厦空循考父牆。", "堆玉巑岏方刮眼，橫雲䆉稏已登場。", "光回愛日庭希訟，喜動前旌客薦觴。", "况復斕斑衣上淚，不妨瀟灑醉中鄉。", "願符魯什昌而熾，更擁箕疇壽且康。"]'),
('dc14cc57-d40b-4ce1-a048-fb4ab6b12a1b','賀提刑生辰二十韵','劉弇','宋','宋诗','song-poetry','','[]','律中蕤賓候，時生翰苑才。',264,'全唐诗/poet.song.59000.json','["律中蕤賓候，時生翰苑才。", "昴星天上降，玉樹署中開。", "地望無雙也，公侯有種哉。", "儀刑推虎子，頭角號龍媒。", "雅負凌雲操，陰懷構厦材。", "家聲說王謝，儒學美鄒枚。", "德宇渾深厚，書林早貢該。", "發談生霧露，走筆落瓊瑰。", "仕譽彰宸聽，綸恩擢憲臺。", "泥封雲外捧，使旆日邊來。", "未夏薰風至，先春暖氣回。", "驅馳車翼翼，制割刃恢恢。", "欽恤恩涵海，澄清令走雷。", "露幃衣照日，行部駕揚埃。", "上表除蛇豕，飛章薦草萊。", "鬧中金韵擲，醉裏玉山頹。", "龍印當時伏，鵷班異日陪。", "暫來爲八使，終去面三槐。", "身况推華胄，門曾位上台。", "定重調鼎鼐，應再作鹽梅。", "適遇懸弧旦，宜傾上壽杯。", "下僚何所祝，願早見天魁。"]'),
('6535147e-7a23-4932-91a2-9cffef8a2ed7','哲宗皇帝挽詞二首  其一','劉弇','宋','宋诗','song-poetry','','[]','帝所鈞天樂，人間弊屣輕。',72,'全唐诗/poet.song.59000.json','["帝所鈞天樂，人間弊屣輕。", "夢移黄屋貴，丹促紫霄行。", "雲絕依堯望，山餘祝漢聲。", "夜長堅絮漆，川急愴牆羹。", "雁鶩黄金閟，樓臺白玉城。", "陋儒孤識擢，清血九秋橫。"]'),
('acea9cfc-0ea0-4959-bb53-58fabaac8a37','哲宗皇帝挽詞二首  其二','劉弇','宋','宋诗','song-poetry','','[]','禹迹從容陟，虞華舄奕重。',72,'全唐诗/poet.song.59000.json','["禹迹從容陟，虞華舄奕重。", "辰韓頒秘籍，湟鄯撫新封。", "洮頮方憑玉，髯胡忽挽龍。", "鳳岡盤王氣，柏殿邃真容。", "洛照當陽水，嵩回入抱峰。", "傷心守陵女，猶認上陽鐘。"]'),
('5116cddc-cc9a-46d8-a5f2-d51a7dff7b18','大行皇太后挽詞二首  其一','劉弇','宋','宋诗','song-poetry','','[]','摯別王雎德，吁嗟卷耳心。',48,'全唐诗/poet.song.59000.json','["摯別王雎德，吁嗟卷耳心。", "軸回坤事退，波度月痕侵。", "金暗奩花澀，椒寒壁氣沉。", "生平宗廟福，膏澤在民深。"]'),
('6912b679-646a-40c0-b2ff-651493eba925','大行皇太后挽詞二首  其二','劉弇','宋','宋诗','song-poetry','','[]','東朝功業高參九，丞相門閭盛活千。',64,'全唐诗/poet.song.59000.json','["東朝功業高參九，丞相門閭盛活千。", "二紀再中扶漢日，一簾全覆避堯天。", "濯龍春去蠶空老，長信衣藏玉不烟。", "與子弄孫神聖上，飛騰誰識母儀篇。"]'),
('2418cb90-cb0b-4c13-9006-18b0ff10f44a','追尊皇太后挽詞二首  其一','劉弇','宋','宋诗','song-poetry','','[]','代邸基元命，唐侯福萬邦。',48,'全唐诗/poet.song.59000.json','["代邸基元命，唐侯福萬邦。", "五雲深紫鳳，九地轉銀江。", "白玉形容冊，蒼烟扈從幢。", "由來閶闔路，望絕帝瞳雙。"]'),
('6b3ead39-fe47-44ac-9dcb-e01c5e02ed2e','追尊皇太后挽詞二首  其二','劉弇','宋','宋诗','song-poetry','','[]','循陔備養虛蘭膳，吹棘深慈愴凱風。',64,'全唐诗/poet.song.59000.json','["循陔備養虛蘭膳，吹棘深慈愴凱風。", "歲閱桮棬餘舊物，氣躔龍虎識新宮。", "素冠起慕三年外，暖律添暉六服中。", "百載重論章懿典，崇成應得敵高嵩。"]'),
('4eb0f9de-2ecc-4b32-a54b-af606e9276f6','何隠居挽詞二首  其一','劉弇','宋','宋诗','song-poetry','','[]','人世猶來共一漚，如君無憾此生浮。',64,'全唐诗/poet.song.59000.json','["人世猶來共一漚，如君無憾此生浮。", "蘭陔長負平生養，蒿里方成不測遊。", "故物他年歸石馬，東楹何事揜天球。", "始應羞殺吳中士，誤把垣星决去留。"]'),
('ef80b158-d30c-4be2-96f4-86b2ba86c0f4','何隠居挽詞二首  其二','劉弇','宋','宋诗','song-poetry','','[]','瑟縮神皋萬木悲，此中祖軷是長辭。',64,'全唐诗/poet.song.59000.json','["瑟縮神皋萬木悲，此中祖軷是長辭。", "半生桂向秋蟾老，一日舟先夜壑移。", "終恐短長私造物，了無毫髮愧銘詩。", "青鴛僅就千雲構，誰是當年識履綦。"]'),
('9f826f9d-fb59-4300-8432-b26de2f0ba90','歐陽升之挽辭','劉弇','宋','宋诗','song-poetry','','[]','老爛爲儒衆所聞，病中猶不廢研論。',64,'全唐诗/poet.song.59000.json','["老爛爲儒衆所聞，病中猶不廢研論。", "生榮不得文章力，死贈須霑雨露恩。", "賢有鳳毛奚所憾，命終龜壽亦何冤。", "卧牛又得佳山水，青紫他年定滿門。"]'),
('17af82bd-709b-4717-ad81-39a2f88f3a55','哭上藍居晉禪師二首  其一','劉弇','宋','宋诗','song-poetry','','[]','師在雲無心，師化雲無迹。',52,'全唐诗/poet.song.59000.json','["師在雲無心，師化雲無迹。", "明明身後語，宛是西來的。", "胡爲西來子，計較歸寸尺。", "膏脣拭舌奈爾何，咄哉青蠅真弔客。"]'),
('fdbcc8f2-7333-420d-b2d9-bef1c549ac88','哭上藍居晉禪師二首  其二','劉弇','宋','宋诗','song-poetry','','[]','惻惻復惻惻，浪生浮世悲。',52,'全唐诗/poet.song.59000.json','["惻惻復惻惻，浪生浮世悲。", "清松疏冷風，尚想瀟灑姿。", "一吷寄去留，羞殺方袍兒。", "令人却憶當陽剖，扠手退身徒爾爲。"]'),
('d17b38a3-b4f7-4391-9580-d6b6abc55ba8','鄧縣君挽辭二首  其一','劉弇','宋','宋诗','song-poetry','','[]','九原秋草沒麒麟，哀挽黎明出問津。',64,'全唐诗/poet.song.59000.json','["九原秋草沒麒麟，哀挽黎明出問津。", "花魄欲招誰些楚，簫聲先斷客愁秦。", "冢間白鶴空雙舞，天上黄姑定卜鄰。", "晰晰目存成底事，空餘粉墨逼天真。"]'),
('be6a242a-98f5-422b-b9af-59ababd2fdf3','鄧縣君挽辭二首  其二','劉弇','宋','宋诗','song-poetry','','[]','中庭熨泠事多違，像設俄驚繐作幃。',64,'全唐诗/poet.song.59000.json','["中庭熨泠事多違，像設俄驚繐作幃。", "風雨夜花連子失，鉛黄朝鏡覺鸞非。", "一篇潘賦空齎恨，數鼓莊盆未息機。", "俯仰便成今昔異，瓶銀簪玉意何歸。"]'),
('5b0c5f2a-795a-4615-977c-07783553390d','句','劉弇','宋','宋诗','song-poetry','','[]','西山崔嵬摩蒼穹，秀嶺巃嵷如朝宗。',16,'全唐诗/poet.song.59000.json','["西山崔嵬摩蒼穹，秀嶺巃嵷如朝宗。"]'),
('81bbcc92-cb85-4ca1-8f83-3a18f71aa717','此君亭歌次毛公韵','王祖道','宋','宋诗','song-poetry','','[]','君不見太白之精下人間兮，昔人號爾謫仙翁。',268,'全唐诗/poet.song.59000.json','["君不見太白之精下人間兮，昔人號爾謫仙翁。", "君不見不爲蒼生起兮，謝安携妓山之東。", "玉堂主人繡衣客，邀我載酒金蓮宮。", "小亭環立千竿竹，參天百尺繫陰重。", "岸巾散髮對此坐，一日無君誰我同。", "夜來霜壓北枝重，剩見鐘雲數尺峰。", "玉實幽香儀彩鳳，日華轉影篩金櫳。", "孤幹未甘春雪折，青陰不逐秋風紅。", "長隨檜柏老剛勁，不羨桃李爭鮮濃。", "我愛此君有直節，肯學蟠木求先容。", "我愛此君歲寒志，長笑霜井落青桐。", "大夫老松邀我侶，三品頑石徒誇雄。", "不作湘江兒女泣，蒼梧雲散愁盈胸。", "夜深明月滿亭戶，此君入我懷袖中。", "故人來兮七賢至，開門滿坐生清風。", "此君此君聽我語，藏器於身兮，終奏太廟歌黄鍾。"]'),
('4dc17a1f-372f-46ec-a920-d0385d0f8904','句','王祖道','宋','宋诗','song-poetry','','[]','石頭虎距海，洲岸馬昂槽。',12,'全唐诗/poet.song.59000.json','["石頭虎距海，洲岸馬昂槽。"]'),
('eb45b229-7d93-4196-b937-e68164382866','求法頌','釋元照','宋','宋诗','song-poetry','','[]','僧統號求法，乃見出家心。',48,'全唐诗/poet.song.59000.json','["僧統號求法，乃見出家心。", "未審以何求，爲求便等法。", "了知求即法，無復更他求。", "將求求佛法，何不自求求。"]'),
('1a6b9d5d-6d0d-497c-ae8a-de19316dff49','白雲庵','釋元照','宋','宋诗','song-poetry','','[]','道人倦逢迎，結菴就巖穴。',48,'全唐诗/poet.song.59000.json','["道人倦逢迎，結菴就巖穴。", "靜愛山頭雲，空濛如積雪。", "隨風亦卷舒，觸石更明滅。", "却憶古人詩，祗可自怡悅。"]'),
('c0054087-922a-44be-9b92-1e3170d8679d','題北山松軒','釋元照','宋','宋诗','song-poetry','','[]','築室已清曠，栽松更幽寂。',48,'全唐诗/poet.song.59000.json','["築室已清曠，栽松更幽寂。", "爲愛金石姿，不逐風霜易。", "颼飀合琴引，鬰密助山色。", "待折最高枝，談對千拳石。"]'),
('37a23e3b-a143-4e93-95bd-0f0f42b3064b','詠甯國院','釋元照','宋','宋诗','song-poetry','','[]','今古區區滾世埃，此中蓮社爲誰開。',64,'全唐诗/poet.song.59000.json','["今古區區滾世埃，此中蓮社爲誰開。", "從教靖節攢眉去，却喜劉雷拄步來。", "百計坦平心地靜，點光回照玉蕖開。", "翻嗟當日陶彭澤，拍手空歌歸去來。"]'),
('7ccbb55b-83d9-4365-91f4-16a2dae8a465','偈','釋普交','宋','宋诗','song-poetry','','[]','若人問我解何宗，一喝須教兩耳聾。',32,'全唐诗/poet.song.59000.json','["若人問我解何宗，一喝須教兩耳聾。", "滿杓黄齏飽喫了，生涯總在鉢盂中。"]'),
('27b36cd8-0c6f-4ddc-a651-957e17b2353b','辭衆偈','釋普交','宋','宋诗','song-poetry','','[]','寶杖敲空觸處春，光陰掣電舊曾聞。',32,'全唐诗/poet.song.59000.json','["寶杖敲空觸處春，光陰掣電舊曾聞。", "昨宵風動寒巖冷，驚起泥牛耕白雲。"]'),
('f2668b1c-dac7-48b3-a967-8b5b4ffb5e62','偈','釋普交','宋','宋诗','song-poetry','','[]','黄面老，佛法付王臣。',22,'全唐诗/poet.song.59000.json','["黄面老，佛法付王臣。", "林下無情客，官差逼殺人。"]'),
('2c8a8922-0644-4c6d-9335-3c6525aa1d06','出游','劉安世','宋','宋诗','song-poetry','','[]','數子坐愁思出游，麗日光風得情節。',134,'全唐诗/poet.song.59000.json','["數子坐愁思出游，麗日光風得情節。", "一百五日寒食近，二十七品鮭菜闕。", "盤空釜冷柰酒何，變劑連環當佳設。", "詰屈宛是腸九回，緝綴渾如衣百結。", "玉笙繞指影參差，疏櫺度風曉明滅。", "濁醪引滿亦何負，響齒膏唇咀冰雪。", "君不見龍丘行令譏點鹽，又不見韓侯出燕歌炰鱉。", "生緣自信可柰何，歸抱柴關晝常閉。"]'),
('d040db6e-c128-4178-a8a4-e96893944381','集句留別李子玉守素處士二首  其一','劉安世','宋','宋诗','song-poetry','','[]','行藏由命不由身，一卧東山三十春。',32,'全唐诗/poet.song.59000.json','["行藏由命不由身，一卧東山三十春。", "誰謂他鄉各異縣，與君相見即相親。"]'),
('7959fb13-3a6e-40ca-8723-1aa44166510c','集句留別李子玉守素處士二首  其二','劉安世','宋','宋诗','song-poetry','','[]','故里心期柰別何，幾時回首一高歌。',32,'全唐诗/poet.song.59000.json','["故里心期柰別何，幾時回首一高歌。", "鏡中絲髮悲來慣，他日相逢應更多。"]'),
('461cf09b-7c32-445a-b917-a9d480405f9f','南山','劉安世','宋','宋诗','song-poetry','','[]','山屏石壁共巇嶔，外鎖浮雲內日陰。',64,'全唐诗/poet.song.59000.json','["山屏石壁共巇嶔，外鎖浮雲內日陰。", "巖凈四時捐俗慮，泉聲一派潔塵襟。", "搜吟得助騷人句，笑傲忘歸逸士心。", "何日路穿松徑僻，杖藜携酒再登臨。"]'),
('f729e9d8-8880-48d5-a6d4-b2d4081111b4','太皇太后生日','王紳','宋','宋诗','song-poetry','','[]','太皇生日最尊榮，獻壽宮中未五更。',32,'全唐诗/poet.song.59000.json','["太皇生日最尊榮，獻壽宮中未五更。", "天子捧觴仍再拜，寶慈侍立到天明。"]'),
('a46e5d9b-c0e7-4332-bccd-be361d610ba1','太后幸景靈宮駕前露面雙童女','王紳','宋','宋诗','song-poetry','','[]','平明綵杖幸琳宮，紫府仙童下九重。',32,'全唐诗/poet.song.59000.json','["平明綵杖幸琳宮，紫府仙童下九重。", "整頓瓏璁時駐馬，畫工暗地貌真容。"]'),
('2a8eb668-2d83-4d1f-ac49-c4ce02c061be','留題招仙觀','李元輔','宋','宋诗','song-poetry','','[]','一片桂蒼崖，分明不惹埃。',48,'全唐诗/poet.song.59000.json','["一片桂蒼崖，分明不惹埃。", "蹙成珠顆白，垂下玉繩來。", "野燕飛難入，山風捲不開。", "聲聲去朝海，無意戀巖隈。"]'),
('4b102594-f800-4b28-b9f6-6563011c0187','景泰禪閣','譚粹','宋','宋诗','song-poetry','','[]','二山相傳成，禪閣出山半。',60,'全唐诗/poet.song.59000.json','["二山相傳成，禪閣出山半。", "仰觀青冥逼，俯見白石粲。", "錫杖涌玉泉，鐵橋通銀漢。", "巍然概諸天，恍若登彼岸。", "無人解菩提，松濤自昏旦。"]'),
('60dce441-25fd-4544-a377-9246f824cdad','建中靖國辛巳八月十日獨遊碧落洞遂成拙句','譚粹','宋','宋诗','song-poetry','','[]','碧落嵯峨石室幽，到難嗟我未嘗遊。',64,'全唐诗/poet.song.59000.json','["碧落嵯峨石室幽，到難嗟我未嘗遊。", "兩崖卷束雲霞滿，一水通流秋色浮。", "宛矣壺中延日馭，凝然乳竇滴泉旒。", "徘徊注目孱顔久，疑有真仙在上頭。"]'),
('f5c0914c-b4f1-45bf-b01c-e220342efd46','望仙亭成再書一絕','譚粹','宋','宋诗','song-poetry','','[]','一亭新構聳崔嵬，水墨屏圖四面開。',32,'全唐诗/poet.song.59000.json','["一亭新構聳崔嵬，水墨屏圖四面開。", "洞口白雲無鎖鑰，州人尋勝任頻來。"]'),
('67322297-cbaf-4043-a7d4-dafbb782b2a7','重建南山亭輒成小詩迺建中靖國元年孟冬五日也','譚粹','宋','宋诗','song-poetry','','[]','南山亭榭復修完，上枕蒼崖下碧瀾。',32,'全唐诗/poet.song.59000.json','["南山亭榭復修完，上枕蒼崖下碧瀾。", "此景詩人吟不盡，丹青圖寫也應難。"]'),
('ee6f6e63-0958-407e-ae26-a09131275940','偈二首  其一','吳恂','宋','宋诗','song-poetry','','[]','中無門戶四無旁，學者徒勞捉影忙。',32,'全唐诗/poet.song.59000.json','["中無門戶四無旁，學者徒勞捉影忙。", "珍重故園千古月，夜來依舊不曾藏。"]'),
('b3747178-c056-4ff5-ba2c-2ac3c0a55056','偈二首  其二','吳恂','宋','宋诗','song-poetry','','[]','廬峰居士舊門人，邈得師真的的親。',32,'全唐诗/poet.song.59000.json','["廬峰居士舊門人，邈得師真的的親。", "大地撮來成箇眼，翻騰別是一般新。"]'),
('24109be9-ac88-4ab5-9b75-b72f47729998','望瀛亭二首  其一','杜子民','宋','宋诗','song-poetry','','[]','擁傳來觀海，危亭一振衣。',48,'全唐诗/poet.song.59000.json','["擁傳來觀海，危亭一振衣。", "雲晴千怪出，浸大百川歸。", "日月遭吞吐，乾坤入範圍。", "羣鷗不須避，禪寂久忘機。"]'),
('0364bd01-36b1-4a23-9bb2-efe56a1da3a3','望瀛亭二首  其二','杜子民','宋','宋诗','song-poetry','','[]','北望滄溟大，茫茫天地間。',48,'全唐诗/poet.song.59000.json','["北望滄溟大，茫茫天地間。", "迴環知萬里，縹緲認三山。", "漢使何年到，星槎度歲還。", "蟠桃應已熟，方朔在人寰。"]'),
('c36cf73c-7cfb-4d6b-a284-a6c67c75f4b1','揚州','杜子民','宋','宋诗','song-poetry','','[]','人穿魚蟹市，路入斗牛天。',24,'全唐诗/poet.song.59000.json','["人穿魚蟹市，路入斗牛天。", "雲水家千里，江山月一船。"]'),
('5476a16e-f202-415c-83f1-1db80a0e5ae2','題韓左軍馬圖','趙說','宋','宋诗','song-poetry','','[]','龍媒神飛影在紙，雙瞳墨濕電光紫。',72,'全唐诗/poet.song.59000.json','["龍媒神飛影在紙，雙瞳墨濕電光紫。", "烏首昂昂渴奔水，青鬃迎風拂不起。", "逸氣難居皂櫪底，勢欲陪龍走千里，月支真馬有如此。", "落筆一與王生似，云是吾州韓畫士。"]'),
('1adb71bc-947e-4fc2-bc64-0a4ff2f9c244','宿富樂山贈海公禪老大師','戴蒙','宋','宋诗','song-poetry','','[]','芙蓉溪畔石連松，殿閣崢嶸倚半空。',64,'全唐诗/poet.song.59000.json','["芙蓉溪畔石連松，殿閣崢嶸倚半空。", "一念超居無色界，幾人長住廣寒宮。", "佳賓喜上山頭月，密友時來竹下風。", "除却少多元本物，泥牛哮吼任西東。"]'),
('b9661876-3a87-4268-a8a7-80445e4719aa','句','田叔通','宋','宋诗','song-poetry','','[]','鑄劍斬佞臣。',6,'全唐诗/poet.song.59000.json','["鑄劍斬佞臣。"]'),
('b7c0e88e-ad58-4b70-8f9e-b0bd67e043d8','句  其一','何宗範','宋','宋诗','song-poetry','','[]','輝赫唐封後，尊嚴寧隠初。',12,'全唐诗/poet.song.59000.json','["輝赫唐封後，尊嚴寧隠初。"]'),
('8dfe4595-ca98-411e-8a8a-d6946ff00a25','句  其二','何宗範','宋','宋诗','song-poetry','','[]','仙雲春對客，神燭夜流空。',12,'全唐诗/poet.song.59000.json','["仙雲春對客，神燭夜流空。"]'),
('6f6cbee3-8632-46cd-b239-1f73ccdad078','絕句  其一','釋景淳','宋','宋诗','song-poetry','','[]','夜色中旬後，虛堂坐幾更。',24,'全唐诗/poet.song.59000.json','["夜色中旬後，虛堂坐幾更。", "臨溪猿不叫，當檻月初生。"]'),
('23db911c-9bab-44a9-a9aa-1dce5c3738e2','絕句  其二','釋景淳','宋','宋诗','song-poetry','','[]','後夜客來稀，幽齋獨掩扉。',24,'全唐诗/poet.song.59000.json','["後夜客來稀，幽齋獨掩扉。", "月中無旁立，草際一螢飛。"]'),
('02608524-d015-4119-92b3-b8196a72b1f0','句  其一','釋景淳','宋','宋诗','song-poetry','','[]','捲箔西風起，乘時上古臺。',24,'全唐诗/poet.song.59000.json','["捲箔西風起，乘時上古臺。", "秋聲隨葉下，夜色带烟來。"]'),
('46ccb689-adee-40a7-81e0-66681369456a','句  其二','釋景淳','宋','宋诗','song-poetry','','[]','漁翁睡重春潭闊，白鳥不飛舟自橫。',16,'全唐诗/poet.song.59000.json','["漁翁睡重春潭闊，白鳥不飛舟自橫。"]'),
('ae652ae4-fb73-4bab-bc8a-3c46eb7dc4ca','句','葉某','宋','宋诗','song-poetry','','[]','明朝蓬島去，白雪滿頭飛。',12,'全唐诗/poet.song.59000.json','["明朝蓬島去，白雪滿頭飛。"]'),
('88e4ea26-738e-4665-be36-d75a7bb58d86','句','王氏','宋','宋诗','song-poetry','','[]','不緣燕子穿簾幕，春去春來那得知。',16,'全唐诗/poet.song.59000.json','["不緣燕子穿簾幕，春去春來那得知。"]'),
('c4dd61c5-c7b6-4e33-9f3d-a86b05198400','贈魏憲','魏憲叔','宋','宋诗','song-poetry','','[]','炎祚無疆越萬齡，如何夷鹵尚憑陵。',64,'全唐诗/poet.song.59000.json','["炎祚無疆越萬齡，如何夷鹵尚憑陵。", "中興事業須王導，撥亂韜鈐要孔明。", "劇盜已分齊鉞定，端星行指泰階平。", "呼韓朝渭非難事，好繼當時丙魏聲。"]'),
('1f00e27a-fbf4-4790-9548-922355e64c47','詩一首','李唐','宋','宋诗','song-poetry','','[]','雲裏烟村雨裏灘，看之如易作之難。',32,'全唐诗/poet.song.59000.json','["雲裏烟村雨裏灘，看之如易作之難。", "早知不入時人眼，多買胭脂畫牡丹。"]'),
('604cae4f-d1a2-4c44-b0b2-423f781759c3','泊吳興西觀音院','秦觀','宋','宋诗','song-poetry','','[]','金剎負城闉，閴然美栖止。',144,'全唐诗/poet.song.59000.json','["金剎負城闉，閴然美栖止。", "卞山直穹窿，苕水相依倚。", "霜檜鬰冥冥，海棕鮮薿薿。", "廣除庇夏陰，飛棟明朝晷。", "溪光鳬鶩邊，天色菰蒲裏。", "緒風傳晝焚，璧月窺夜禮。", "洩雲彗層空，規荷鑑幽沚。", "艅艎烟際下，鍾磬林端起。", "聱牙戲清深，嶔崟撲空紫。", "所遇信悠然，此生如寄耳。", "志士恥溝瀆，征夫念桑梓。", "攬衣軒楹間，嘯歌何窮已。"]'),
('41b93fda-9570-42d2-8d31-d950d9b3856e','三老堂','秦觀','宋','宋诗','song-poetry','','[]','堂堂三元老，業履冠儔匹。',216,'全唐诗/poet.song.59000.json','["堂堂三元老，業履冠儔匹。", "蹇諤橫秋霜，高明麗朝日。", "並道謁溫宣，連科收甲乙。", "東南奠藩服，西北馳使驛。", "解鞅環堵安，岸幘氈裘屈。", "群姦懾謦咳，衆廢起咄叱。", "至今領麾地，謳吟遍蓬蓽。", "出入雖異途，歸潔固如一。", "晚厭方內遊，把袂訪閑逸。", "雲壑慶安車，風川駛飛鷁。", "酬獻埃壒外，珠玉在揮筆。", "風標傲松鶴，顔髮移丹漆。", "遂令吳越人，藻繪資稱述。", "邈然超世姿，彷彿得十七。", "辟廱禮寂滅，麟閣事蕭瑟。", "茲焉出民願，名實更炳蔚。", "琬琰琢高詞，龍蘭燎深室。", "福履既所綏，光華無終畢。"]'),
('237cfc19-f53e-4891-a073-a8517745597f','送周裕之赴新息令','秦觀','宋','宋诗','song-poetry','','[]','丈人淮海英，抗節浮雲外。',72,'全唐诗/poet.song.59000.json','["丈人淮海英，抗節浮雲外。", "揮毫錯星錦，抵掌參竽籟。", "青春抱脩能，脫略無范蔡。", "晚營三徑資，百里聊束带。", "扁舟歲欲徂，古剎夜仍艾。", "去去整羽儀，行與高風會。"]'),
('4da5b241-0a6e-4f9c-a53b-21ed5cfdfaa1','寄曾逢原','秦觀','宋','宋诗','song-poetry','','[]','孟夏氣候好，林塘媚晴輝。',96,'全唐诗/poet.song.59000.json','["孟夏氣候好，林塘媚晴輝。", "回渠轉清流，藻荇相因依。", "叢薄起疏籟，衆鳥鳴且飛。", "高城带落日，光景酣夕霏。", "即事遠興託，撫己幽思微。", "超搖弄柔翰，徙倚弦金徽。", "美人邈雲眇，志願固有違。", "丹青儻不渝，與子同裳衣。"]'),
('6034e35f-198f-4b6e-8637-06ab1f74d657','送僧歸遂州','秦觀','宋','宋诗','song-poetry','','[]','寶師本巴蜀，浪跡遊淮海。',48,'全唐诗/poet.song.59000.json','["寶師本巴蜀，浪跡遊淮海。", "定水湛虛明，戒珠烱圓彩。", "飄零鄉縣異，晼晚星霜改。", "明發又西征，孤帆破烟靄。"]'),
('9507c3fd-2329-4930-9947-182833275f86','司馬遷','秦觀','宋','宋诗','song-poetry','','[]','子長少不羈，發軔遍丘壑。',96,'全唐诗/poet.song.59000.json','["子長少不羈，發軔遍丘壑。", "晚遭李陵禍，憤悱思遠託。", "高辭振幽光，直筆誅隠惡。", "馳騁數千載，貫穿百家作。", "至今青簡上，文彩炳金雘。", "高才忽小疵，難用常情度。", "譬彼海運鵬，豈復顧繒繳。", "區區班叔皮，未易議疏略。"]'),
('93b5d033-ae4b-4594-bd6e-a779313b9b48','觀易元吉獐猿圖歌','秦觀','宋','宋诗','song-poetry','','[]','參天老木相樛枝，嵌空怪石銜青漪。',160,'全唐诗/poet.song.59000.json','["參天老木相樛枝，嵌空怪石銜青漪。", "兩猿上下一旁掛，兩猿熟視蒼蛙疑。", "蕭蕭叢竹山風吹，海棠杜宇相因依。", "下有兩獐從兩兒，花餐草囓含春嬉。", "藝老筆精湖海推，畫意忘形形更奇。", "解衣一掃神扶持，他日自見猶嗟咨。", "金錢百萬酒千鴟，荆南將軍欣得之。", "老禪豪取橐爲垂，白晝掩門初許窺。", "房櫳烱烱明冬曦，榛叢羽革分豪釐。", "殘編未終且歸讀，歲暮有間重借披。"]'),
('bf0dfdfb-65f1-40e5-94b3-ee49fe707fc9','夜坐懷莘老司諫','秦觀','宋','宋诗','song-poetry','','[]','六合寥寥信茫昧，中有日月無根柢。',96,'全唐诗/poet.song.59000.json','["六合寥寥信茫昧，中有日月無根柢。", "古往今來漫不休，青髮素顔從此逝。", "嗟予自少多邅迴，氣血未衰心已艾。", "北渡長淮霜入屨，南窺禹穴塵生袂。", "日鑿一竅渾沌死，雖有餘風終破碎。", "回車復路可無緣，三問道人三不對。"]'),
('cdcec548-c8f6-4c63-a348-4cac5b602e26','答朱廣微','秦觀','宋','宋诗','song-poetry','','[]','廣微才華殆天付，十歲孤山有佳句。',192,'全唐诗/poet.song.59000.json','["廣微才華殆天付，十歲孤山有佳句。", "又夢東林飲虎溪，歎息清風人不悟。", "自爾所見無全牛，桐柏崑崙日傾注。", "葱蘢曉景破新花，蹭蹬老拳擒脫兔。", "身勤事左竟何成，巧迫化工天所怒。", "兩鬢星星滄海頭，强學禪那慰遲暮。", "昨夜燈花吐金粟，曉烹鯉魚得尺素。", "笑我徜徉吳楚間，經卷酒巵隨所遇。", "人生迕意十八九，月得解顔能幾度。", "著書準易空自疲，服藥求仙良亦誤。", "北風老矣無能爲，行看黄鸝語飛絮。", "安得從君醉百場，落筆珠璣不論數。"]'),
('256a9a78-f50a-4a8a-8409-2e7349b1d556','送僧歸保寧','秦觀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖環岸皆招提，樓閣晦明如卧披。',160,'全唐诗/poet.song.59000.json','["西湖環岸皆招提，樓閣晦明如卧披。", "保寧復在最佳處，水光四合無端倪。", "車塵不來馬足斷，時有海月相因依。", "上人弱齡已隸此，心目所證惟瑰琦。", "白玉芙蓉出清沼，天然不受緇塵擾。", "坐客一語不入意，目如明星視飛鳥。", "冠切雲兮佩玉難，上人顧之真等閑。", "應緣聊入人間世，興盡却歸湖上山。", "伊余久欲窺禹穴，矧今仲父官東越。", "行挽秋風入剡溪，爲君先醉西湖月。"]'),
('94266c54-809e-456f-93f3-28873e14070d','和王通叟琵琶夢','秦觀','宋','宋诗','song-poetry','','[]','鶗鴂鳴時衆芳歇，華堂夢斷音容絕。',96,'全唐诗/poet.song.59000.json','["鶗鴂鳴時衆芳歇，華堂夢斷音容絕。", "風驚玉露不成圓，一夜芙蕖泣秋月。", "金紋捍面紫檀槽，曾抱花前送酒舠。", "庾郎江令費珠璧，小砑紅牋揮兔毫。", "風流雲散令人瘦，忍看麴塵昏錦綬。", "楚水悠悠更不西，上天破鑑空依舊。"]'),
('91bc4e2f-c2bd-4996-827f-1e8214d90763','醫者','秦觀','宋','宋诗','song-poetry','','[]','塊然一氣初渾淪，散作六物相吐吞。',112,'全唐诗/poet.song.59000.json','["塊然一氣初渾淪，散作六物相吐吞。", "主承客禦勝復存，是爲萬物疾病原。", "寥寥空陂遊冤魂，誨此法術成軒轅。", "金書玉冊要不煩，煥如星宿不可捫。", "時遷聖徂遂幽昏，弊俗竊以資利源。", "余嘗感槩期明論，世無妙質孰與言。", "因君乞詩置屋軒，聊復援筆賦本根。"]'),
('61a8bc1e-c4c5-459d-8c92-20011f9e91cf','漫郎','秦觀','宋','宋诗','song-poetry','','[]','元公機鑒天所高，中興諸彥非其曹。',160,'全唐诗/poet.song.59000.json','["元公機鑒天所高，中興諸彥非其曹。", "自呼漫郎示真率，日與聱叟爲嬉遨。", "是時胡星殞未久，關輔擾擾猶弓刀。", "百里不聞易五羖，三士空傳殺二桃。", "心知不得載行事，俛首刻意追風騷。", "字偕華星章對月，漏洩元氣煩揮毫。", "猗玕春深茂花竹，九疑日暮吟哀猱。", "紅顔白骨付清醥，一官於我真鴻毛。", "乃知達人妙如水，濁清顯晦惟所遭。", "無時有祿亦可隠，何必龕巖遠遁逃。"]'),
('cbf39e2a-e1db-4a6d-a62d-b6cc8d5f2e26','記夢答劉全羙','秦觀','宋','宋诗','song-poetry','','[]','歲逢困敦斗申指，辰次庚辰漏傳子。',160,'全唐诗/poet.song.59000.json','["歲逢困敦斗申指，辰次庚辰漏傳子。", "夢出城闉登古原，草木縈天带流水。", "千夫荷鍤開久殯，前有一人狀瓌偉。", "素冠長跪烝酒殽，云是劉郎字全羙。", "馬鳴車響斷還續，人境晦明秋色裹。", "既寤茫然失所遭，河轉星翻汗如洗。", "世傳夢凶常得吉，神物戲人良有旨。", "全羙聲名海縣聞，閉久當開乃其理。", "娟娟二十四橋月，月下吹簫聊爾耳。", "洗眼看君先一鳴，九萬扶搖從此始。"]'),
('e4e5a490-c608-4da1-9f37-01f7004b5c9b','田居四首  其一','秦觀','宋','宋诗','song-poetry','','[]','雞號四鄰起，結束赴中原。',120,'全唐诗/poet.song.59000.json','["雞號四鄰起，結束赴中原。", "戒婦預爲黍，呼兒隨掩門。", "犁鋤带晨景，道路更笑喧。", "宿潦濯芒屨，野芳簪髻根。", "霽色披窅靄，春空正鮮繁。", "辛夷茂橫阜，錦雉嬌空園。", "少壯已雲趨，伶俜尚鴟蹲。", "蟹黄經雨潤，野馬從風奔。", "村落次第集，隔塍致寒暄。", "眷言月占好，努力競晨昏。"]'),
('16b88fc9-5a64-4c1d-9408-9f91d02cd41d','田居四首  其二','秦觀','宋','宋诗','song-poetry','','[]','入夏桑柘稠，陰陰翳墟落。',120,'全唐诗/poet.song.59000.json','["入夏桑柘稠，陰陰翳墟落。", "新麥已登場，餘蠶猶占箔。", "隆曦破層陰，霽靄收遠壑。", "雌蜺卧淪漪，鮮飆泛叢薄。", "林深鳥更鳴，水漫魚知樂。", "羸老厭煩歊，解衣屢槃礴。", "蔭樹濯凉颸，起行遺带索。", "冢婦餉初還，丁男耘有託。", "倒筒備青錢，鹽茗恐垂橐。", "明日輸絹租，鄰兒入城郭。"]'),
('6a04f4e2-0959-4167-953d-0fe3beafb3c8','田居四首  其三','秦觀','宋','宋诗','song-poetry','','[]','昔我蒔青秧，廉纖屬梅雨。',120,'全唐诗/poet.song.59000.json','["昔我蒔青秧，廉纖屬梅雨。", "及茲欲成穗，已復頹星暑。", "遲暮易昏晨，搖落多砧杵。", "村迥少過從，客來旋炊黍。", "興發即杖藜，未嘗先處所。", "褰裳涉淺瀨，矯首沒孤羽。", "叢祠土鼓悲，野埭鵾雞舞。", "雉子隨販夫，老翁拜巫女。", "辛勤稼穡事，惻愴田疇語。", "得穀不敢儲，催科吏旁午。"]'),
('b6359b13-f5a9-4f76-8fb4-193214a2408e','田居四首  其四','秦觀','宋','宋诗','song-poetry','','[]','嚴冬百草枯，鄰曲富休暇。',125,'全唐诗/poet.song.59000.json','["嚴冬百草枯，鄰曲富休暇。", "土井時一汲，柴車久停駕。", "寥寥場圃空，跕跕烏鳶下。", "孤榜傍橫塘，喧舂起旁舍。", "田家重農隙，翁嫗相邀迓。", "班坐釃酒醪，一行三四謝。", "陶盤奉旨蓄，竹筯羞雞{炙火=肉}。", "飲酣爭獻酬，語闋或悲咤。", "悠悠燈火暗，剌剌風飆射。", "客散靜柴門，星蟾耿寒夜。"]'),
('1ddc6a30-5f27-463b-9f8c-e0e3b68fb1f3','寄題傅欽之草堂','秦觀','宋','宋诗','song-poetry','','[]','河陽有洑流，經營太行根。',144,'全唐诗/poet.song.59000.json','["河陽有洑流，經營太行根。", "盛德不終晦，發爲清濟源。", "斯堂濟源上，太行正當門。", "仰視浮雲作，俯窺流水奔。", "脩竹带藩籬，百禽鳴朝暾。", "相望有盤谷，李願故居存。", "主人國之老，實惟商巖孫。", "班行昔供奉，亟進逆耳言。", "天子色爲動，群公聲亦吞。", "蕭條冰霜際，不改白玉溫。", "出處士所重，其微難具論。", "公勿思草堂，朝廷待公尊。"]'),
('fbe415d3-5a2a-4a02-8908-4aaff3baaa69','次韵酬徐仲車見寄','秦觀','宋','宋诗','song-poetry','','[]','渭清非勝涇，蘭芳本無慕。',48,'全唐诗/poet.song.59000.json','["渭清非勝涇，蘭芳本無慕。", "我生季葉中，乃與古人遇。", "職當供洒掃，匏繫愧遲暮。", "來章感存沒，三讀淚如注。"]'),
('b96fb696-85bc-441a-abd6-4b0a1ec44e15','次韵邢敦夫秋懷十首  其一','秦觀','宋','宋诗','song-poetry','','[]','驅車陟高丘，却望大梁圻。',48,'全唐诗/poet.song.59000.json','["驅車陟高丘，却望大梁圻。", "馳道入雙闕，勾陳連太微。", "夷門壯下屬，清洛相因依。", "美哉吾黨士，皋卨良可希。"]'),
('213d78b4-ba89-4a80-93fe-c2bcbc7e394b','次韵邢敦夫秋懷十首  其二','秦觀','宋','宋诗','song-poetry','','[]','暮有二客至，俱以能禪聞。',48,'全唐诗/poet.song.59000.json','["暮有二客至，俱以能禪聞。", "一枝惠林出，一派智海分。", "言各不相可，往來劇絲棼。", "謝客姑舍是，妨余醉看雲。"]'),
('083770df-4266-4a30-bab4-31cbfe29f41a','次韵邢敦夫秋懷十首  其三','秦觀','宋','宋诗','song-poetry','','[]','昔者曾中書，門戶實難瞰。',48,'全唐诗/poet.song.59000.json','["昔者曾中書，門戶實難瞰。", "筆勢如長淮，初源可觴濫。", "經營終入海，欲語焉能暫。", "斯人今則亡，悲歌風慘澹。"]'),
('2e79244a-453c-4ff3-8369-abef60f2710c','次韵邢敦夫秋懷十首  其四','秦觀','宋','宋诗','song-poetry','','[]','渤海有巨鼇，其顛冠嵯峨。',48,'全唐诗/poet.song.59000.json','["渤海有巨鼇，其顛冠嵯峨。", "宿昔嘗小抃，八弦相盪摩。", "忽遭龍伯人，一舉空潮波。", "取皮煎作膠，清此崑崙河。"]'),
('3b6fb5aa-a928-4ff5-8175-1712dd08d969','次韵邢敦夫秋懷十首  其五','秦觀','宋','宋诗','song-poetry','','[]','蝮蛇初螫手，壯士斷其腕。',48,'全唐诗/poet.song.59000.json','["蝮蛇初螫手，壯士斷其腕。", "豈不悲毀傷，所卹在軀幹。", "西羌沙鹵地，置戍或煩漢。", "雞肋不足云，阿瞞妙思算。"]'),
('1b075bb0-9359-4c44-b8b0-d1fb533b314a','次韵邢敦夫秋懷十首  其六','秦觀','宋','宋诗','song-poetry','','[]','湯湯辟廱流，中有學子居。',48,'全唐诗/poet.song.59000.json','["湯湯辟廱流，中有學子居。", "但說若稽古，言猶三萬餘。", "來者轉相祖，詞林日凋疏。", "稍喜績溪令，入校天祿書。"]'),
('c62b497f-7edb-4b17-b029-02d388bf89d9','次韵邢敦夫秋懷十首  其七','秦觀','宋','宋诗','song-poetry','','[]','匠氏構明堂，百材入斤斧。',48,'全唐诗/poet.song.59000.json','["匠氏構明堂，百材入斤斧。", "儻非豫章棟，冗長亦焉取。", "英英范與蘇，器識兼文武。", "胡爲先一州，不用作霖雨。"]'),
('d5f66ff1-db03-43f4-8816-b7e0fcf767be','次韵邢敦夫秋懷十首  其八','秦觀','宋','宋诗','song-poetry','','[]','憬彼高句麗，來脩裔夷職。',48,'全唐诗/poet.song.59000.json','["憬彼高句麗，來脩裔夷職。", "天都富如海，勞汝送涓滴。", "舳艫尾相銜，遠近困供億。", "止沸當絕薪，揚湯百無益。"]'),
('c8cc3d1f-9568-43ae-909b-0f9552f9ee63','次韵邢敦夫秋懷十首  其九','秦觀','宋','宋诗','song-poetry','','[]','祖宗舉賢良，充賦多名儒。',48,'全唐诗/poet.song.59000.json','["祖宗舉賢良，充賦多名儒。", "執事惡言者，此科爲之無。", "雖有仲舒錯，或橫江潭魚。", "果欲鳴鳳至，還當種椅梧。"]'),
('8a5701cb-4d28-4e25-9057-99c8e1169c0e','次韵邢敦夫秋懷十首  其一○','秦觀','宋','宋诗','song-poetry','','[]','邢侯秋卧痾，揮毫見深衷。',48,'全唐诗/poet.song.59000.json','["邢侯秋卧痾，揮毫見深衷。", "賡者二三子，翕然笙磬同。", "不爲兒女姿，頗形四方風。", "屬有山水念，因之絲與桐。"]'),
('d1584234-f546-4206-b3d1-c885f3b24d6c','春日雜興十首  其一','秦觀','宋','宋诗','song-poetry','','[]','飄忽星氣徂，青陽迫遲暮。',96,'全唐诗/poet.song.59000.json','["飄忽星氣徂，青陽迫遲暮。", "鳴飛各有適，赤白紛無數。", "雨砌墮危芳，風軒納飛絮。", "褰幃香霧橫，岸幘雲峰度。", "林影舞窗扉，池光染衣屨。", "參差花鳥期，蹭蹬琴觴趣。", "撫事動幽尋，感時遺近慕。", "秣馬膏余車，行行不周路。"]'),
('cc9d2868-0a0e-43b6-a181-72524607d4b9','春日雜興十首  其二','秦觀','宋','宋诗','song-poetry','','[]','結髮謝外好，僶俛希前修。',96,'全唐诗/poet.song.59000.json','["結髮謝外好，僶俛希前修。", "繆挾江海志，恥爲升斗謀。", "齞歷難刻畫，賤貧多釁尤。", "發軔背伊闕，解驂憩邗溝。", "丹鉛費永晷，麴糵敺深愁。", "璧月鑒簾櫳，珠星絡梧楸。", "泯泯渠水駛，霏霏花霧浮。", "公子悵何許，撫膺徒離憂。"]'),
('83a76302-6d43-4d40-9f7b-9b9183c0f290','春日雜興十首  其三','秦觀','宋','宋诗','song-poetry','','[]','潭潭故邑井，猗猗上宮蘭。',96,'全唐诗/poet.song.59000.json','["潭潭故邑井，猗猗上宮蘭。", "不食自清渫，莫服更幽閒。", "志士恥弱植，卷跡甘饑寒。", "佳晨追良覿，觸物懸悲端。", "川途眇回遠，經歲曠音翰。", "豈不慕裘馬，詭得非所安。", "蟬冕多怵迫，繩樞尠憂患。", "枉尋竟何補，方枘誠獨難。"]'),
('d845c615-b4db-4ed7-8e43-fd5ccf84edb6','春日雜興十首  其四','秦觀','宋','宋诗','song-poetry','','[]','吳會雖褊小，海濱富奇峰。',120,'全唐诗/poet.song.59000.json','["吳會雖褊小，海濱富奇峰。", "天雞一號叫，劍戟明遥空。", "谿谷相徑復，深林杳攢叢。", "猿吟虎豹啼，雲氣迷西東。", "中有遯世士，超然閟孤蹤。", "被蘭服明月，起坐松聲中。", "夜鍛吸沆瀣，朝琴庇青葱。", "騎星友元氣，巢許安可同。", "俛眄區中人，飛埃集毛鋒。", "問津或不繆，從子游鴻蒙。"]'),
('7ae983ff-1c47-4a42-9bbf-21bf769458f2','春日雜興十首  其五','秦觀','宋','宋诗','song-poetry','','[]','東方有美人，容華茂春粲。',96,'全唐诗/poet.song.59000.json','["東方有美人，容華茂春粲。", "抱影守單棲，含睇理哀彈。", "聲意一何切，所歡邈雲漢。", "徒然事膏沐，孰與徂昏旦。", "微誠浪自持，嘉月忽復晏。", "巧轉度虛櫺，飛紅觸幽幔。", "歲歲芳草滋，夜夜明星爛。", "合并會有時，索居不必歎。"]'),
('9d7430ad-d578-471b-836a-b91dd8724dbf','春日雜興十首  其六','秦觀','宋','宋诗','song-poetry','','[]','寢瘵倦文史，駕言從遨嬉。',96,'全唐诗/poet.song.59000.json','["寢瘵倦文史，駕言從遨嬉。", "颸風舉遥溆，規日麗清漪。", "含桃粲朱實，杜若懷碧滋。", "娉娉弱絮墮，圉圉文魴馳。", "明霞廓遠矚，哀禽攪離思。", "縟草天際合，孤雲川上移。", "寬閑絕輪鞅，重複多路歧。", "信美難久佇，歸歟從所治。"]'),
('0321ef2b-99fd-4ca2-a01b-8c9992f9d370','春日雜興十首  其七','秦觀','宋','宋诗','song-poetry','','[]','昔我遊京室，交通五陵間。',120,'全唐诗/poet.song.59000.json','["昔我遊京室，交通五陵間。", "主客各英妙，袍馬相追攀。", "千金具飲啜，百金雇吹彈。", "纓弁羅廣席，當頭舞交竿。", "鮮妝耀淥酒，采纈生風瀾。", "燈燭暗夜艾，士女紛相班。", "歡娛易徂歇，轉眄如飛翰。", "亹亹負孤願，離離銜永歡。", "山鳥窺茗飲，簷花笑蔬餐。", "棄捐勿重陳，事定須蓋棺。"]'),
('10d02b33-3f1e-4574-b985-7664544c6fdc','春日雜興十首  其八','秦觀','宋','宋诗','song-poetry','','[]','客從遠方來，遺我昭華管。',96,'全唐诗/poet.song.59000.json','["客從遠方來，遺我昭華管。", "吹之動人心，異境生虛窾。", "磝磝青嶂橫，泱泱春溜滿。", "馬蹄交狹邪，車轂錯平坦。", "士女競芳辰，禽魚蔭修竿。", "依微認睇笑，凌沒見纖短。", "停吹欻泯滅，耽耽復空館。", "靈物信所珍，顧恨知音罕。"]'),
('390b26b4-c417-4f4e-b1d0-b14646d571d7','春日雜興十首  其九','秦觀','宋','宋诗','song-poetry','','[]','桃李用事辰，鮮明奪雲綺。',48,'全唐诗/poet.song.59000.json','["桃李用事辰，鮮明奪雲綺。", "繁華一朝去，默默慚杞梓。", "時徂鷹化鳩，地遷橘爲枳。", "獨有羨門生，後天猶不死。"]'),
('615236a9-cda6-4b78-b748-8b9406e7f0aa','春日雜興十首  其一○','秦觀','宋','宋诗','song-poetry','','[]','藝籍燔祖龍，斯文就淪喪。',144,'全唐诗/poet.song.59000.json','["藝籍燔祖龍，斯文就淪喪。", "帝矜黔首愚，諸雋出相望。", "揚馬操宏綱，韓柳激頹浪。", "建安妙謳吟，風概亦超放。", "玉繩带華月，艷艷青冥上。", "奕世希末光，經緯得無妄。", "兒曹獨何事，詆斥幾覆醤。", "原心良自誣，猥欲私所尚。", "螳螂拒飛轍，精衛填溟漲。", "咄咄徒爾爲，東海固無恙。", "鵷鸞日彫滅，黄口紛冗長。", "投袂睇層霄，茲懷誰與亮。"]'),
('5c4b3ff5-10b7-45ae-abbe-f1390b2083de','和孫莘老題召伯斗野亭','秦觀','宋','宋诗','song-poetry','','[]','淮海破冬仲，雪霜滋不平。',120,'全唐诗/poet.song.59000.json','["淮海破冬仲，雪霜滋不平。", "菱荷枯折盡，積水寒更清。", "輟棹得佳觀，湖天繞朱甍。", "信美無與娛，濁醪聊自傾。", "北眺桑梓國，悠然白雲生。", "南望古邗溝，滄波带蕪城。", "村墟翳茅竹，孤烟起晨烹。", "簷間鳥聲落，客子念當行。", "攬衣視日景，薄陰漏微明。", "何時復來遊，春風發鮮榮。"]'),
('a632b87d-4ae7-44b4-acdc-e79602cd8743','和虛飄飄','秦觀','宋','宋诗','song-poetry','','[]','虛飄飄，虛飄飄。',60,'全唐诗/poet.song.59000.json','["虛飄飄，虛飄飄。", "風寒飄絮浪，春暖履冰橋。", "勢緩霜垂霰，聲乾葉下條。", "雨中漚點沒流水，風裏綵雲鋪遠霄。", "虛飄飄，比時光影猶堅牢。"]'),
('3b40814b-e195-4ef6-b9a8-375a620112b6','和游金山','秦觀','宋','宋诗','song-poetry','','[]','江流會揚子，洶洶東南騖。',192,'全唐诗/poet.song.59000.json','["江流會揚子，洶洶東南騖。", "海門劃前開，金山屹中據。", "鼓鍾食萬指，金雘棲千柱。", "夜庭游月波，曉觀摶香霧。", "天清猿鳥哀，風暗魚龍怒。", "雲物橫古今，濤波閱晨暮。", "三州氣色來，上下端倪露。", "偉哉元氣間，此勝知誰聚。", "念昔憩精廬，登臨輒忘去。", "汲新試團月，飯素羹魁芋。", "妙興入芳藤，真境在芒屨。", "別來景暑換，寤寐經從處。", "忽蒙珠璧投，了與雲巒遇。", "幽光烱肝肺，爽氣森庭戶。", "區中多滯念，方外饒奇趣。", "寄語山阿人，泠然行復御。"]'),
('de370f8f-a63c-4cc5-9932-144eac54db05','同子瞻端午日遊諸寺賦得深字','秦觀','宋','宋诗','song-poetry','','[]','太史抱孤韵，暢懷在登臨。',120,'全唐诗/poet.song.59000.json','["太史抱孤韵，暢懷在登臨。", "別乘載鄒枚，佳辰事幽尋。", "參差水石瘦，窅窕房櫳深。", "清磬發疏箔，妙香橫素襟。", "復登窣堵波，環回矚嶔崟。", "雙溪貫城郭，暝色带孤禽。", "凉飈動爽籟，薄雨生微陰。", "塵想澹清漣，牢愁洗芳斟。", "揮箑訂往古，援毫示來今。", "愧無刻燭敏，續此金玉音。"]'),
('d6c906e8-c319-437a-93df-3eb7be45e8c0','寄陳季常','秦觀','宋','宋诗','song-poetry','','[]','一鉤五十犗，始具任公釣。',144,'全唐诗/poet.song.59000.json','["一鉤五十犗，始具任公釣。", "揭竿趣灌瀆，與爾不同調。", "先生本西蜀，俠氣見英妙。", "哀憐世間兒，細黠似黄鷂。", "侍童雙擢玉，鬢髮光可照。", "駿馬錦障泥，相隨窮海嶠。", "平生携手好，十七登廊廟。", "小生相吏耶，徒枉尺書召。", "暮年更折節，學佛得心要。", "鬻馬放阿樊，幅巾對沉燎。", "泠泠屋外泉，兀兀原頭燒。", "欲知山中樂，萬古同一笑。"]'),
('f57ca18d-a203-4cd9-ad0b-dd37cc17b5cd','同子瞻賦游惠山三首  其一','秦觀','宋','宋诗','song-poetry','','[]','輟棹縱幽討，籃輿入青蒼。',72,'全唐诗/poet.song.59000.json','["輟棹縱幽討，籃輿入青蒼。", "圓頂相邀迓，旃檀燎深堂。", "層巒淡如洗，傑閣森欲翔。", "林芳含雨滋，岫日隔林光。", "涓涓續清溜，靡靡傳幽香。", "俯仰佳覽眺，悠哉身世忘。"]'),
('4cad971b-66f5-4516-acd8-82f801d7a610','同子瞻賦游惠山三首  其二','秦觀','宋','宋诗','song-poetry','','[]','史君厭機械，所與惟散人。',72,'全唐诗/poet.song.59000.json','["史君厭機械，所與惟散人。", "顧慚蒹葭陋，繆倚瓊枝新。", "上干青磝磝，下屬白磷磷。", "洞天不知老，金界無棲塵。", "緬彼人間世，烏蟾閱青旻。", "詎得踵三隠，山阿相與鄰。"]'),
('55e5ae21-f7b6-4118-a6f3-445c0dfe4bc7','同子瞻賦游惠山三首  其三','秦觀','宋','宋诗','song-poetry','','[]','樓觀相複重，邈然閟深樾。',72,'全唐诗/poet.song.59000.json','["樓觀相複重，邈然閟深樾。", "九龍吐清泠，㶁㶁曾未絕。", "罌缶馳千里，真珠猶不滅。", "況復從茶僊，茲焉試葵月。", "岸巾塵想消，散策佳興發。", "何以慰遨嬉，操觚繼前轍。"]'),
('acf517c6-51b7-4e23-86dd-ea303409ebdd','馬上口占二首  其一','秦觀','宋','宋诗','song-poetry','','[]','向晨結束爭長途，利風刮面冰在鬚。',64,'全唐诗/poet.song.59000.json','["向晨結束爭長途，利風刮面冰在鬚。", "岡窮得水馬不進，霧暗失道人相呼。", "悠悠旁舍見汲井，軋軋隔林聞輓車。", "游目騁懷自可樂，勿憶鄉縣增煩紆。"]'),
('8f4ce460-0279-486c-a755-658b1a81783e','馬上口占二首  其二','秦觀','宋','宋诗','song-poetry','','[]','霜風稜稜萬木枯，梅花破萼猶含鬚。',64,'全唐诗/poet.song.59000.json','["霜風稜稜萬木枯，梅花破萼猶含鬚。", "田家往往事游獵，追逐狐兔相號呼。", "微茫山中起狂燒，隠約林梢低日車。", "馬頭漸覺有佳趣，勿厭阡陌多縈紆。"]'),
('740e939a-5afb-4729-bba8-bdd74e6cfd0a','別子瞻','秦觀','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','人生異趣各有求，繫風捕影祇懷憂。',192,'全唐诗/poet.song.59000.json','["人生異趣各有求，繫風捕影祇懷憂。", "我獨不願萬戶侯，惟願一識蘇徐州。", "徐州英偉非人力，世有高名擅區域。", "珠樹三株詎可攀，玉海千尋真莫測。", "一昨秋風動遠情，便憶鱸魚訪洞庭。", "芝蘭不獨庭中秀，松栢仍當雪後青。", "故人持節過鄉縣，教以東來償所願。", "天上麒麟昔漫聞，河東鸑鷟今纔見。", "不將俗物礙天真，北斗已南能幾人。", "八磚學士風標遠，五馬使君恩意新。", "黄塵冥冥日月換，中有盈虛亦何算。", "據龜食蛤暫相從，請結後期游汗漫。"]'),
('048cee4d-3522-4897-a872-9088bda9cf2a','和黄法曹憶建溪梅花','秦觀','宋','宋诗','song-poetry','','[]','海陵參軍不枯槁，醉憶梅花愁絕倒。',128,'全唐诗/poet.song.59000.json','["海陵參軍不枯槁，醉憶梅花愁絕倒。", "爲憐一樹傍寒溪，花水多情自相惱。", "清淚班班知有恨，恨春相逢苦不早。", "甘心結子待君來，洗雨梳風爲誰好。", "誰云廣平心似鐵，不惜珠璣與揮掃。", "月沒參橫畫角哀，暗香銷盡令人老。", "天分四時不相貸，孤芳轉盼同衰草。", "要須健步遠移歸，亂插繁華向晴昊。"]'),
('c545fced-4d58-4e4a-94a3-a9eceedad84f','送少章弟赴仁和主簿','秦觀','宋','宋诗','song-poetry','','[]','我宗本江南，爲將門列戟。',240,'全唐诗/poet.song.59000.json','["我宗本江南，爲將門列戟。", "中葉徙淮海，不仕但潜德。", "先祖實起家，先君始縫掖。", "議郎爲名士，余亦忝詞客。", "風流以及汝，三通桂堂籍。", "汝弱不好弄，文章有風格。", "久從先生游，術業良未測。", "武林一都會，山水富南國。", "下有賢別駕，上有明方伯。", "干將入砥礪，騕褭就銜勒。", "勿矜孔鸞姿，不樂棲枳棘。", "吳中多高士，往往寄老釋。", "辨才雖物化，參寥猶夙昔。", "投閑數訪之，可得三友益。", "少來輕別離，老去重乖隔。", "念汝遠行役，惘惘意不懌。", "道山雖云佳，久寓有饑色。", "功名已絕意，政苦婚嫁迫。", "終從大人議，稅駕邗溝側。", "追蹤漢兩疏，父子老阡陌。"]'),
('37d295b7-30b4-4d75-aa7f-8e6e10a43078','送李端叔從辟中山','秦觀','宋','宋诗','song-poetry','','[]','人畏朔風聲，我聞獨寬懷。',144,'全唐诗/poet.song.59000.json','["人畏朔風聲，我聞獨寬懷。", "豈不知凜冽，爲自中山來。", "端叔天下士，淹留蹇無成。", "去從中山辟，良亦慰平生。", "與君英妙時，俠氣上參天。", "孰云行半百，身世各茫然。", "當時兒戲念，今日已灰死。", "著書如結氂，聊以忘憂耳。", "駸駸歲遒盡，淮海歸無期。", "功名良獨難，雖成定奚爲。", "念君遠行役，中夜憂反側。", "攬衣起成章，贈以當馬策。"]'),
('5cde3500-f96f-4448-9d73-4ff4d731806e','贈蹇法師翊之','秦觀','宋','宋诗','song-poetry','','[]','天都九經緯，人物如紡績。',120,'全唐诗/poet.song.59000.json','["天都九經緯，人物如紡績。", "豈無僊聖游，但未見哀識。", "蹇師蜀方士，鬼物充服役。", "朅來長安城，摩挲金銅狄。", "大蛇死已論，葛陂囚且釋。", "是事何足云，聊爾恤艱厄。", "方從馬明生，西去鍊金液。", "丹成得度世，造化爲莫逆。", "予亦江海人，名宦偶牽迫。", "投劾去未能，見師三歎息。"]'),
('cf401db4-f186-4623-b4ee-69deaa786339','送劉貢父舍人二首  其一','秦觀','宋','宋诗','song-poetry','','[]','虎去藜藿採，珠在其川媚。',120,'全唐诗/poet.song.59000.json','["虎去藜藿採，珠在其川媚。", "君子一詘信，實繫天下事。", "念昔元豐間，公初謫南裔。", "託詞吊湘水，聞者爲心醉。", "踰年憸臣逐，國老起相繼。", "除公守襄陽，士始有生意。", "茲焉歸法從，乃是朝廷計。", "在公何足云，事業本餘棄。", "掖垣美花木，入直春正麗。", "同僚看家風，立馬揮九制。"]'),
('bf068d77-88f8-4122-999c-6c2978b5638d','送劉貢父舍人二首  其二','秦觀','宋','宋诗','song-poetry','','[]','觀也本諸生，早與世參商。',120,'全唐诗/poet.song.59000.json','["觀也本諸生，早與世參商。", "方枘不量鑿，交親指爲狂。", "末路辱公知，賜出非所望。", "相期古人處，豈止事文章。", "汝南雖奧區，校官實始張。", "解鞅百無有，栖栖寄僧坊。", "築室從有徒，皆公借餘光。", "一壺千金直，所濟在倉黄。", "萬里猶比鄰，別離無足傷。", "何以報公德，修好以爲常。"]'),
('8df04d1a-d369-41e0-8938-2ec51667b032','南京妙峰亭','秦觀','宋','宋诗','song-poetry','','[]','王公厭承明，出守南宮鑰。',192,'全唐诗/poet.song.59000.json','["王公厭承明，出守南宮鑰。", "結構得崇岳，巋然瞰清洛。", "是時謫仙人，發軔自廬霍。", "郊原春鳥鳴，來此動豪酌。", "報投一何富，玉桉金刀錯。", "新牓揭中楹，千載見遠託。", "朅來訪陳迹，物色屬搖落。", "人烟隔鳬雁，田疇带城郭。", "紅蕖隕風漪，砂礫卷飛籜。", "青青陵上姿，獨汝森自若。", "人生如博奕，得喪難前約。", "金鎚初控頤，已復東方作。", "大明昇中天，龍鸞入階閣。", "深懲漁奪弊，法令一刊削。", "斯民如解懸，喜氣鬰磅礴。", "公乎數登覽，行矣翔寥廓。"]'),
('3335b22c-d6ad-4b00-b458-7bc9b02d7910','次韵奉酬丹元先生','秦觀','宋','宋诗','song-poetry','','[]','金華紫烟客，來作牧羊兒。',96,'全唐诗/poet.song.59000.json','["金華紫烟客，來作牧羊兒。", "至言初無文，尋繹自成詩。", "二景入妙解，元氣含烟詞。", "憐我鬣蒼浪，黄埃眩蟲絲。", "勸解冠上纓，一濯含風漪。", "攝身列缺外，倒躡蜿蜒鬐。", "維斗錯明珠，望舒耿脩眉。", "真游無疆界，浩蕩天風吹。"]'),
('20f4ddd7-15bf-454f-b984-dd3c63b7aec1','送裴仲謨','秦觀','宋','宋诗','song-poetry','','[]','君才出於德，妙高如匠石。',168,'全唐诗/poet.song.59000.json','["君才出於德，妙高如匠石。", "但見廣厦成，不見斧斤迹。", "厚爲諸兄奉，自奉頗云嗇。", "三生陽亢宗，薄俗有慚色。", "汝南古佳郡，月旦評一易。", "爾來似揚州，不辦龍蜥蜴。", "短簿髯參軍，喜怒移頃刻。", "正平竟獲免，實我文舉力。", "念公當乖隔，憂思如紡績。", "恥爲兒女仁，到此淚橫臆。", "熙朝大烹飪，賢者不家食。", "朝爲郡縣吏，暮作臺省客。", "矧聞諸法從，久欲薦言責。", "去去勿重陳，九萬自此擊。"]'),
('1ed4043b-9c85-4b18-a412-0e4a9c751b8d','題雙松寄陳季常','秦觀','宋','宋诗','song-poetry','','[]','遥聞連理松，託根黄麻城。',48,'全唐诗/poet.song.59000.json','["遥聞連理松，託根黄麻城。", "枝枝相鉤带，葉葉同死生。", "雖云金石姿，未免兒女情。", "想應風月夕，滿庭合歡聲。"]'),
('8993da2c-98d1-47e9-b615-9f1a3295bd41','徐仲車食於學官吏或以爲不可欲罷去之太守不聽禮遇如初感之而作','秦觀','宋','宋诗','song-poetry','','[]','許丞老病聾，督郵白欲廢。',156,'全唐诗/poet.song.59000.json','["許丞老病聾，督郵白欲廢。", "賢哉黄次公，鑒裁實精詣。", "殷勤謝督郵，此丞乃廉吏。", "重聽庸何傷，善助無失意。", "古人骨已朽，來者復誰繼。", "仲車天下士，固非許丞類。", "至行通神明，問學有根柢。", "若充老更聘，自革風俗弊。", "太守前已聞，粟帛俄見賜。", "奈何少年子，輒效督郵事。", "道喪賢哲窮，聞之爲流涕。", "人心如其面，難以一律揆。", "所望在次公，督郵何足議。"]'),
('34ade70a-31dc-4c92-acee-47aa33e71b26','次韵夏侯太沖秀才','秦觀','宋','宋诗','song-poetry','','[]','儒官飽閑散，室若僧坊靜。',84,'全唐诗/poet.song.59000.json','["儒官飽閑散，室若僧坊靜。", "北窗腹便便，支枕看斗柄。", "或時得名酒，亭午猶中聖。", "醒來復何事，弄筆賦秋興。", "焉知懶是真，但覺貧非病。", "茫茫流水意，會有知音聽。", "鐘鼎與山林，人生各天性。"]'),
('db888fe6-0f1e-425a-a599-11032171439e','送張和叔兼簡黄魯直','秦觀','宋','宋诗','song-poetry','','[]','汝南如一器，百千聚飛蚊。',120,'全唐诗/poet.song.59000.json','["汝南如一器，百千聚飛蚊。", "終然鼓狂鬧，啾啾竟誰聞。", "議郎盛德後，清修繼先芬。", "未試霹靂手，低回從此君。", "學官冷於水，虀鹽度朝曛。", "間蒙相煖熱，破憂發孤欣。", "君今又復去，冀北遂空羣。", "豈無一樽酒，誰與通殷勤。", "大梁多豪英，故人滿青雲。", "爲謝黄叔度，鬢毛今白紛。"]'),
('f80fc409-28ce-4773-8604-1a89d72b690b','題騕褭圖','秦觀','宋','宋诗','song-poetry','','[]','雙瞳夾鏡權協月，尾鬣蕭森澤於髮。',128,'全唐诗/poet.song.59000.json','["雙瞳夾鏡權協月，尾鬣蕭森澤於髮。", "鞍銜不施韁復脫，旁無馭者氣騰越。", "地如砥平丘隴滅，天寒日暮抱饑渴。", "驤首號鳴思一發，超軼絕塵入恍忽。", "東門金鑄久銷歇，曹霸丹青亦云沒。", "頼有龍眠戲揮筆，眼前時見千里骨。", "玉臺閶闔相因依，嗟爾龍媒空自奇。", "鸞旗日行三十里，焉用逐風追電爲。"]'),
('7bc899f8-a173-462e-8874-0a6c5d9a2b0f','和東坡紅鞓带','秦觀','宋','宋诗','song-poetry','','[]','君不見相如容貌窮不枯，卓氏恥之分百奴。',163,'全唐诗/poet.song.59000.json','["君不見相如容貌窮不枯，卓氏恥之分百奴。", "一朝奉指使筇筰，駟馬赤車從萬夫。", "仲元君平更高妙，寄食耕卜霜眉鬚。", "兩川人物古不乏，數子風流今可無。", "參軍少年飽經術，期作侍中司御壺。", "老披青衫更矍鑠，上馬不用兒孫扶。", "一朝忽解印綬去，恥將詩禮攘裙襦。", "懸知百年事已定，却笑列仙形甚臞。", "東阡北陌西風入，瑞草橋邊人叫呼。", "想見紅圍照白髮，頹然醉卧文君壚。"]'),
('2441c42c-fc65-4ac4-bc76-1b9f9314d823','和王忠玉提刑','秦觀','宋','宋诗','song-poetry','','[]','嵩峰何其高，峰高氣尤清。',120,'全唐诗/poet.song.59000.json','["嵩峰何其高，峰高氣尤清。", "念昔秋欲老，從公峰下行。", "古木上參天，哀禽報新晴。", "脩塗雲外轉，槁葉風中零。", "曛黑度伊水，眇然古今情。", "黎明出龍門，山川莽難名。", "信美非吾土，顧瞻懷楚萍。", "美人天一方，傷哉誰目成。", "黄綬我聊爾，白鷗公勿驚。", "糟醨可餔啜，古人忌偏醒。"]'),
('b508a8a6-b524-4f49-90d5-1745f8f20286','題楊康功醉道士石','秦觀','宋','宋诗','song-poetry','','[]','黄冠初飲何人酒，徑醉頹然不知久。',160,'全唐诗/poet.song.59000.json','["黄冠初飲何人酒，徑醉頹然不知久。", "風吹化石楚山阿，藤蔓纏身蘚封口。", "常隨白鶴亦飛去，但有衣冠同不朽。", "異物終爲賢俊得，野老田夫豈宜有。", "華陰楊公香桉吏，一見遂作忘年友。", "日暮西垣視草歸，往往對之傾數斗。", "大夢之間無定論，啟母望夫天所誘。", "穀城或與子房期，西域更爲陳那吼。", "我疑黄冠反見玩，若此堅頑定醒否。", "何當一笑凌蒼霞，顧謝主人聊舉手。"]'),
('dcabfd3e-3727-47b8-9294-ee00d5dbcbca','送蔡子驤用蔡子駿韵','秦觀','宋','宋诗','song-poetry','','[]','越絕山川遠相屬，萬壑千巖抱青綠。',192,'全唐诗/poet.song.59000.json','["越絕山川遠相屬，萬壑千巖抱青綠。", "卧龍一峰稱是奇，遶趾清漪如带束。", "鏡水春生鶂尾銜，稽山日暮猿聲續。", "三休上與蓬萊接，登眺使人遺寵辱。", "我昔東游觀禹穴，痛飲狂歌得所欲。", "上天何曾有官府，鸞鳳日日遭鞭扑。", "僧坊畫壁閱幾徧，神妙難忘獨金粟。", "華胥夢斷已十年，又見春風煮餳粥。", "苧羅若耶固依舊，可憐雲月誰追逐。", "故人淡泊出天性，鷦鷯巢林一枝足。", "不肯弦歌甘筦庫，還同市門隠梅福。", "惟應月下小叢歌，尚有哀音傳舊俗。"]'),
('97ff81a8-54a5-4035-8f3b-e9fc44ad5fc1','飲酒詩四首  其一','秦觀','宋','宋诗','song-poetry','','[]','我觀人間世，無如醉中真。',48,'全唐诗/poet.song.59000.json','["我觀人間世，無如醉中真。", "虛空爲消隕，況乃百憂身。", "惜哉知此晚，坐令華髮新。", "聖人難驟得，得且致賢人。"]'),
('b019db8c-3693-44f6-ab2a-3344df15b2c3','飲酒詩四首  其二','秦觀','宋','宋诗','song-poetry','','[]','左手持蟹螯，舉觴屬雲漢。',48,'全唐诗/poet.song.59000.json','["左手持蟹螯，舉觴屬雲漢。", "天生此神物，爲我洗憂患。", "山川同恍惚，魚鳥共蕭散。", "客至壺自傾，欲去不容間。"]'),
('3928f3da-2e8b-4dd2-bc02-7da3a9a8971c','飲酒詩四首  其三','秦觀','宋','宋诗','song-poetry','','[]','客從南方來，酌我一甌茗。',48,'全唐诗/poet.song.59000.json','["客從南方來，酌我一甌茗。", "我酌初不啜，彊啜且復醒。", "既鑿渾沌氏，遂出華胥境。", "操戈逐儒生，舉觴還酩酊。"]'),
('6d8cc84a-db39-4350-8a85-1d24a6e3dcb1','飲酒詩四首  其四','秦觀','宋','宋诗','song-poetry','','[]','雷觴淡如水，經年不濡脣。',48,'全唐诗/poet.song.59000.json','["雷觴淡如水，經年不濡脣。", "爰有擾龍系，爲造英靈春。", "英靈韵甚高，蒲萄難爲鄰。", "他年血食汝，應配杜康神。"]'),
('12701659-bad1-4729-a2d6-3f01207a9a54','艇齋','秦觀','宋','宋诗','song-poetry','','[]','平生樂漁釣，放浪江湖間。',72,'全唐诗/poet.song.59000.json','["平生樂漁釣，放浪江湖間。", "兀兀寄幽艇，不憂浪如山。", "聞君城郭居，左右羣書環。", "有齋亦名艇，何時許追攀。", "釣古不釣今，所得孔與顔。", "不然如爾祖，跨鶴出雲寰。"]'),
('10def70e-6a33-4cbe-9b1a-2d50b5fd8053','和裴仲謨放兔行','秦觀','宋','宋诗','song-poetry','','[]','兔饑食山林，兔渴飲川澤。',116,'全唐诗/poet.song.59000.json','["兔饑食山林，兔渴飲川澤。", "與人不瑕玼，焉用苦求索。", "天寒草枯死，見窘何太迫。", "上有蒼鷹禍，下有黄犬厄。", "一死無足悲，所恥敗頭額。", "敢期揮金遇，倒橐無難色。", "雖乖獵者意，頗塞仁人責。", "兔兮兔兮聽我言，月中仙子最汝憐。", "不如亟返月中宿，休顧商巖并嶽麓。"]'),
('7f0702b5-0b33-40d8-9595-662ba963af64','和裴仲謨摘白鬚行','秦觀','宋','宋诗','song-poetry','','[]','仲將題凌雲，比訖鬚盡白。',168,'全唐诗/poet.song.59000.json','["仲將題凌雲，比訖鬚盡白。", "陸展媚側室，星星染爲黑。", "人生如寄耳，況復形與色。", "澤壑藏山舟，夜半輸有力。", "厖眉三不遇，已矣何所惜。", "二毛賦秋興，自愛頗姑息。", "聞諸古竺乾，毛髮因地得。", "數窮反其本，螻螘得而食。", "妙年光可鑒，烱若鴉羽戢。", "映梳漸蕭肅，變化了無隙。", "所以梵志云，昔人已非昔。", "皤然君勿笑，子羽以貌失。", "信美如客兒，終翦施摩詰。", "我作白鬚行，而得養生術。"]'),
('bd312289-1499-4269-837c-5e4cc9f2cfaf','覿覯二弟作小室請書魯直名曰寄寂作此寄之用孫子實韵','秦觀','宋','宋诗','song-poetry','','[]','力田不逢年，識者未宜閔。',120,'全唐诗/poet.song.59000.json','["力田不逢年，識者未宜閔。", "他時歲在金，百兩無虛稛。", "士生當自量，天道平如準。", "汝兄魯叔山，正坐不前謹。", "有琴亦無弦，何心尚求軫。", "客來欲頹玉，大白輒滿引。", "官長既屢駡，諸生亦時囅。", "一口吸西江，玄哉居士藴。", "歲寒知蒼松，日暮識丹槿。", "夢想八九椽，森然羅玉筍。"]'),
('4886a041-aa1a-49a3-a931-cac707d7154d','南都新亭行寄王子發','秦觀','宋','宋诗','song-poetry','','[]','洛水沄沄天上動，道入隋渠下梁宋。',304,'全唐诗/poet.song.59000.json','["洛水沄沄天上動，道入隋渠下梁宋。", "宋都堤上十二亭，一一飛驚若鸞鳳。", "光華遠繼周王雅，宴喜還歸魯侯頌。", "玉觴嚴令肅衣冠，金縷哀音繞梁棟。", "娟娟殘月照波翻，習習暖風吹鳥哢。", "何處高帆落文鷁，誰家駿馬嘶征鞚。", "柳枝芳草恨連天，暮雨朝雲同昨夢。", "借問亭名製者誰，留守王公才望重。", "胸中雲夢吞八九，日解千牛節皆中。", "祥符相公實曾祖，庭列三槐多伯仲。", "承明厭直出荆州，轉守此都行大用。", "此都去天纔尺五，交廣荆揚歸引控。", "兔園事迹化黄埃，清泠文雅堪長慟。", "舳艫銜尾車挂轊，昨日出迎今日送。", "送故迎新無已時，古往今來相戲弄。", "亭下嶔崎淮海客，末路逢公詩酒共。", "一樽明日難重持，豈恤官期後芒種。", "今年氣候頗云早，夭矯梅花春欲縱。", "行見亭中祖帳開，千乘送公歸法從。"]'),
('ce004cf2-3c71-4539-9741-7c547ebe372d','反初','秦觀','宋','宋诗','song-poetry','','[]','昔年淮海未，邂逅安期生。',144,'全唐诗/poet.song.59000.json','["昔年淮海未，邂逅安期生。", "記我有靈骨，法當遊太清。", "區中緣未斷，方外道難成。", "一落世間網，五十換嘉平。", "夜參半不寢，披衣涕縱橫。", "誓當反初服，仍先謝諸彭。", "晞髮陽之阿，餔餟太和精。", "心將虛無合，身與元氣并。", "陟降三境中，高真相送迎。", "琅函紀前績，金蒲錫嘉名。", "耿光洞寥廓，不借日月明。", "故棲黄埃裹，絕想空復情。"]'),
('a630d3f0-6348-460b-a642-3671d8b6d397','寄蓴薑法魚糟蟹','秦觀','宋','宋诗','song-poetry','','[]','鮮鯽經年漬醽醁，團臍紫蟹脂填腹。',96,'全唐诗/poet.song.59000.json','["鮮鯽經年漬醽醁，團臍紫蟹脂填腹。", "後春蓴茁滑於酥，先社薑芽肥勝肉。", "鳬卵累累何足道，飣餖盤餐亦時欲。", "淮南風俗事瓶罌，方法相傳爲旨蓄。", "魚鱐蜃醢薦籩豆，山蔌溪毛例蒙錄。", "輒送行庖當擊鮮，澤居備禮無麋鹿。"]'),
('1eff517d-6071-424c-ba63-6c64a24ca174','精思','秦觀','宋','宋诗','song-poetry','','[]','精思洞元化，白日昇高旻。',120,'全唐诗/poet.song.59000.json','["精思洞元化，白日昇高旻。", "俯仰凌倒景，龍行速如神。", "半道過紫府，弭節聊逡巡。", "金床設寶几，璀璨明月珍。", "僊者二三子，眷然骨肉親。", "飲我霞一杯，放懷暖如春。", "遂朝玉虛上，冠劍班列真。", "無端拜失儀，放斥令自新。", "雲霄難遽返，下土多埃塵。", "淮南守天庖，嗟我實何人。"]'),
('fb0eaad1-edf1-443b-b475-d1809283665f','送楊康功守蘇','秦觀','宋','宋诗','song-poetry','','[]','公於萬事輕，獨嗜山水重。',120,'全唐诗/poet.song.59000.json','["公於萬事輕，獨嗜山水重。", "寓直西掖垣，滄洲長入夢。", "廣陵一都會，厨酒萬斯甕。", "每歎闕登臨，持此將焉用。", "比持蘇臺節，論鬰縉紳共。", "翻云美泉石，汔可小嬉弄。", "匆匆治行李，草草別賓從。", "乃知仁智心，所樂異庸衆。", "梅花發春端，百卉日興動。", "公等行復反，臺閣俟鸞鳳。"]'),
('2bcf5d05-bdf6-4065-90f2-b3c9005e97bf','偶戲','秦觀','宋','宋诗','song-poetry','','[]','偶戲失班龍，坐謫崑崙陰。',120,'全唐诗/poet.song.59000.json','["偶戲失班龍，坐謫崑崙陰。", "崑崙一何高，去天無數尋。", "嘉禾穗盈車，珠玉烱成林。", "天飄時一拂，清哀動人心。", "一面四百門，宮譙雲氣侵。", "闕然竹使符，難矣暫登臨。", "羣仙來按行，憐我久滯淫。", "力請始云免，反室歲已深。", "親朋喜我來，感歎或霑襟。", "塵寰君勿悲，殊勝巢嶔崟。"]'),
('229262be-c65b-4afe-98c0-44957ed4718a','次韵黄冕仲寄題順興步雲閣','秦觀','宋','宋诗','song-poetry','','[]','故山無期大刀頭，黄塵溽暑未罷休。',96,'全唐诗/poet.song.59000.json','["故山無期大刀頭，黄塵溽暑未罷休。", "步雲之篇忽我投，便見冰玉懸清秋。", "順興山川甲閩甌，無風萬壑松颼颼。", "步雲之人人品優，御風禦寇真其儔。", "仙人乘槎凌斗牛，回環十見天星周。", "猿鶴忽驚空蕙帳，周家正要磻溪望。"]'),
('33068894-7866-4a9f-af3a-9bf1f7b25dc6','正仲左丞生日','秦觀','宋','宋诗','song-poetry','','[]','元氣鍾英偉，東皇賦炳靈。',240,'全唐诗/poet.song.59000.json','["元氣鍾英偉，東皇賦炳靈。", "蓂敷十一葉，椿茂八千齡。", "汗血來西極，摶風出北溟。", "之無分襁褓，詩禮學趨庭。", "妙質珠遺海，高材刃發硎。", "亟更芸閣祕，屢直瑣闈青。", "史筆開凡例，綸言正緯經。", "文昌頻曳履，京兆屢空囹。", "遂總臺綱紀，常參國典刑。", "兩宮隆眷遇，諸夏聳瞻聽。", "武略驅雷電，文鋒粲斗星。", "乞閑辭亢滿，分逸下青冥。", "騎引雙朱服，腰橫萬寶釘。", "明峰春矗矗，汝水暮泠泠。", "散策花間徑，揮犀水上亭。", "壺觴延墨客，燈燭按歌伶。", "周衮歸公旦，商巖夢武丁。", "久聞虛揆席，佇見返皇扃。", "別數汾陽考，重鎸宋父銘。", "巍然廟堂上，永作世儀形。"]'),
('d3218b75-25f5-454b-a394-abd8ba892afb','病犬','秦觀','宋','宋诗','song-poetry','','[]','犬以守禦用，老憊將何爲。',120,'全唐诗/poet.song.59000.json','["犬以守禦用，老憊將何爲。", "踉蹌劣於行，纍然抱渴饑。", "主人恩義易，勿爲升斗資。", "黽勉不肯去，猶若戀藩籬。", "屠膾意得逞，烹庖在須斯。", "糟糠固非意，豚矢同一時。", "念昔初得寵，青韁纏閟絲。", "飼養候饑飽，動止常相隨。", "胡云不終始，委逐在衰遲。", "犬死不足道，固爲主人悲。"]'),
('15322cc9-393c-418f-9a00-cf9159934a16','贈女冠暢師','秦觀','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u5973\u5b50", "\u5199\u4eba\u8bd7"]','瞳人剪水腰如束，一幅烏紗裹寒玉。',64,'全唐诗/poet.song.59000.json','["瞳人剪水腰如束，一幅烏紗裹寒玉。", "飄然自有姑射姿，回看粉黛皆塵俗。", "霧閤雲窗人莫窺，門前車馬任東西。", "禮罷曉壇春日靜，落紅滿地乳鴉啼。"]'),
('e1469977-e592-4b53-8142-d6b1a830fe66','和子瞻雙石','秦觀','宋','宋诗','song-poetry','','[]','天鑱海濱石，鬰若龜毛綠。',168,'全唐诗/poet.song.59000.json','["天鑱海濱石，鬰若龜毛綠。", "信爲小仇池，氣象宛然足。", "連巖下空洞，鼎張彭亨腹。", "雙峰照清漣，春眉鏡中蹙。", "疑經女媧鍊，或入金華牧。", "鑪熏充雲氣，研滴當川瀆。", "尤物足移人，不必珠與玉。", "道旁初無異，漢將疑虎伏。", "支機亦何據，但出君平卜。", "奇礓入華林，傾都自追逐。", "我願作陳那，令吼震山谷。", "一拳既在夢，二駒空所欲。", "大士捨寶陀，仙人遺句曲。", "惟詩落人間，如傳置郵速。"]'),
('9d65e0b4-2ab6-4e45-b40a-6e46f85faca5','徐得之閑軒','秦觀','宋','宋诗','song-poetry','','[]','建安自古多俊髦，徐子磊落尤其豪。',112,'全唐诗/poet.song.59000.json','["建安自古多俊髦，徐子磊落尤其豪。", "論兵說劍走湖海，身勤事左無所遭。", "綠林五校已屠膾，黑衣三衛羞徒勞。", "歸來故山便卜築，脫棄萬事輕鴻毛。", "橫前澗水漱哀玉，傍舍老櫪藏飛猱。", "山蔬何用媿粱肉，鶴氅未必輸青袍。", "追寒弄月有真意，慎勿輕語傳兒曹。"]'),
('7d8eaf55-b7a7-445a-b37e-65e4c1d0b853','雷陽書事  其一','秦觀','宋','宋诗','song-poetry','','[]','駱越風俗殊，有疾皆勿藥。',48,'全唐诗/poet.song.59000.json','["駱越風俗殊，有疾皆勿藥。", "束带趨祀房，用史巫紛若。", "弦歌薦繭栗，奴士洽觴酌。", "呻吟殊未央，更把鷄骨灼。"]'),
('c21994c3-f8dd-43ee-aad8-22960c31c077','雷陽書事  其二','秦觀','宋','宋诗','song-poetry','','[]','一笛一腰鼓，鳴聲甚悲凉。',48,'全唐诗/poet.song.59000.json','["一笛一腰鼓，鳴聲甚悲凉。", "借問此何爲，居人朝送殤。", "出郭披莽蒼，磨刀向豬羊。", "何須作佳事，鬼去百無殃。"]'),
('77d1c9ea-7c54-4a82-8af0-fb629d43770f','雷陽書事  其三','秦觀','宋','宋诗','song-poetry','','[]','舊傳日南郡，野女出成群。',48,'全唐诗/poet.song.59000.json','["舊傳日南郡，野女出成群。", "此去尚應遠，東門已如雲。", "蚩氓託絲布，相就通慇懃。", "可憐秋胡子，不遇卓文君。"]'),
('659ceb02-7091-4972-8e6d-85a8a6474980','海康書事十首  其一','秦觀','宋','宋诗','song-poetry','','[]','白髮坐鉤黨，南遷海瀕州。',48,'全唐诗/poet.song.59000.json','["白髮坐鉤黨，南遷海瀕州。", "灌園以餬口，身自雜蒼頭。", "籬落秋暑中，碧花蔓牽牛。", "誰知把鋤人，舊日東陵侯。"]'),
('9d15cd1d-eee4-4302-9d6f-fa56ebceef8b','海康書事十首  其二','秦觀','宋','宋诗','song-poetry','','[]','荔子無幾何，黄柑遽如許。',48,'全唐诗/poet.song.59000.json','["荔子無幾何，黄柑遽如許。", "遷臣不惜日，恣意移寒暑。", "層巢俯雲木，信美非吾土。", "草芳自有時，鵯鵊何關汝。"]'),
('9aaca6a7-7536-47f0-9052-fcd66b2937bf','海康書事十首  其三','秦觀','宋','宋诗','song-poetry','','[]','卜居近流水，小巢依嶔岑。',48,'全唐诗/poet.song.59000.json','["卜居近流水，小巢依嶔岑。", "終日數椽間，但聞鳥遺音。", "鑪香入幽夢，海月明孤斟。", "鷦鷯一枝足，所恨非故林。"]'),
('8e76e392-02c7-40d4-aa6a-7a2078579c78','海康書事十首  其四','秦觀','宋','宋诗','song-poetry','','[]','培塿無松栢，駕言出焉遊。',48,'全唐诗/poet.song.59000.json','["培塿無松栢，駕言出焉遊。", "讀書與意會，却掃可忘憂。", "尺蠖以時詘，其信亦非求。", "得歸良不惡，未歸且淹留。"]'),
('f8c25bc1-804a-471c-a8f4-5a5291b185c8','海康書事十首  其五','秦觀','宋','宋诗','song-poetry','','[]','粵女市無常，所至輒成區。',48,'全唐诗/poet.song.59000.json','["粵女市無常，所至輒成區。", "一日三四遷，處處售蝦魚。", "青裙脚不襪，臭味猨與狙。", "孰云風土惡，白州生綠珠。"]'),
('b25526e8-f481-4b3e-8805-b72b973ddf99','海康書事十首  其六','秦觀','宋','宋诗','song-poetry','','[]','海康臘己酉，不論冬孟仲。',48,'全唐诗/poet.song.59000.json','["海康臘己酉，不論冬孟仲。", "殺牛檛祭鼓，城郭爲沸動。", "雖非堯曆頒，自我先人用。", "大笑荆楚人，嘉平獵雲夢。"]'),
('90efa654-25ef-4633-b7c7-4dbf5862ed75','海康書事十首  其七','秦觀','宋','宋诗','song-poetry','','[]','粲粲菴摩勒，作湯美無有。',48,'全唐诗/poet.song.59000.json','["粲粲菴摩勒，作湯美無有。", "上客賦驪駒，玉奩開素手。", "那知蒼梧野，棄置同芻狗。", "荆山玉抵鵲，此事繇來久。"]'),
('7fcaf2b1-aa9a-4344-ad53-ff0aefd2c7c7','海康書事十首  其八','秦觀','宋','宋诗','song-poetry','','[]','裔土桑柘希，蠶月不紡績。',51,'全唐诗/poet.song.59000.json','["裔土桑柘希，蠶月不紡績。", "吳綃與魯縞，取具{舟罔}船客。", "一朝南風發，家室相怵迫。", "半賈鬻我藏，倍稱還君息。"]'),
('9abe0fab-d770-439c-9f3b-970ac33f5b2d','海康書事十首  其九','秦觀','宋','宋诗','song-poetry','','[]','一雨復一暘，蒼茫颶風發。',48,'全唐诗/poet.song.59000.json','["一雨復一暘，蒼茫颶風發。", "怒號兼晝夜，山海爲顛蹶。", "云何大塊噫，乃爾不可遏。", "黎明衆竅虛，白日麗空闊。"]'),
('54841073-db43-487c-a3b1-740e56d76614','海康書事十首  其一○','秦觀','宋','宋诗','song-poetry','','[]','合浦古珠池，一熟胎如山。',48,'全唐诗/poet.song.59000.json','["合浦古珠池，一熟胎如山。", "試問池邊蜑，云今累年閑。", "豈無明月珍，轉徙溟渤間。", "何關二千石，時至自當還。"]'),
('22aa6f3c-5def-41ae-b84d-8122419537b8','次韵曾存之嘯竹軒','秦觀','宋','宋诗','song-poetry','','[]','翩翩曾公子，子猷定前身。',60,'全唐诗/poet.song.59000.json','["翩翩曾公子，子猷定前身。", "嗜好準疇昔，了然不緇磷。", "寄食平準官，植竹當比鄰。", "朝與竹相對，暮與竹相親。", "安可一日無，此君真可人。"]'),
('c66688cb-1e52-4cb4-acb3-5b7b2bc78f88','游仙二首  其一','秦觀','宋','宋诗','song-poetry','','[]','服形百神朝，刳心萬緣盡。',96,'全唐诗/poet.song.59000.json','["服形百神朝，刳心萬緣盡。", "我無退轉境，何以有精進。", "戲爲汗漫游，八極一何近。", "渺渺東海水，纍纍北邙墳。", "向來歌舞處，忽復成荒村。", "愚人如鹿耳，其死了無魂。", "孰知九霄間，玄圃枕崑崙。", "緇塵化人衣，蒼蘿誰與捫。"]'),
('539dc3c6-a6bd-44c8-bc7e-e49d605f6e49','游仙二首  其二','秦觀','宋','宋诗','song-poetry','','[]','雲車自天來，駕言游混茫。',132,'全唐诗/poet.song.59000.json','["雲車自天來，駕言游混茫。", "手持太一節，身佩使者章。", "龍虎傍夭矯，馬龜伏以翔。", "朝元紫微上，所睹浩難量。", "寶網結萬珠，參伍相焜煌。", "花品不知數，妙英拆玄房。", "宮殿隨人身，處處輒清凉。", "危髾擢貞玉，高謝人間妝。", "二三古鬚眉，冠雲带含光。", "遺我飛霞佩，副以明月璫。", "再拜敬服之，百毛發靈香。"]'),
('6377f731-e32b-40c2-b2ef-419599be9ff0','次韵答張文潜病中見寄','秦觀','宋','宋诗','song-poetry','','[]','與君涉世網，所得如鉤溫。',168,'全唐诗/poet.song.59000.json','["與君涉世網，所得如鉤溫。", "念昔相乖離，俯仰變寒暄。", "把袂安可期，寄書囑加餐。", "三年汝水濱，孤懷誰與言。", "末路非所望，聯鑣金馬門。", "校文多豫暇，玄談到羲軒。", "孰云笭箵小，史書垂後昆。", "匪惟以舊聞，牴牾良可刊。", "比枉病中作，筆端淮海奔。", "亟駕問所苦，兀坐一室閑。", "晤對不知夕，歸途斗星翻。", "平時带十圍，頗復減臂環。", "君其專精神，微恙不足論。", "愷悌神所勞，此理直如弦。"]'),
('3aae59b8-3cf0-41fc-94d2-31a1efd89c59','送喬希聖','秦觀','宋','宋诗','song-poetry','','[]','鷃翔蓬蒿非所悲，鵬擊風雲非所喜。',160,'全唐诗/poet.song.59000.json','["鷃翔蓬蒿非所悲，鵬擊風雲非所喜。", "貴賤窮通盡偶然，回頭總是東海水。", "我思田文昔相齊，朱袍照日如雲霓。", "三千冠珮醉明月，清歌一曲傾玻璃。", "如今陳迹知何在，但見荒冢烟蕪迷。", "又思原憲昔居魯，門戶東西閉環堵。", "杖藜對客騁高談，自覺胸襟輩堯禹。", "如今寂寞已成塵，空有聲名掛千古。", "送君去，何時回，世間如此令人哀。", "我徒駐足不可久，笑指白雲歸去來。"]'),
('b0601117-7f9f-45fc-963c-3c3d43bb92f5','與子瞻會松江得浪字','秦觀','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','松江浩無旁，垂虹跨其上。',120,'全唐诗/poet.song.59000.json','["松江浩無旁，垂虹跨其上。", "漫然銜洞庭，領略非一狀。", "怳如陣平野，萬馬攢穹帳。", "離離雲抹山，窅窅天粘浪。", "烟中漁唱起，鳥外征帆颺。", "愈知宇宙寬，斗覺東南壯。", "太史主文盟，諸豪盡詩將。", "超搖外形檢，語笑供頡頑。", "㛹娟棄不追，撥剌亦從放。", "獨留三百缸，聊用沃軒曠。"]'),
('33cdc4c4-3974-47d4-9aab-b0a049917360','德清道中還寄子瞻','秦觀','宋','宋诗','song-poetry','','[]','投曉理竿栧，溪行耳目醒。',120,'全唐诗/poet.song.59000.json','["投曉理竿栧，溪行耳目醒。", "蟲魚各蕭散，雲日共晶熒。", "水荇重深翠，烟山疊亂青。", "路迴逢短榜，崖斷點孤翎。", "叢薄開羅帳，淪漪寫鏡屏。", "疏籬窺窅窕，支港泛笭箵。", "遠溆依微見，哀猱斷續聽。", "夢長天杳杳，人遠樹冥冥。", "旅思搖風旆，歸期數月蓂。", "何時燃蜜炬，復聽閤前鈴。"]'),
('5af7246b-15eb-4c51-a3c0-b4d5d49ef4cd','次韵子由題斗野亭','秦觀','宋','宋诗','song-poetry','','[]','滿市花風起，平堤漕水流。',48,'全唐诗/poet.song.59000.json','["滿市花風起，平堤漕水流。", "不堪春解手，更爲晚停舟。", "古埭天連雁，荒祠木蔽牛。", "杖藜聊復爾，轉盼夕烟浮。"]'),
('78070b09-dde5-4746-82c6-c68eebbc50d1','鮮于子駿使君生日','秦觀','宋','宋诗','song-poetry','','[]','惟昔高堂夢，熊羆兆吉占。',240,'全唐诗/poet.song.59000.json','["惟昔高堂夢，熊羆兆吉占。", "氣鍾西蜀秀，時應仲秋嚴。", "江漢揮犀尾，風雲下筆尖。", "微辭追屈宋，精義到黄炎。", "操履森寒栢，名聲耿夜蟾。", "擊彊鵰鶚健，治劇鸊鵜銛。", "使者旌旄易，將軍印綬添。", "鴛鴻隨步武，虎豹入韜鈐。", "錦覆郎官被，彤垂太守襜。", "兩行分蜜炬，十里上珠簾。", "禮士常懸榻，誅姦或奮髯。", "雨堂昏絳帳，風帙亂牙籤。", "銀漢星初換，金莖露已霑。", "歡聲連北固，壽邑亙東漸。", "麗句充文几，奇香牣玉奩。", "簪紳五福具，罇俎四難兼。", "賤子真殊幸，清標獲屢覘。", "誤蒙雕朽木，猥辱畫無鹽。", "嘉運方熙洽，英才豈滯淹。", "佇公歸法從，行道慰民瞻。"]'),
('ee0f6e84-f33d-4dea-8727-0f31d36963ed','輦下春晴','秦觀','宋','宋诗','song-poetry','','[]','樓闕過朝雨，參差動霽光。',48,'全唐诗/poet.song.59000.json','["樓闕過朝雨，參差動霽光。", "衣冠紛禁路，雲氣繞宮牆。", "亂絮迷春闊，薦花困日長。", "經旬辜酒伴，猶未獻長楊。"]'),
('fbc7cc96-cdcd-4bea-aeaf-1a64ea458154','睡起','秦觀','宋','宋诗','song-poetry','','[]','睡起東軒下，悠悠春緒長。',48,'全唐诗/poet.song.59000.json','["睡起東軒下，悠悠春緒長。", "爬搔失幽囀，款欠墮危芳。", "蛛網留晴絮，蜂房受晚香。", "欲尋初斷夢，雲霧已冥茫。"]'),
('1e623fe4-9f81-4e4e-bd40-b5b76eb2aeb9','次韵莘老初至湯泉','秦觀','宋','宋诗','song-poetry','','[]','夾路山重複，參天樹老蒼。',48,'全唐诗/poet.song.59000.json','["夾路山重複，參天樹老蒼。", "一區成小市，數埒引溫湯。", "洗沐同幽客，餔餐就梵坊。", "未輸朝市子，斗酒得西凉。"]'),
('19dc1c38-e97e-4ec9-9652-cc9eaff53582','過六合水亭懷裴博士次韵','秦觀','宋','宋诗','song-poetry','','[]','晚憩孤亭上，羸驂繫斷柯。',48,'全唐诗/poet.song.59000.json','["晚憩孤亭上，羸驂繫斷柯。", "荒門寒带路，空檻闊增波。", "往事青山在，餘生白鳥過。", "誦言成絕唱，亹亹迫陰何。"]'),
('3d819868-f6ab-4bff-ad1f-c723abc54ab0','懷孫子實','秦觀','宋','宋诗','song-poetry','','[]','舉眼趨浮末，斯人獨好脩。',48,'全唐诗/poet.song.59000.json','["舉眼趨浮末，斯人獨好脩。", "青春三不惑，黄卷百無憂。", "玉出方流潤，鸞停翠竹幽。", "相思自成韵，不必寄西郵。"]'),
('45b47973-45bd-4ca9-bf2e-09048a2db816','對淮南詔獄二首  其一','秦觀','宋','宋诗','song-poetry','','[]','一室如懸磬，人音盡不聞。',48,'全唐诗/poet.song.59000.json','["一室如懸磬，人音盡不聞。", "老兵隨卧起，漂母給朝曛。", "樊雉思秋野，鞲鷹望暮雲。", "念歸忘食事，日減臂環分。"]'),
('70ceb5ba-6158-4d15-8ae0-eceb8c749a65','對淮南詔獄二首  其二','秦觀','宋','宋诗','song-poetry','','[]','淮海行搖落，文書亦罷休。',48,'全唐诗/poet.song.59000.json','["淮海行搖落，文書亦罷休。", "風霜欺獨宿，燈火伴冥搜。", "笳動朱樓曉，參橫粉堞秋。", "更拚飛鏡破，應得大刀頭。"]'),
('c07b9bbb-1cd7-4118-b8df-bee3a5fe53c6','次韵答米元章','秦觀','宋','宋诗','song-poetry','','[]','嗜好清無滓，周旋粲有文。',48,'全唐诗/poet.song.59000.json','["嗜好清無滓，周旋粲有文。", "揮毫春在手，岸幘海生雲。", "花鳥空撩我，蓴鱸正屬君。", "惟應讀雌蜺，差不愧王筠。"]'),
('f338f41b-9d14-44ec-a1c0-df414e05fc17','宿參寥房','秦觀','宋','宋诗','song-poetry','','[]','鄉國秋行暮，房櫳日已暝。',48,'全唐诗/poet.song.59000.json','["鄉國秋行暮，房櫳日已暝。", "驚風多犯竹，破月不藏星。", "鉤箔簷花動，抄書燭燼零。", "非關相見喜，自是眼長青。"]'),
('382a44ee-36cf-4328-853b-6c30feb1aef3','次韵蔣穎叔南郊祭告上清儲祥宮','秦觀','宋','宋诗','song-poetry','','[]','特起朝陽內，祠宮極邃清。',288,'全唐诗/poet.song.59000.json','["特起朝陽內，祠宮極邃清。", "高窗闚玉女，巨闑守昌明。", "盛掩秦諸畤，雄逾漢兩京。", "垣橫天上紫，洲露海中瀛。", "黄帝初龍躍，中原罷虎爭。", "樵夫亦談道，行旅不持兵。", "此地脩禳禬，于時保利亨。", "栢梁災未幾，陳寶詔重營。", "御帑金繒出，慈闈服玩并。", "標題動宸翰，撰次屬鴻生。", "玉刻黄冠印，金書祕殿名。", "妙經藏洞觀，真籙佩威盟。", "仙溜花間靜，瓊枝物外榮。", "肇禋承帝祉，肆眚順民情。", "天施寧論報，風行不計程。", "近傳聞磬管，時或見旄旌。", "海嶽朝雙闕，星辰集上楹。", "禮如尊太一，事異寵文成。", "大以圓丘報，長於至日迎。", "侍臣來祭告，法駕欲時行。", "釐事通元氣，高真達孝誠。", "慶增黄帝系，壽續太陰精。", "西北夷門峻，東南輦路傾。", "雲行博山氣，風卷步虛聲。"]'),
('c51937e1-d45b-472f-8333-1ac2ee993298','次韵米元章齋居即事','秦觀','宋','宋诗','song-poetry','','[]','庭木雙株茂，盆池一掬慳。',48,'全唐诗/poet.song.59000.json','["庭木雙株茂，盆池一掬慳。", "支頤魚出樂，入眥鳥知還。", "老境行將及，仙書讀未閑。", "因君歌鳳過，通昔夢歸山。"]'),
('3f8da5b6-2fe4-4850-825a-2c7e7ceba512','次韵酬陳傳道','秦觀','宋','宋诗','song-poetry','','[]','白髮三冬學，青衫八尺身。',48,'全唐诗/poet.song.59000.json','["白髮三冬學，青衫八尺身。", "誰知人上傑，聊作吏中循。", "揮翰通元氣，開編友古人。", "寄聲張氏子，曲逆豈長貧。"]'),
('5b388aac-869b-45c1-ad3f-a6438aea3468','次韵傳道自適兼呈都司芸叟學士','秦觀','宋','宋诗','song-poetry','','[]','楚國陳夫子，周南頗滯留。',48,'全唐诗/poet.song.59000.json','["楚國陳夫子，周南頗滯留。", "弊袍披槁葉，瘦馬兀扁舟。", "藥餌過三伏，文書散百憂。", "何人共禪悅，居士有浮休。"]'),
('0cd52ddc-af72-4bd7-82f8-ce4361217226','擬郡學試東風解凍','秦觀','宋','宋诗','song-poetry','','[]','寶曆開新歲，春回斗柄東。',72,'全唐诗/poet.song.59000.json','["寶曆開新歲，春回斗柄東。", "漪生天際水，凍解日邊風。", "浩蕩依蘋起，侵尋带雪融。", "江河霜練靜，池沼玉奩空。", "魚藻雍容裏，雲霄俯仰中。", "更無舟楫礙，從此百川通。"]'),
('1ccc90b2-23f9-4b0b-9ea7-76282d306cb3','駕幸太學','秦觀','宋','宋诗','song-poetry','','[]','原廟初更十二章，還輿詔蹕幸諸庠。',64,'全唐诗/poet.song.59000.json','["原廟初更十二章，還輿詔蹕幸諸庠。", "法天辟水遥迎仗，應月深衣不亂行。", "風動四夷將遣子，禮行三舍遂賓王。", "前知此舉追虞氏，果有球音發舜堂。"]'),
('fc3c610e-fc0e-47a8-8651-818a2ac52977','題閻求仁虛樂亭','秦觀','宋','宋诗','song-poetry','','[]','長官平昔嗜林丘，僧與開亭待勝遊。',64,'全唐诗/poet.song.59000.json','["長官平昔嗜林丘，僧與開亭待勝遊。", "修竹回環扶碧瓦，小池方折轉清流。", "春深鶗鴂催詩句，夜靜蟾蜍入酒舟。", "只恐政成留不得，縣人空此憶韋游。"]'),
('82894c64-0ee6-4d32-89bf-6378444c0907','懷李公擇學士','秦觀','宋','宋诗','song-poetry','','[]','一辭行旆楚亭皋，幾爲登臨掛鬰陶。',64,'全唐诗/poet.song.59000.json','["一辭行旆楚亭皋，幾爲登臨掛鬰陶。", "蓬斷草枯時節晚，山長水遠夢魂勞。", "流傳玉刻皆黄絹，早晚金閨報大刀。", "宣室方疑鬼神事，順風行看駛鴻毛。"]'),
('4920ea1b-ba1d-4b85-93ba-a10b2f8fbe36','題湯泉二首  其一','秦觀','宋','宋诗','song-poetry','','[]','滿斛泠泠注不窮，幻塵乾慧洗皆空。',64,'全唐诗/poet.song.59000.json','["滿斛泠泠注不窮，幻塵乾慧洗皆空。", "法流水接諸天上，神瀵香聞一國中。", "金粟示爲除病惱，跋陀仍已獲圓通。", "馬蹄又入風埃去，回首吳吟謝迮翁。"]'),
('29dbb3bc-80f0-4fe6-b60d-9ce893811b92','題湯泉二首  其二','秦觀','宋','宋诗','song-poetry','','[]','溫井霜寒碧甃澄，飛塵不動玉奩清。',64,'全唐诗/poet.song.59000.json','["溫井霜寒碧甃澄，飛塵不動玉奩清。", "老翁仙去羸驂共，太子東歸廢沼平。", "據石聊爲寶陀觀，决渠還落堰溪聲。", "浣腸灌頂雖殊事，一洗勞生病惱輕。"]'),
('b4382299-d27d-49e1-abb9-bd728eb31042','寄題王欽之自圓庵','秦觀','宋','宋诗','song-poetry','','[]','誅茅北戶結圓廬，從事風流入畫圖。',64,'全唐诗/poet.song.59000.json','["誅茅北戶結圓廬，從事風流入畫圖。", "珠箔粉垣藏混沌，葛巾藜杖造虛無。", "春閑居士天花室，晝靜仙人白玉壺。", "遥想吏行鳬鶩散，沉烟一穗對團蒲。"]'),
('14326552-094f-4962-a7c5-38bd9fe3dd2a','流觴亭并次韵二首  其一','秦觀','宋','宋诗','song-poetry','','[]','縹緲雲巒欲盡頭，灑然華構引飛流。',64,'全唐诗/poet.song.59000.json','["縹緲雲巒欲盡頭，灑然華構引飛流。", "朱盤瀲灧開冰鑑，碧甃縈紆走玉虬。", "毛骨漸驚超濁界，風烟驟覺變清秋。", "更憐白足如霜句，可羨溪邊六逸遊。"]'),
('a48a63b9-aa0d-4046-854d-98bf43d9c2b5','流觴亭并次韵二首  其二','秦觀','宋','宋诗','song-poetry','','[]','卧龍西畔北池頭，水擘華堂瑟瑟流。',64,'全唐诗/poet.song.59000.json','["卧龍西畔北池頭，水擘華堂瑟瑟流。", "幾曲漪漣盤翠带，一峰孤秀浴蒼虬。", "香囊近午清無汗，素扇生凉爽入秋。", "待喚畫師來貌取，圖成便是竹溪遊。"]'),
('b0d56c19-5f5d-4d4b-9f80-c221dd569e20','遊龍門山次程公韵','秦觀','宋','宋诗','song-poetry','','[]','路轉橫塘入亂峰，遍尋萧洒興無窮。',64,'全唐诗/poet.song.59000.json','["路轉橫塘入亂峰，遍尋萧洒興無窮。", "樓臺特起喧卑外，村落隨生指點中。", "溪傍五雲清逗玉，松分八面翠成宮。", "歸途父老欣相語，今日程公昔謝公。"]'),
('b714b56d-72a5-46a9-a181-8fcc58b94d4a','遊龍瑞宮次程公韵','秦觀','宋','宋诗','song-poetry','','[]','靈祠真館閟山隈，形勢相高對越臺。',64,'全唐诗/poet.song.59000.json','["靈祠真館閟山隈，形勢相高對越臺。", "莓徑翠依屏上轉，藕花紅繞鑑中開。", "鶴銜寶箭排烟去，龍護金書带雨來。", "夾道萬星攢騎火，滿城爭看使君回。"]'),
('859edb31-01f4-47ba-b6ad-15be4001ffa7','次韵朱李二君見寄二首    其一','秦觀','宋','宋诗','song-poetry','','[]','東阡北陌坐淹時，偶爲高風振羽儀。',64,'全唐诗/poet.song.59000.json','["東阡北陌坐淹時，偶爲高風振羽儀。", "十丈蓮花開處遠，三年楮葉刻成遲。", "鬢毛但速安仁老，錢粟難輸曼倩饑。", "尚頼故人遥省憶，發揮春色有新詩。"]'),
('fc143cbe-8d7f-44e8-b7a2-b2ed94f5eada','次韵朱李二君見寄二首    其二','秦觀','宋','宋诗','song-poetry','','[]','萬古流空一鳥沉，衣冠常苦事違心。',64,'全唐诗/poet.song.59000.json','["萬古流空一鳥沉，衣冠常苦事違心。", "七行俱下知君舊，四者難并笑我今。", "梅已偷春成國色，雲猶憑臘造天陰。", "美人綠綺煩遥贈，莫致南金增永吟。"]'),
('eea30088-9fa6-4609-82f0-bea125e5a6da','睡足軒二首    其一','秦觀','宋','宋诗','song-poetry','','[]','長年憂患百端慵，開斥僧坊頗有功。',64,'全唐诗/poet.song.59000.json','["長年憂患百端慵，開斥僧坊頗有功。", "地撤蔽虧僧界浄，人除荒穢玉奩空。", "青天併入揮毫裏，白鳥時興隠几中。", "最是人間佳絕處，夢殘風鐵響丁東。"]'),
('af3da188-8c2d-4180-81a8-287fc9fee1a1','睡足軒二首    其二','秦觀','宋','宋诗','song-poetry','','[]','數椽空屋枕清流，一榻蕭然散百憂。',64,'全唐诗/poet.song.59000.json','["數椽空屋枕清流，一榻蕭然散百憂。", "終日掩關塵境謝，有時開卷古人遊。", "鳴鳩去後滄浪晚，飛雨來初菡萏秋。", "此處便令君睡足，何須雲夢澤南州。"]'),
('b1471378-edcc-43ee-abf4-9a635b7e127f','寄孫莘老少監','秦觀','宋','宋诗','song-poetry','','[]','一出承明七換麾，君恩復許上彤墀。',64,'全唐诗/poet.song.59000.json','["一出承明七換麾，君恩復許上彤墀。", "白衣蒼狗無常態，璞玉渾金有定姿。", "天上圖書森似舊，人間歲月浪如馳。", "鼇頭只在蓬山畔，行赴蟠桃熟後期。"]'),
('fec5f9c5-43ac-429d-a059-5db5a963a53a','次韵馬忠玉喜王定國還自濱州','秦觀','宋','宋诗','song-poetry','','[]','淮海相逢一解顔，紛紛歲月夢魂間。',64,'全唐诗/poet.song.59000.json','["淮海相逢一解顔，紛紛歲月夢魂間。", "初驚漁艇迷花去，忽認星槎拂斗還。", "桂嶺暮登猿斷續，槐堂春到鳥綿蠻。", "石渠舊議行當復，未信佳時得自閑。"]'),
('1c238b86-9437-4c20-8066-6769b3552928','寄李公擇郎中','秦觀','宋','宋诗','song-poetry','','[]','節旄淮畔脫秋風，忽跨鯨魚上碧空。',64,'全唐诗/poet.song.59000.json','["節旄淮畔脫秋風，忽跨鯨魚上碧空。", "華秀兩跗當重露，文成五色在高桐。", "江南又說衣冠盛，廷右仍瞻禮樂隆。", "朝睍既升淮海見，瀌瀌雨雪自消融。"]'),
('9d34519b-6592-4d31-ae25-66ef1361a1d4','寄李端叔編修','秦觀','宋','宋诗','song-poetry','','[]','旗亭解手屢冬春，聞道歸來白髮新。',64,'全唐诗/poet.song.59000.json','["旗亭解手屢冬春，聞道歸來白髮新。", "馬革裹尸心未艾，金龜換酒氣方震。", "夢魂偷遶邊城月，道從公穿禁路塵。", "知有新編號橫槊，爲憑東使寄淮濱。"]'),
('f1b2d284-6c9f-465e-b453-89decc63941e','寄題倪敦復北軒','秦觀','宋','宋诗','song-poetry','','[]','倪郎才韵照冰壺，北向開軒頗自娛。',64,'全唐诗/poet.song.59000.json','["倪郎才韵照冰壺，北向開軒頗自娛。", "簷度蕙風鳴鴶鵴，壁經梅雨畫螔蝓。", "觥籌交錯銀河掛，文史縱橫角簟鋪。", "官舍私居同是漫，莫嗟三徑就荒蕪。"]'),
('e2222bfe-53c3-481a-9f0d-15b87440c2f5','寄題盧君斗齋','秦觀','宋','宋诗','song-poetry','','[]','俠氣軒軒翰墨場，邅迴世路鬢成霜。',64,'全唐诗/poet.song.59000.json','["俠氣軒軒翰墨場，邅迴世路鬢成霜。", "出從車馬行千里，歸與琴書寄一方。", "鳥囀入簾春欲破，爐香侵夢日初長。", "扁舟會有山陽役，聊借狂夫挹酒漿。"]'),
('be37f4ac-7063-4d57-b326-893f1548afe6','次韵酬周開祖宣義','秦觀','宋','宋诗','song-poetry','','[]','并州令尹古人風，淮海相忘十載中。',64,'全唐诗/poet.song.59000.json','["并州令尹古人風，淮海相忘十載中。", "麗句曉披花綽約，清談初扣玉丁東。", "追攀昔共猗玕子，嗜好今同桑苧翁。", "所惜華船輕解繂，未窺笠澤故書叢。"]'),
('57b8a997-2da9-457d-8c22-e4c5fbbe4956','送王元龍赴泗州','秦觀','宋','宋诗','song-poetry','','[]','子猷風味最諸王，試吏聊懷筦庫章。',64,'全唐诗/poet.song.59000.json','["子猷風味最諸王，試吏聊懷筦庫章。", "鵠峙碧桐初振羽，珠遺滄海漸騰光。", "淮山暮眺千峰擢，洛水秋輸萬鷁翔。", "顧我行爲大梁役，一巵薄酒話愁腸。"]'),
('2161e726-6fa0-4b8c-bedb-a9194d3c6b6d','廣陵五題 次韵子由題九曲池','秦觀','宋','宋诗','song-poetry','','[]','蕭瑟通池閟茂林，岸傍無復屬車音。',64,'全唐诗/poet.song.59000.json','["蕭瑟通池閟茂林，岸傍無復屬車音。", "涵春似恨隋家遠，漲曉疑連蜀井深。", "鬭草事空烟冉冉，司花人遠樹陰陰。", "勞生俛仰成陳迹，縱有遺聲可用尋。"]'),
('04f8348f-49a0-4bdd-b5f1-2c438431e082','廣陵五題 次韵子由題平山堂','秦觀','宋','宋诗','song-poetry','','[]','棟宇高開古寺間，盡收佳處入雕欄。',64,'全唐诗/poet.song.59000.json','["棟宇高開古寺間，盡收佳處入雕欄。", "山浮海上青螺遠，天轉江南碧玉寬。", "雨檻幽花滋淺淚，風巵清酒漲微瀾。", "遊人若論登臨美，須作淮東第一觀。"]'),
('f04902e2-1b94-4690-a910-d92393aee97e','廣陵五題 次韵子由題蜀井','秦觀','宋','宋诗','song-poetry','','[]','蜀岡精氣滀多年，故有清泉發石田。',64,'全唐诗/poet.song.59000.json','["蜀岡精氣滀多年，故有清泉發石田。", "乍飲肺肝俱澡雪，久窺杖屨亦輕便。", "炊成香稻流珠滑，煮出新茶潑乳鮮。", "坐使二公鄉思動，放杯西望欲揮鞭。"]'),
('fb541f6a-7634-4b1c-9b9e-0586ba2ded40','廣陵五題 次韵子由題摘星亭','秦觀','宋','宋诗','song-poetry','','[]','崑崙左右兩招提，中起孤高雉堞西。',64,'全唐诗/poet.song.59000.json','["崑崙左右兩招提，中起孤高雉堞西。", "不見燒香成宿霧，虛傳裁錦作障泥。", "螢流花苑飛星亂，蕪滿春城綠髮齊。", "長憶凭欄風雨後，斷虹明處海天低。"]'),
('ee68db28-9c34-43f9-81da-3e21de70da4e','廣陵五題 次韵子由題光化塔','秦觀','宋','宋诗','song-poetry','','[]','古佛悲憐得度人，應緣來現比丘身。',64,'全唐诗/poet.song.59000.json','["古佛悲憐得度人，應緣來現比丘身。", "水流月落知何處，花發鶑啼又一春。", "方外笑談清似玉，夢中煩惱細如塵。", "老僧自說從居此，却悔平時事遠巡。"]'),
('25c6826b-cc68-4fb9-aea3-96e8ca766ba3','次韵子瞻贈金山寶覺大師','秦觀','宋','宋诗','song-poetry','','[]','雲峰一變隔炎凉，猶喜重來飯積香。',64,'全唐诗/poet.song.59000.json','["雲峰一變隔炎凉，猶喜重來飯積香。", "宿鳥水干迎曉鬧，亂帆天際受風忙。", "青鞋踏雨尋幽徑，朱火籠紗語上方。", "珍重故人敦妙契，自憐身世兩微茫。"]'),
('db271a2c-9005-4b3f-9512-d8ec96cb7200','遊鑑湖','秦觀','宋','宋诗','song-poetry','','[]','畫舫珠簾出繚牆，天風吹到芰荷鄉。',64,'全唐诗/poet.song.59000.json','["畫舫珠簾出繚牆，天風吹到芰荷鄉。", "水光入座盃盤瑩，花氣侵人笑語香。", "翡翠側身窺淥酒，蜻蜓偷眼避紅妝。", "蒲萄力緩單衣怯，始信湖中五月凉。"]'),
('9eb2d803-888f-4b21-9200-b130385b6dc7','謁禹廟','秦觀','宋','宋诗','song-poetry','','[]','陰陰古殿注脩廊，海伯川靈儼在傍。',64,'全唐诗/poet.song.59000.json','["陰陰古殿注脩廊，海伯川靈儼在傍。", "一代衣冠埋石窆，千年風雨鎖梅梁。", "碧雲暮合稽山暗，紅芰秋開鑑水香。", "令我免魚繇帝力，恨無歌舞奠椒漿。"]'),
('434b4936-720e-44c0-8e3e-5b0f2a6f6ee8','蓬萊閣','秦觀','宋','宋诗','song-poetry','','[]','雄簷傑檻跨崢嶸，席上風雲指顧生。',64,'全唐诗/poet.song.59000.json','["雄簷傑檻跨崢嶸，席上風雲指顧生。", "千里勝形歸俎豆，七州和氣入簫笙。", "人遊晚岸朱樓遠，鳥度晴空碧嶂橫。", "今夜請看東越分，藩星應带少微明。"]'),
('7c8a8de0-cd64-4051-93ae-f50360927a19','別程公闢給事','秦觀','宋','宋诗','song-poetry','','[]','人物風流推鎮東，夕郎持節作元戎。',64,'全唐诗/poet.song.59000.json','["人物風流推鎮東，夕郎持節作元戎。", "罇前倦客劉師命，月下清歌盛小叢。", "裘弊黑貂霜正急，書傳黄犬歲將窮。", "買舟江上辭公去，迴首蓬萊夢寐中。"]'),
('be964828-c42d-42ee-9580-90fbf304c83c','中秋口號','秦觀','宋','宋诗','song-poetry','','[]','雲山簷楯接低空，公宴初開氣鬰葱。',64,'全唐诗/poet.song.59000.json','["雲山簷楯接低空，公宴初開氣鬰葱。", "照海旌幢秋色裏，激天鼓吹月明中。", "香槽旋滴珠千顆，歌扇驚圍玉一叢。", "二十四橋人望處，台星正在廣寒宮。"]'),
('1d7f07b3-bd47-4e0b-8902-18e0154bb107','客有傳朝議欲以子瞻使高麗大臣有惜其去者白罷之作詩以紀其事','秦觀','宋','宋诗','song-poetry','','[]','學士風流異域傳，幾航雲海使南天。',64,'全唐诗/poet.song.59000.json','["學士風流異域傳，幾航雲海使南天。", "不因名動五千里，豈見文高二百年。", "貢外別題求妙札，錦中翻樣織新篇。", "淹留却恨鴛行舊，不得飛觴駐蹕前。"]'),
('870c86e2-12e6-47d8-a314-085a45bca335','顯之禪老許以草庵見處作詩以約之','秦觀','宋','宋诗','song-poetry','','[]','橡葉岡頭釋馬銜，區中奇觀得窮探。',64,'全唐诗/poet.song.59000.json','["橡葉岡頭釋馬銜，區中奇觀得窮探。", "崖空飛鼠聲相應，江靜群峰影倒涵。", "居士碧雲裁秀句，道人哀玉扣清談。", "偶成二老風流事，不是三乘宿草庵。"]'),
('b627b180-af90-45e1-9936-fa5eda38b1d8','和莘老游龍洞','秦觀','宋','宋诗','song-poetry','','[]','葦蕭傳火度冥冥，乍入清都醉魄醒。',64,'全唐诗/poet.song.59000.json','["葦蕭傳火度冥冥，乍入清都醉魄醒。", "草隠月崖垂鳳尾，風生陰穴带龍腥。", "壁間泉貯千鍾碧，門外天橫數尺青。", "更欲仗笻留頃刻，却疑朝市已千齡。"]'),
('c4ceaebc-b783-41fe-88a1-6f8314c72bf1','送蔣穎叔帥熙河二首  其一','秦觀','宋','宋诗','song-poetry','','[]','侍臣不合出都門，爲有威名蕃漢尊。',64,'全唐诗/poet.song.59000.json','["侍臣不合出都門，爲有威名蕃漢尊。", "戶部左曹回妙手，匈奴右臂落清罇。", "揮毫珠璧生談笑，轉盼龍鸞在夢魂。", "瀚海一空何足道，歸來黄閤坐調元。"]'),
('a8408e3c-8392-45f9-9aa5-8bd47850c6a1','送蔣穎叔帥熙河二首  其二','秦觀','宋','宋诗','song-poetry','','[]','天馬蒲萄隔玉門，漢廷誰更勇如尊。',64,'全唐诗/poet.song.59000.json','["天馬蒲萄隔玉門，漢廷誰更勇如尊。", "行臺曉日屯千騎，祖道春風屬一罇。", "莫許留犁輕結好，便令甌脫復游魂。", "要須盡取熙河地，打鼓梁州看上元。"]'),
('69789103-ae1b-48d7-bd16-fc85af382c5c','和劉僕射感舊言懷寄蘇左丞左丞昔守南京僕射方爲幕客今同爲執政作此詩僕射詩略記其一聯云論文青眼今猶在報國丹心老更同','秦觀','宋','宋诗','song-poetry','','[]','三禁提衡系擾龍，拜無燒尾有家風。',64,'全唐诗/poet.song.59000.json','["三禁提衡系擾龍，拜無燒尾有家風。", "班行舊號青雲士，賓主今爲黄閤公。", "烱烱坐屏雲母隔，珊珊行佩水蒼同。", "自驚初到蓬萊上，便見驪珠出海宮。"]'),
('99f4510e-8c31-4bed-a9af-8dc30fe0fa97','西城宴集元祐七年三月上巳日詔賜館閣官花酒以中澣日游金明池瓊林苑又會於國夫人園會者二十有六人二首  其一','秦觀','宋','宋诗','song-poetry','','[]','春溜泱泱初滿池，晨光欲轉萬年枝。',64,'全唐诗/poet.song.59000.json','["春溜泱泱初滿池，晨光欲轉萬年枝。", "樓臺四望烟雲合，簾幕千家錦繡垂。", "風過忽聞花外笑，日長時奏水中嬉。", "太平誰謂全無象，寓在群仙把酒時。"]'),
('fc9cf785-ea4f-4af7-bc9e-1c77acd9694c','西城宴集元祐七年三月上巳日詔賜館閣官花酒以中澣日游金明池瓊林苑又會於國夫人園會者二十有六人二首  其二','秦觀','宋','宋诗','song-poetry','','[]','宜秋門外喜參尋，豪竹哀絲發妙音。',64,'全唐诗/poet.song.59000.json','["宜秋門外喜參尋，豪竹哀絲發妙音。", "金爵日邊棲壯麗，彩虹天際卧清深。", "已煩逸少書陳迹，更屬相如賦上林。", "猶恨真人足官府，不如魚鳥自飛沉。"]'),
('c47fe536-5063-4a47-88fb-291003fcc548','清明前一日李觀察席上得風字','秦觀','宋','宋诗','song-poetry','','[]','病軀寒食百無悰，偶到平陽舊第中。',64,'全唐诗/poet.song.59000.json','["病軀寒食百無悰，偶到平陽舊第中。", "池籞信爲三輔冠，杯盤真有五陵風。", "美人賦韵分春色，上客揮毫奪化工。", "白髮漸於花柳薄，但憐流水碧相通。"]'),
('e03271bc-8006-4dc3-9d38-88626129061c','次韵羅正之惠綿扇','秦觀','宋','宋诗','song-poetry','','[]','吳扇新翻製素綿，名郎持贈意俱圓。',64,'全唐诗/poet.song.59000.json','["吳扇新翻製素綿，名郎持贈意俱圓。", "有人充戶修明月，無女乘鸞向紫烟。", "供奉宜升清暑殿，動搖合作御風仙。", "誰知揮却青蠅輩，功在春蠶一覺眠。"]'),
('0fb21061-b82a-4357-a125-c5df5e0774fc','寄新息王令藏春塢','秦觀','宋','宋诗','song-poetry','','[]','令尹才高寺爲空，歲時行樂與民同。',64,'全唐诗/poet.song.59000.json','["令尹才高寺爲空，歲時行樂與民同。", "旋開小塢藏春色，更製新聲寫土風。", "客向罇前忘爾汝，路穿花去失西東。", "無言媯女今焉在，桃李相傳恨未窮。"]'),
('0823a271-dc46-481e-b712-1f5f47a73ab5','送劉承議解職歸養','秦觀','宋','宋诗','song-poetry','','[]','征馬蕭蕭柳外鳴，議郎歸養洛陽城。',64,'全唐诗/poet.song.59000.json','["征馬蕭蕭柳外鳴，議郎歸養洛陽城。", "登山尚記飛雲處，罷吏端如棄唾輕。", "爲米折腰知我拙，下車入里見君榮。", "堂前嵩少宜秋色，獻壽還應旋製聲。"]'),
('4e2c5df9-0b75-46a2-9f68-cac61e2af6a0','次韵王仲至侍郎','秦觀','宋','宋诗','song-poetry','','[]','螭口清漪下玉欄，隔花時聽鳥關關。',64,'全唐诗/poet.song.59000.json','["螭口清漪下玉欄，隔花時聽鳥關關。", "酒行寒食清明際，人在蓬壺閬苑間。", "天近省闈卿月麗，春偏戚里將星閑。", "忽思歸去焚香坐，靜取楞嚴看入還。"]'),
('b4124c21-49d1-4c3b-a8e6-145f71b52a73','慶張君俞都尉留後得子','秦觀','宋','宋诗','song-poetry','','[]','天上吹簫玉作樓，蟠桃熟後更無憂。',64,'全唐诗/poet.song.59000.json','["天上吹簫玉作樓，蟠桃熟後更無憂。", "內家報喜車凌曉，太史占祥斗掛秋。", "龍得一珠應獻佛，虎生三日便吞牛。", "魯元福祿何人似，坐見張敖數子侯。"]'),
('40ce40f1-fdfc-40f9-8e82-7e19ad8d1375','寄題趙侯澄碧軒','秦觀','宋','宋诗','song-poetry','','[]','風流公子四難并，更引清漪作小亭。',64,'全唐诗/poet.song.59000.json','["風流公子四難并，更引清漪作小亭。", "潤及玉階春漲雨，光浮藻井夜涵星。", "捲簾几硯成圖畫，倚檻鬚鬟入鏡屏。", "何日解衣容借榻，卧聽螭口瀉泠泠。"]'),
('e7391a7e-d4f0-463d-b635-1c3c1022b2fb','寄張文潜右史','秦觀','宋','宋诗','song-poetry','','[]','解手亭皋纔幾月，春風已復動林塘。',64,'全唐诗/poet.song.59000.json','["解手亭皋纔幾月，春風已復動林塘。", "稍遷右史公何泰，初閱除書國爲狂。", "日出想驚儒發冢，風行應罷女爭桑。", "東坡手種千株柳，聞說邦人比召棠。"]'),
('7d8066d5-b236-4d0e-9b0e-3c7b885a1d87','次韵裴秀才上太守向公二首  其一','秦觀','宋','宋诗','song-poetry','','[]','東風已動北風歸，寒氣侵尋自霽威。',64,'全唐诗/poet.song.59000.json','["東風已動北風歸，寒氣侵尋自霽威。", "何處管弦傳臘酒，誰家刀尺製春衣。", "使君英妙開蓮幕，別駕風流出粉闈。", "唯有廣文官獨冷，終年如坐水邊磯。"]'),
('886181ab-b533-4c75-88bd-f316562368f5','次韵裴秀才上太守向公二首  其二','秦觀','宋','宋诗','song-poetry','','[]','上客新從潁尾歸，使君高會列南威。',64,'全唐诗/poet.song.59000.json','["上客新從潁尾歸，使君高會列南威。", "風將沉燎縈歌扇，雪带梅香上舞衣。", "翻樣雲團分御帑，如椽蜜炬出宮闈。", "食前方丈羅珍怪，却訝犀燃牛渚磯。"]'),
('f6918f98-d91a-4529-9ad3-7eb93e46e8f6','次韵太守向公登樓眺望二首  其一','秦觀','宋','宋诗','song-poetry','','[]','茫茫汝水抱城根，野色偷春入燒痕。',64,'全唐诗/poet.song.59000.json','["茫茫汝水抱城根，野色偷春入燒痕。", "千點湘妃枝上淚，一聲杜宇水邊魂。", "遥憐鴻隙陂穿路，尚想元和賊負恩。", "粉堞女牆都已盡，恍如陶侃夢天門。"]'),
('cd2aa910-0156-4f34-aad1-35a119143399','次韵太守向公登樓眺望二首  其二','秦觀','宋','宋诗','song-poetry','','[]','庖烟起處認孤村，天色清寒不見痕。',64,'全唐诗/poet.song.59000.json','["庖烟起處認孤村，天色清寒不見痕。", "車輞湖邊梅濺淚，壺公祠畔月銷魂。", "封疆盡是春秋國，廟食多懷將相恩。", "試問李斯長歎後，誰牽黄犬出東門。"]'),
('5201684e-4402-47f5-980d-b8f5fda8a909','寄錢節','秦觀','宋','宋诗','song-poetry','','[]','論月柴門不浪開，命車良爲故人來。',64,'全唐诗/poet.song.59000.json','["論月柴門不浪開，命車良爲故人來。", "茫然極目春千里，尚想愁腸日九回。", "綠水池邊聊復爾，黄粱枕上信悠哉。", "何時共約參寥子，自擷青菁作飯材。"]'),
('23339821-5eda-49bc-a065-eb19a37a9092','贈劉使君景文','秦觀','宋','宋诗','song-poetry','','[]','落落衣冠八尺雄，魚符新賜大河東。',64,'全唐诗/poet.song.59000.json','["落落衣冠八尺雄，魚符新賜大河東。", "穰苴兵法申司馬，曹植詩原出國風。", "拈筆古心生篆刻，引觴俠氣上雲空。", "石渠病客君應笑，手校黄書兩鬢蓬。"]'),
('0382d12b-d057-4f1f-9e16-7febb0c41db8','答龔深之','秦觀','宋','宋诗','song-poetry','','[]','深巷茅簷日漸長，卧看花鳥競朝陽。',64,'全唐诗/poet.song.59000.json','["深巷茅簷日漸長，卧看花鳥競朝陽。", "惜無好事携罇酒，頼有鄰家振燭光。", "尚友頗存書萬卷，封侯正闕木千章。", "錯刀錦段相仍至，小子都忘進取狂。"]'),
('3225c94d-fe00-4126-8990-6fd101e271da','次韵答裴仲謨','秦觀','宋','宋诗','song-poetry','','[]','十年淮海閒居草，偶遣兒童次第成。',64,'全唐诗/poet.song.59000.json','["十年淮海閒居草，偶遣兒童次第成。", "方愧貧家矜敝帚，忽蒙鄰壁借餘明。", "文昌但願花前老，張翰何須身後名。", "移病闔門參拜阻，卧聽車馬去來聲。"]'),
('43ba02a1-ca08-4883-b6d7-5f32a7eee985','答曾存之','秦觀','宋','宋诗','song-poetry','','[]','環堵蕭然汝水隈，孤懷烱烱向誰開。',64,'全唐诗/poet.song.59000.json','["環堵蕭然汝水隈，孤懷烱烱向誰開。", "青春不覺書邊過，白髮無端鏡上來。", "祭竈請鄰聊復爾，賣刀買犢豈難哉。", "故人休說封侯事，歸釣江天有舊臺。"]'),
('e840bf4f-f534-4ade-9a97-c1f68ce1cae1','春日寓直有懷參寥','秦觀','宋','宋诗','song-poetry','','[]','觚稜金爵自岧嶢，藏室春深更寂寥。',64,'全唐诗/poet.song.59000.json','["觚稜金爵自岧嶢，藏室春深更寂寥。", "捫虱幽花欹露葉，岸巾高柳轉風條。", "文書几上鬚髯變，鞍馬塵中歲月銷。", "何日一筇江海上，與君徐步看生潮。"]'),
('d6198ba6-5046-423d-83a8-da258c6aa17e','次韵裴仲謨和何先輩二首  其一','秦觀','宋','宋诗','song-poetry','','[]','聞說何郎操行端，蕭然環堵若爲安。',64,'全唐诗/poet.song.59000.json','["聞說何郎操行端，蕭然環堵若爲安。", "鳥啼花發阻携手，水遠山高空憑欄。", "別後想多黄絹作，春來尤厭惠文彈。", "兩章讀罷知高義，貴賤交情自古難。"]'),
('fa904774-7832-4ef0-aacd-2652a94484b6','次韵裴仲謨和何先輩二首  其二','秦觀','宋','宋诗','song-poetry','','[]','汝南古郡寡參尋，兀兀長如鶴在陰。',64,'全唐诗/poet.song.59000.json','["汝南古郡寡參尋，兀兀長如鶴在陰。", "支枕星河橫醉後，入簾風絮報春深。", "青山未落詩人手，白髮誰知國士心。", "多謝名郎傳綠綺，愧無佳句比南金。"]'),
('f4d71ed4-c2b5-4042-aec5-c70bd331942e','答閻求仁謝參寥彥溫訪於墳所','秦觀','宋','宋诗','song-poetry','','[]','老濞城西木半摧，崑崙岡下路新開。',64,'全唐诗/poet.song.59000.json','["老濞城西木半摧，崑崙岡下路新開。", "故人此地銜憂去，禪客他時問疾回。", "聞爲樹風增永感，却因水鳥證西來。", "已謀寒食驅羸馬，細聽清談動玉哀。"]'),
('1ef68d36-d7e0-498f-b379-ec808c888cba','次韵劉遜父以寧齋詩二軸作以還之','秦觀','宋','宋诗','song-poetry','','[]','揚舲偶過海邊州，一見名郎破百憂。',64,'全唐诗/poet.song.59000.json','["揚舲偶過海邊州，一見名郎破百憂。", "荀氏諸龍俱俊偉，河東小鳳最風流。", "明珠白璧俱投報，細草幽花入獻酬。", "別駕舊齋何足念，文昌新府待公游。"]'),
('2ef6c798-b2bf-498e-95ad-9d07d5ad37d5','次韵何子溫','秦觀','宋','宋诗','song-poetry','','[]','一星就起海隅傍，縣弩前驅過射陽。',64,'全唐诗/poet.song.59000.json','["一星就起海隅傍，縣弩前驅過射陽。", "行見斯民無重困，坐令吾道有餘光。", "簿書不礙詩人筆，猿鳥常窺使者章。", "談笑自然群吏肅，何須酒後次公狂。"]'),
('7f45e82a-3809-4ad9-abe0-5ed2ae4cf6f3','次韵宋履中近謁大慶退食館中','秦觀','宋','宋诗','song-poetry','','[]','翠華初到殿中間，三館諸儒共一班。',64,'全唐诗/poet.song.59000.json','["翠華初到殿中間，三館諸儒共一班。", "迎謁曉廷清蹕近，退穿春仗綵旓閑。", "病來怕飲東西玉，老去慚陪大小山。", "知續春明退朝錄，借觀當奉一鴟還。"]'),
('fd4a056e-455f-43ad-8595-419626d82c54','與鄧慎思沐於啟聖遇李端叔','秦觀','宋','宋诗','song-poetry','','[]','羸兵瘦馬犯黄塵，自笑區區夢裏身。',64,'全唐诗/poet.song.59000.json','["羸兵瘦馬犯黄塵，自笑區區夢裏身。", "不是對花能伏老，自緣無酒可澆春。", "校書天祿陪群彥，晞髮陽阿遇故人。", "三百六旬如此少，更添香火坐逡巡。"]'),
('6d442fa1-0469-4096-8e2a-3e53d56b8990','和程給事贇闍黎化去之什','秦觀','宋','宋诗','song-poetry','','[]','風流雲散越王城，珍重闍黎願力成。',64,'全唐诗/poet.song.59000.json','["風流雲散越王城，珍重闍黎願力成。", "不使鄧尼驚倒化，祇教白傅歎先行。", "早因妙契窺曹洞，竟以清芬繼肇生。", "迴首中庭旌騎散，月華還可一方明。"]'),
('3b7b2e73-999b-4d1c-9234-904e35716ed1','再賦流觴亭','秦觀','宋','宋诗','song-poetry','','[]','仙山遊觀甲寰瀛，不比人間自雨亭。',64,'全唐诗/poet.song.59000.json','["仙山遊觀甲寰瀛，不比人間自雨亭。", "歌斷瑶池雲杳杳，酒行金谷水泠泠。", "珠簾卷雨驚秋近，羅襪凌波笑客醒。", "月下珮環聲更好，應容揮麈伴公聽。"]'),
('8e91c206-af21-4c39-a3e1-3dd56b1242cb','燕觴亭','秦觀','宋','宋诗','song-poetry','','[]','碧流如鏡羽觴飛，夏木陰陰五月時。',64,'全唐诗/poet.song.59000.json','["碧流如鏡羽觴飛，夏木陰陰五月時。", "清渭日長遊女困，武陵春去落花遲。", "玉笙吹罷觥籌錯，蜜炬燒殘簪珥遺。", "吳越風流公第一，未輸山簡習家池。"]'),
('b86dc82d-cf28-4537-9eb0-d2e636a014d9','會蓬萊閣','秦觀','宋','宋诗','song-poetry','','[]','冠裳蓋座灑清風，軒外時聞韵籜龍。',64,'全唐诗/poet.song.59000.json','["冠裳蓋座灑清風，軒外時聞韵籜龍。", "人面春生紅玉液，銀盤烟覆紫駝峰。", "天涵秋色山山共，樹攪鄉思葉葉重。", "便欲買船江北去，爲懷明德更從容。"]'),
('f0675979-3d0b-4b33-8f96-985a31bf81ac','次韵侍祠南郊','秦觀','宋','宋诗','song-poetry','','[]','風馬雲車下九天，郊柴初告帝心虔。',64,'全唐诗/poet.song.59000.json','["風馬雲車下九天，郊柴初告帝心虔。", "天如倚蓋臨壇上，星若連珠繞御前。", "縹緲珮環參雅奏，岧嶢樓閣抱非烟。", "侍臣舉酒欣相屬，醉看參橫左右肩。"]'),
('90bcec7d-d243-4fd9-bc7c-260896f7452c','與李端叔遊智海用前韵','秦觀','宋','宋诗','song-poetry','','[]','點目誰能化兩龍，超然想見古人風。',64,'全唐诗/poet.song.59000.json','["點目誰能化兩龍，超然想見古人風。", "紅塵稍與僧家遠，白髮偏於我輩公。", "休計浮名千載後，且欣湯餠一杯同。", "何時並築邗溝上，引水澆花半畝宮。"]'),
('5bb5ca38-5369-47cf-86e5-70d92a6d6748','和黄冕仲寄題延平泠風閣','秦觀','宋','宋诗','song-poetry','','[]','泠風三伏是清秋，雖有炎蒸不汝留。',64,'全唐诗/poet.song.59000.json','["泠風三伏是清秋，雖有炎蒸不汝留。", "滿地溪山歸藻井，有時絲管下滄洲。", "快哉便得逍遥趣，偶爾還成汗漫遊。", "誰爲發揮無妙手，賦凌楚玉有家丘。"]'),
('d1d27a53-a86c-4b9c-b601-f606224eebf8','次韵謝李安上惠茶','秦觀','宋','宋诗','song-poetry','','[]','故人早歲佩飛霞，故遣長須致茗芽。',64,'全唐诗/poet.song.59000.json','["故人早歲佩飛霞，故遣長須致茗芽。", "寒橐遽收諸品玉，午甌初試一團花。", "著書懶復追鴻漸，辨水時能效易牙。", "從此道山春困少，黄書剩校兩三家。"]'),
('ce911111-eb03-4f28-adb6-21c5f9f7fdc3','次韵范純夫戲答李方叔饋笋兼簡鄧慎思','秦觀','宋','宋诗','song-poetry','','[]','楚山冬笋斸寒空，北客長嗟食不重。',64,'全唐诗/poet.song.59000.json','["楚山冬笋斸寒空，北客長嗟食不重。", "秀色可憐刀切玉，清香不斷鼎烹龍。", "論羹未愧蓴千里，入貢當隨傳一封。", "薄祿養親甘旨少，滿包時頼故人供。"]'),
('6285ba92-3d55-44b5-8e62-4779b7a57d0a','寄少儀弟','秦觀','宋','宋诗','song-poetry','','[]','一隔音塵月屢遷，忽收來問涕潸然。',64,'全唐诗/poet.song.59000.json','["一隔音塵月屢遷，忽收來問涕潸然。", "栖遲冊府吾如昨，流落江村汝可憐。", "夢裏漫成池草句，愁來空誦棣華篇。", "卑飛暫爾無多恨，會有高風送上天。"]'),
('20f8b06a-912c-4033-b286-ee2ba8303ba9','九月八日夜大風雨寄王定國','秦觀','宋','宋诗','song-poetry','','[]','長年身外事都捐，節物驚心一悵然。',64,'全唐诗/poet.song.59000.json','["長年身外事都捐，節物驚心一悵然。", "正是山川秋入夢，可堪風雨夜連天。", "桐梢摵摵增悽斷，燈燼飛飛落小圓。", "湔洗此情須痛飲，明朝試就酒中仙。"]'),
('fd37864e-0808-4725-84c7-92702fda4fc3','林次中奉使契丹劉仲平出倅鄆州同舍十有六人飲餞于丁氏園次少蓬韵二首 送次中諫議','秦觀','宋','宋诗','song-poetry','','[]','鮮車百乘使龍庭，路指全燕古北平。',64,'全唐诗/poet.song.59000.json','["鮮車百乘使龍庭，路指全燕古北平。", "祖帳列仙修故事，行臺諸部奏新聲。", "留犂撓酒知胡意，尺牘移書示漢情。", "納節便應歸法從，中途已報制書行。"]'),
('490819fd-6ded-4f14-86fe-63358ce2f6b1','林次中奉使契丹劉仲平出倅鄆州同舍十有六人飲餞于丁氏園次少蓬韵二首 送平仲學士','秦觀','宋','宋诗','song-poetry','','[]','須句別駕偉儀刑，陵谷初無見坦平。',64,'全唐诗/poet.song.59000.json','["須句別駕偉儀刑，陵谷初無見坦平。", "七子建安推世藝，五經中祕擅家聲。", "南宮參掇端如夢，東觀分携空復情。", "莫愛谿堂好風月，早來龍尾道前行。"]'),
('6c75262e-7892-4314-aef9-e4eda6a5d949','寄孫傳師著作','秦觀','宋','宋诗','song-poetry','','[]','上林池籞富春風，十里宮青錯御紅。',32,'全唐诗/poet.song.59000.json','["上林池籞富春風，十里宮青錯御紅。", "應與少年修故事，誤隨遊轂柳花中。"]'),
('bb439e1e-8327-43f0-89a5-b009d3b1b060','泗州東城晚望','秦觀','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5c71\u6c34", "\u5199\u666f"]','渺渺孤城白水環，舳艫人語夕霏間。',32,'全唐诗/poet.song.59000.json','["渺渺孤城白水環，舳艫人語夕霏間。", "林梢一抹青如畫，應是淮流轉處山。"]'),
('c487acd8-2876-4915-b62c-b9b1cb75e7cb','戲雲龍山人二絕  其一','秦觀','宋','宋诗','song-poetry','','[]','芳草未應羞鵯鵊，潜鱗終是畏提壺。',32,'全唐诗/poet.song.59000.json','["芳草未應羞鵯鵊，潜鱗終是畏提壺。", "蔡經背上痕猶在，更念麻姑指爪無。"]'),
('eba853e4-0a7e-44c9-a46c-41864a26540d','戲雲龍山人二絕  其二','秦觀','宋','宋诗','song-poetry','','[]','選勝只携長脛鶴，入廛還駕短轅車。',32,'全唐诗/poet.song.59000.json','["選勝只携長脛鶴，入廛還駕短轅車。", "時人若問虛玄事，笑答無過李老書。"]'),
('2a5b2071-70f3-4313-a9dc-89890de22baa','圓通院白衣閣  其一','秦觀','宋','宋诗','song-poetry','','[]','無邊剎境一毫端，同住澄清覺海間。',32,'全唐诗/poet.song.59000.json','["無邊剎境一毫端，同住澄清覺海間。", "還似此花并此葉，壞空成住未曾閑。"]'),
('ca7275ed-3170-4ca6-8ef8-cfcf7feb0806','圓通院白衣閣  其二','秦觀','宋','宋诗','song-poetry','','[]','一根反本六根同，古佛傳家有此風。',32,'全唐诗/poet.song.59000.json','["一根反本六根同，古佛傳家有此風。", "滿目紅蕖參翠蓋，不唯門裏獲圓通。"]'),
('f31a959f-c406-4ce2-bcf4-3ee855aba228','照閣','秦觀','宋','宋诗','song-poetry','','[]','彌猴鏡裏三身現，龍女珠中萬象開。',32,'全唐诗/poet.song.59000.json','["彌猴鏡裏三身現，龍女珠中萬象開。", "未若此軒人散後，水光清泛月華來。"]'),
('37ba0fd8-abee-439e-9da3-b04ffece5f02','睡足寮寄震鼎二弟','秦觀','宋','宋诗','song-poetry','','[]','與物無營但欲眠，客來從笑腹便便。',32,'全唐诗/poet.song.59000.json','["與物無營但欲眠，客來從笑腹便便。", "秋生淮海凉如水，得句還應夢阿連。"]'),
('ee254c66-738f-48b2-8c96-bfe004923dc6','次韵參寥見別','秦觀','宋','宋诗','song-poetry','','[]','爐香冉冉紆寒穗，篝火熒熒擢夜芒。',32,'全唐诗/poet.song.59000.json','["爐香冉冉紆寒穗，篝火熒熒擢夜芒。", "預想江天回首處，雪風橫急雁聲長。"]'),
('92461265-0e9d-410f-9717-7df8224a9fa2','與倪老伯輝九曲池有懷元龍參寥','秦觀','宋','宋诗','song-poetry','','[]','雲月娟娟淮海秋，隋家池上共浮游。',32,'全唐诗/poet.song.59000.json','["雲月娟娟淮海秋，隋家池上共浮游。", "可憐一段風流事，特欠支郎與子猷。"]'),
('44008171-138b-4881-bbe6-6308d6fe1bd8','春日五首  其一','秦觀','宋','宋诗','song-poetry','','[]','幅巾投曉入西園，春動林塘物物鮮。',32,'全唐诗/poet.song.59000.json','["幅巾投曉入西園，春動林塘物物鮮。", "却憩小庭纔日出，海棠花發麝香眠。"]'),
('b7a20e77-258c-443e-aba2-36b227a26dcc','春日五首  其二','秦觀','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u5199\u666f", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u96e8"]','一夕輕雷落萬絲，霽光浮瓦碧差差。',32,'全唐诗/poet.song.59000.json','["一夕輕雷落萬絲，霽光浮瓦碧差差。", "有情芍藥含春淚，無力薔薇卧曉枝。"]'),
('11033661-21ac-48d6-b008-fdde49321352','春日五首  其三','秦觀','宋','宋诗','song-poetry','','[]','裌衣新著倦琴書，散策池塘返照初。',32,'全唐诗/poet.song.59000.json','["裌衣新著倦琴書，散策池塘返照初。", "翠碧黄鸝相續去，荇絲深處見游魚。"]'),
('331eec3b-4fef-40c9-ac46-bb96aa6ebe39','春日五首  其四','秦觀','宋','宋诗','song-poetry','','[]','春禽葉底引圓吭，臨罷黄庭日正長。',32,'全唐诗/poet.song.59000.json','["春禽葉底引圓吭，臨罷黄庭日正長。", "滿院柳花寒食後，旋鑽新火爇爐香。"]'),
('cc246661-9b23-4d7c-b0e1-1af6f7a8f587','春日五首  其五','秦觀','宋','宋诗','song-poetry','','[]','金屋舊題煩乙子，蜜脾新採頼蜂臣。',32,'全唐诗/poet.song.59000.json','["金屋舊題煩乙子，蜜脾新採頼蜂臣。", "蜻蜓蛺蝶無情思，隨例顛忙過一春。"]'),
('4bb3fe0a-60c7-4766-aada-bb4068b6d40c','秋日三首  其一','秦觀','宋','宋诗','song-poetry','','[]','霜落邗溝積水清，寒星無數傍船明。',32,'全唐诗/poet.song.59000.json','["霜落邗溝積水清，寒星無數傍船明。", "菰蒲深處疑無地，忽有人家笑語聲。"]'),
('b4fd5373-9d2f-4cf0-8396-43c3036a09fe','秋日三首  其二','秦觀','宋','宋诗','song-poetry','','[]','月團新碾瀹花瓷，飲罷呼兒課楚詞。',32,'全唐诗/poet.song.59000.json','["月團新碾瀹花瓷，飲罷呼兒課楚詞。", "風定小軒無落葉，青蟲相對吐秋絲。"]'),
('829c8a70-9fc7-4ae8-8277-b3a4d7259b79','秋日三首  其三','秦觀','宋','宋诗','song-poetry','','[]','連卷雌蜺掛西樓，逐雨追晴意未休。',32,'全唐诗/poet.song.59000.json','["連卷雌蜺掛西樓，逐雨追晴意未休。", "安得萬妝相向舞，酒酣聊把作纏頭。"]'),
('ae58e81e-6805-4f76-9862-b0c3b5cf2244','次韵子由召伯埭見別三首  其一','秦觀','宋','宋诗','song-poetry','','[]','孤蓬短榜泝河流，無頼寒侵紫綺裘。',32,'全唐诗/poet.song.59000.json','["孤蓬短榜泝河流，無頼寒侵紫綺裘。", "召伯埭南春欲盡，爲公重賦畔牢愁。"]'),
('cde4b16c-1a99-4429-aec3-ee4fd1352dd4','次韵子由召伯埭見別三首  其二','秦觀','宋','宋诗','song-poetry','','[]','青熒燈火照深更，逐客舟航冷似冰。',32,'全唐诗/poet.song.59000.json','["青熒燈火照深更，逐客舟航冷似冰。", "到處故應山作主，隨方還有月爲朋。"]'),
('34c8b992-72df-4928-937a-27cf67bcaeb2','次韵子由召伯埭見別三首  其三','秦觀','宋','宋诗','song-poetry','','[]','冠蓋紛紛不我謀，掩關聊與古人遊。',32,'全唐诗/poet.song.59000.json','["冠蓋紛紛不我謀，掩關聊與古人遊。", "會須匹馬淮西去，雲巘風溪遂所求。"]'),
('c5feac2c-a644-43a2-8797-ba0b43c31f34','還自廣陵四首  其一','秦觀','宋','宋诗','song-poetry','','[]','薄茶便當烏程酒，短艇聊充下澤車。',32,'全唐诗/poet.song.59000.json','["薄茶便當烏程酒，短艇聊充下澤車。", "墳墓去家無百里，往來仍不廢觀書。"]'),
('4711f370-04a8-4d06-bef9-cd8a3fc8ef68','還自廣陵四首  其二','秦觀','宋','宋诗','song-poetry','','[]','南北悠悠三十年，謝公遺埭故依然。',32,'全唐诗/poet.song.59000.json','["南北悠悠三十年，謝公遺埭故依然。", "欲論舊事無人共，卧聽鍾魚古寺邊。"]'),
