('2f17deed-ea36-4148-a524-0756ea36226c','題務中壁','秦觀','宋','宋诗','song-poetry','','[]','醡頭春酒響潺潺，壚下黄翁寢正安。',32,'全唐诗/poet.song.59000.json','["醡頭春酒響潺潺，壚下黄翁寢正安。", "夢入平陽舊池館，隔花螭口吐清寒。"]'),
('9b9b3c56-68c3-43bc-9dd8-229e314787b6','題法海平闍黎','秦觀','宋','宋诗','song-poetry','','[]','寒食山州百色喧，春風花雨暗川原。',32,'全唐诗/poet.song.59000.json','["寒食山州百色喧，春風花雨暗川原。", "因循移病依香火，寫得彌陀七萬言。"]'),
('d137f048-cb8d-46fc-8c56-68fbb34a1327','留別平闍黎','秦觀','宋','宋诗','song-poetry','','[]','緣盡山城且不歸，此生相見了無期。',32,'全唐诗/poet.song.59000.json','["緣盡山城且不歸，此生相見了無期。", "保持異日蓮花上，重說如今結社時。"]'),
('b3f93472-91fc-4d26-a628-877ff74d6bdc','大行太皇太后挽詞二首  其一','秦觀','宋','宋诗','song-poetry','','[]','東朝制詔九年稱，烈武功高後世興。',64,'全唐诗/poet.song.59000.json','["東朝制詔九年稱，烈武功高後世興。", "坐舉不周天柱正，親扶暘谷日車升。", "班行尚想延和殿，羽衛俄趨永厚陵。", "洛水嵩峰霄漢外，百官西望涕難勝。"]'),
('70ca9cdd-7ddd-4b8c-8ecf-153ca05287c5','大行太皇太后挽詞二首  其二','秦觀','宋','宋诗','song-poetry','','[]','保扶明主自春宮，萬國昇平出至公。',64,'全唐诗/poet.song.59000.json','["保扶明主自春宮，萬國昇平出至公。", "顧命一時聊共政，思齊千古遂同風。", "外家恩數仍長信，原廟蒸嘗即治隆。", "欲敘聖功歌挽者，乾坤難入畫圖中。"]'),
('06d29a8f-14e4-43c7-acca-14ae49ca0ac4','韓樞密夫人挽詞二首  其一','秦觀','宋','宋诗','song-poetry','','[]','奕葉貂蟬後，宗姻樂靜間。',48,'全唐诗/poet.song.59000.json','["奕葉貂蟬後，宗姻樂靜間。", "從夫登兩地，看子入三山。", "舊像瞻榆闕，遺音想佩環。", "百年川閱水，不復更西還。"]'),
('0b906721-0efa-44f5-9ad0-9e46f142673b','韓樞密夫人挽詞二首  其二','秦觀','宋','宋诗','song-poetry','','[]','天上開華屋，丘山忽返真。',48,'全唐诗/poet.song.59000.json','["天上開華屋，丘山忽返真。", "內人歸賵盛，挽者轉哀新。", "鸞詔初乾墨，魚軒已暗塵。", "藹然多德善，論次有蒼珉。"]'),
('7de2f126-6f39-4c16-8604-fc3b95eb7ac4','俞公達待制挽詞二首  其一','秦觀','宋','宋诗','song-poetry','','[]','詞場英妙氣如虹，出入青雲見事功。',64,'全唐诗/poet.song.59000.json','["詞場英妙氣如虹，出入青雲見事功。", "流馬木牛通蜀漕，葛巾羽扇破渠戎。", "風生使者旌旄上，春在將軍俎豆中。", "詔墨未乾人奄忽，傷心江漢日傾東。"]'),
('4ac57159-ed23-4f4e-9468-733d55c45c8c','俞公達待制挽詞二首  其二','秦觀','宋','宋诗','song-poetry','','[]','一麾出守著威名，凶訃西來上爲驚。',64,'全唐诗/poet.song.59000.json','["一麾出守著威名，凶訃西來上爲驚。", "玉帳笑談成昨夢，錦囊書札見平生。", "衣冠漸散紅蓮府，鎧馬還歸細柳營。", "可道風流回首盡，芝蘭庭下粲朝榮。"]'),
('405f5d1c-ba67-4b9e-8bfc-54fe67da0df2','陳承事挽詞','秦觀','宋','宋诗','song-poetry','','[]','明時就養寄淮壖，忽歎艅艎以柩旋。',64,'全唐诗/poet.song.59000.json','["明時就養寄淮壖，忽歎艅艎以柩旋。", "八尺衣冠成繪事，百年風誼列幽鎸。", "銘旌暮暗黄梅雨，鄉路秋橫碧玉天。", "遥想葬期豪傑會，高車連軫駐新阡。"]'),
('799a9537-f829-4c66-8ad0-a35556bda751','永壽縣君挽詞二首  其一','秦觀','宋','宋诗','song-poetry','','[]','廷尉蒙恩後，蘭臺就養初。',48,'全唐诗/poet.song.59000.json','["廷尉蒙恩後，蘭臺就養初。", "大椿宜更壽，流水遽焉如。", "鸞錦封花誥，蛛絲網板輿。", "百年誰考德，琬琰在幽墟。"]'),
('54ae2e6e-031a-41ef-8c56-9b1d5aa1cb01','永壽縣君挽詞二首  其二','秦觀','宋','宋诗','song-poetry','','[]','明世辭隆養，哀榮道路傳。',48,'全唐诗/poet.song.59000.json','["明世辭隆養，哀榮道路傳。", "賻喪從上宰，歌挽出群仙。", "素幔傷秋泛，青缸慘夜船。", "玉峰歸葬處，木拱雁連天。"]'),
('a2d66fef-3a9f-4d30-9a4d-86f07dd830ad','曾子固哀詞','秦觀','宋','宋诗','song-poetry','','[]','皇受命而熙洽兮，實千祀而一時。',358,'全唐诗/poet.song.59000.json','["皇受命而熙洽兮，實千祀而一時。", "協氣鬰而四塞兮，與盛德其俱升。", "麟鳳出而旁午兮，猶氤氳而扶輿。", "篤生我公兮，以文章爲世師。", "公神禹之苗裔兮，肇子爵而鄫封。", "逮去邑而爲氏兮，季葉汩其南征。", "祖騫翔而績著兮，考踡跼而文鳴。", "公既生而多艱兮，踵祖武而好修。", "既輕車又良御兮，遂大放乎厥詞。", "發天人之奧秘兮，約六藝而成章。", "元氣含而未泄兮，洞芒芴而窅冥。", "挽天河而一瀉兮，物應手而華昌。", "揖揚馬使先路兮，咸告公曰不敢。", "彼崔蔡之紛紛兮，孰云窺其藩翰。", "辰來遲而去速兮，固前修以跋疐。", "方盤礴而上征兮，遽相羊而補外。", "皇揆公之忠誠兮，即商墟而賜環。", "紬史諜乎東觀兮，裁誥命乎西垣。", "典章絕而復作兮，世爭睹而快先。", "正經緯乎終古兮，配維斗而昭然。", "變化詭而難常兮，雖司命其或昧。", "忽遭艱而去國兮，遂銜哀而即世。", "述作紛其具存兮，悵爽靈之焉詣。", "信百年不斯須兮，遒電滅而焱逝。"]'),
('78684496-5c54-44fb-b310-24b06ab68fd4','蔡氏哀詞','秦觀','宋','宋诗','song-poetry','','[]','惟夫人之高誼兮，真一時之女英。',363,'全唐诗/poet.song.59000.json','["惟夫人之高誼兮，真一時之女英。", "既富有此好德兮，又申之以令儀。", "带幽蕙之縹緲兮，佩明月之陸離。", "人自操舍之不一兮，雅獨取善以自持。", "何報施之或忒兮，罹禍艱於不虞。", "顔色炫而未暮兮，所天忽以殞俎。", "痛平素之偕處兮，忍此奄奄而嫠居。", "瀝哀血以自誓兮，甘餌毒而捐軀。", "佩珠玉以死真兮，固衆女之所嗤。", "曷卓越以不顧兮，棄性命其如遺。", "美不可强有兮，信天資之所開。", "要反心以內省兮，豈或售乎人知。", "嗟三晨之未浹兮，遂俱遊而莫留。", "死者有知兮，羌魂魄以並遊。", "日黄昏而不見兮，虛室窈其無人。", "惟哀風以歸來兮，動素幔之襜襜。", "何平生之款密兮，遽音聲之不可尋。", "儼遺跡以在目兮，紛百憂而攻心。", "豈至理不吾喻兮，如意厚而悲深。", "撫雙櫬以增慟兮，涕清血而灑襟。", "已矣哉，人生有死兮，自前古而既然。", "精魄忽其不駐兮，惟修名之可延。", "忍錄錄以寓世兮，信烈者之所羞。", "儻佳志之獲申兮，雖奄忽其焉悼。"]'),
('d7ed3e29-6af9-44fe-851a-ec1b1f5d8fb3','時宣義挽詞','秦觀','宋','宋诗','song-poetry','','[]','奮發多難裏，哀榮後夜中。',48,'全唐诗/poet.song.59000.json','["奮發多難裏，哀榮後夜中。", "妙年推正行，末路見陰功。", "風雨雙龍合，山川吊鶴空。", "懸知青史上，又載一于公。"]'),
('0539534f-e256-4265-b882-c0368e39efc5','中書侍郎挽詞二首  其一','秦觀','宋','宋诗','song-poetry','','[]','崛起商巖後，清忠士論歸。',48,'全唐诗/poet.song.59000.json','["崛起商巖後，清忠士論歸。", "法知商鞅弊，議折董宏非。", "遷謫生華髮，騫騰上紫微。", "又騎箕尾去，朝野涕空揮。"]'),
('b375e007-0dcd-45d4-a1fd-31090cc4f93f','中書侍郎挽詞二首  其二','秦觀','宋','宋诗','song-poetry','','[]','守道無夷險，如公實寡仇。',48,'全唐诗/poet.song.59000.json','["守道無夷險，如公實寡仇。", "望從烏府重，官到鳳池休。", "二品追褒峻，千金賻恤優。", "搢紳終有恨，王駿不封侯。"]'),
('479377dd-4e50-4fbc-a008-290568636a30','呂與叔挽章四首  其一','秦觀','宋','宋诗','song-poetry','','[]','舉舉西州士，來爲邦國華。',48,'全唐诗/poet.song.59000.json','["舉舉西州士，來爲邦國華。", "藝文尤爾雅，經術自名家。", "正有高山仰，俄成逝水嗟。", "賢人各有數，不獨歲龍蛇。"]'),
('ac35fad6-6cd2-47e0-8083-6fcc7529cae5','呂與叔挽章四首  其二','秦觀','宋','宋诗','song-poetry','','[]','數日音容隔，人琴遂已虛。',48,'全唐诗/poet.song.59000.json','["數日音容隔，人琴遂已虛。", "門生應有謚，國史可無書。", "舊室懸蛛網，遺編走蠹魚。", "定無封禪草，平日笑相如。"]'),
('7c4a98d6-1aa4-4b26-b4f7-5a152725b5ca','呂與叔挽章四首  其三','秦觀','宋','宋诗','song-poetry','','[]','追惟獻歲發春間，和我新詩憶故山。',32,'全唐诗/poet.song.59000.json','["追惟獻歲發春間，和我新詩憶故山。", "今日始知詩是讖，魂兮應已度函關。"]'),
('aaf6f373-4db4-40f5-a1a8-829588cf597a','呂與叔挽章四首  其四','秦觀','宋','宋诗','song-poetry','','[]','風流雲散了無餘，天祿空存舊直廬。',32,'全唐诗/poet.song.59000.json','["風流雲散了無餘，天祿空存舊直廬。", "小吏獨來開鎖鑰，案頭塵滿校殘書。"]'),
('3941083c-5270-4c43-a7ed-6b261ec1116d','東平夫人挽章','秦觀','宋','宋诗','song-poetry','','[]','相閥風流盛，王家地勢雄。',48,'全唐诗/poet.song.59000.json','["相閥風流盛，王家地勢雄。", "室中蘭作佩，庭下玉成叢。", "啼鳥悲春檻，荒原入夜宮。", "遺芳得鴻筆，論次詔無窮。"]'),
('8b2dba23-98c8-427d-9d34-70b25eb65442','開府李公挽章  其一','秦觀','宋','宋诗','song-poetry','','[]','報國封章數，論交意氣真。',48,'全唐诗/poet.song.59000.json','["報國封章數，論交意氣真。", "先朝貴公子，當代老成人。", "月動融尊酒，花催鄭驛賓。", "誰知古原上，馬鬣一朝新。"]'),
('bc4f1d74-2603-41a6-b741-90375304e83d','開府李公挽章  其二','秦觀','宋','宋诗','song-poetry','','[]','戚里薨耆舊，哀榮世未如。',48,'全唐诗/poet.song.59000.json','["戚里薨耆舊，哀榮世未如。", "襚加三事衮，奠致兩宮輿。", "鹵簿前衢隘，歌鍾後院虛。", "英風知不墜，芝玉茂庭除。"]'),
('be8c561b-4d8b-4f2c-a909-790ec736dbe9','孫莘老挽詞四首  其一','秦觀','宋','宋诗','song-poetry','','[]','同功一體盡調元，獨抱沉痾反故園。',32,'全唐诗/poet.song.59000.json','["同功一體盡調元，獨抱沉痾反故園。", "壺遂暮年非不遇，人生到此可忘言。"]'),
('b937bf5e-05c2-4f7e-a0f1-02b1f12c3ca5','孫莘老挽詞四首  其二','秦觀','宋','宋诗','song-poetry','','[]','青春芸閣妙文詞，進讀金華鬢若絲。',32,'全唐诗/poet.song.59000.json','["青春芸閣妙文詞，進讀金華鬢若絲。", "轉守七州多異政，奉常處處有房祠。"]'),
('a8485bbc-63c2-4f8f-990a-e38010dfa566','孫莘老挽詞四首  其三','秦觀','宋','宋诗','song-poetry','','[]','月旦嘗居第一評，立朝風采照公卿。',32,'全唐诗/poet.song.59000.json','["月旦嘗居第一評，立朝風采照公卿。", "門生故吏知多少，盡向碑陰刻姓名。"]'),
('865d2498-6213-48ef-a189-e272ffa13c41','孫莘老挽詞四首  其四','秦觀','宋','宋诗','song-poetry','','[]','華屋丘山可柰何，百年光景一投梭。',32,'全唐诗/poet.song.59000.json','["華屋丘山可柰何，百年光景一投梭。", "故人唯有羊曇在，慟哭西州不忍歌。"]'),
('96f6b0c5-920e-44e7-8d55-2c5a69efbb61','陳用之學士挽詞  其一','秦觀','宋','宋诗','song-poetry','','[]','禮經三百鬢毛班，追述先儒伯仲間。',32,'全唐诗/poet.song.59000.json','["禮經三百鬢毛班，追述先儒伯仲間。", "誰請尚書重給札，盡抄遺稿入名山。"]'),
('dc3afd1d-0d64-45e9-88a7-2f0bcdb55ae2','陳用之學士挽詞  其二','秦觀','宋','宋诗','song-poetry','','[]','岧嶢芸閣上參天，直舍相依欲二年。',32,'全唐诗/poet.song.59000.json','["岧嶢芸閣上參天，直舍相依欲二年。", "願寫此情歌挽者，淚霑毫素不成篇。"]'),
('a1591f13-0eaa-4681-9265-aff25cd04daa','陳用之學士挽詞  其三','秦觀','宋','宋诗','song-poetry','','[]','雲臺觀者候昏明，奎壁躔中失二星。',32,'全唐诗/poet.song.59000.json','["雲臺觀者候昏明，奎壁躔中失二星。", "上界真人重離別，陰風一夜攪青冥。"]'),
('8aa18716-49a9-49b4-b4bb-6e7ae1700211','陳用之學士挽詞  其四','秦觀','宋','宋诗','song-poetry','','[]','牢落公車待詔時，白頭掌故更棲棲。',32,'全唐诗/poet.song.59000.json','["牢落公車待詔時，白頭掌故更棲棲。", "一生勤苦成何事，只得銘旌數尺題。"]'),
('ca07a79b-fede-4308-8986-a4cd63c8a1c7','滕達道挽詞  其一','秦觀','宋','宋诗','song-poetry','','[]','早歲峨冠侍冕旒，白頭淹卹外諸侯。',64,'全唐诗/poet.song.59000.json','["早歲峨冠侍冕旒，白頭淹卹外諸侯。", "篋中尚有東封草，塞下曾無北顧憂。", "心繫漢廷長入夢，氣吞胡虜不防秋。", "經綸未了埋黄土，精爽還應屬斗牛。"]'),
('62024ab0-39fa-4119-b95b-f694651ae113','滕達道挽詞  其二','秦觀','宋','宋诗','song-poetry','','[]','江南江北奉周旋，合散如雲二十年。',64,'全唐诗/poet.song.59000.json','["江南江北奉周旋，合散如雲二十年。", "春郡勝遊花蔽馬，夜山清話雨連天。", "共驚萬里長城壞，獨把千金寶劍懸。", "平日書題多散亂，呼兒尋聚一潸然。"]'),
('1202fcd2-d159-4d5c-9e56-2930c6ba4688','自作挽詞','秦觀','宋','宋诗','song-poetry','','[]','嬰釁徙窮荒，茹哀與世辭。',180,'全唐诗/poet.song.59000.json','["嬰釁徙窮荒，茹哀與世辭。", "官來錄我橐，吏來驗我屍。", "藤束木皮棺，藁葬路傍陂。", "家鄉在萬里，妻子天一涯。", "孤魂不敢歸，惴惴猶在茲。", "昔忝柱下史，通籍黄金閨。", "奇禍一朝作，飄零至於斯。", "弱孤未堪事，返骨定何時。", "脩途繚山海，豈免從闍維。", "荼毒復荼毒，彼蒼那得知。", "歲晚瘴江急，鳥獸鳴聲悲。", "空濛寒雨零，慘淡陰風吹。", "殯宮生蒼蘚，紙錢掛空枝。", "無人設薄奠，誰與飯黄緇。", "亦無挽歌者，空有挽歌辭。"]'),
('44cf7085-37e4-4265-ab60-b5b3226081df','進南郊慶成詩','秦觀','宋','宋诗','song-poetry','','[]','於赫龍飛後，中區八月秋。',240,'全唐诗/poet.song.59000.json','["於赫龍飛後，中區八月秋。", "合嚴天地祀，遠繼祖宗休。", "熙事將興舉，彝章預講諏。", "紛然曲臺議，斷自太任謀。", "宗伯方承命，元龜遂告猷。", "三錢封內帑，五瑞輯諸侯。", "路寢前齋玉，清宮復射牛。", "長迎南至日，圓即自然丘。", "扈蹕三千劍，干霄十二樓。", "鈎陳嚴御座，太一奉宸遊。", "好雨虛聞畢，生陽不待鄒。", "浮雲依斗散，華月亙天流。", "霄被黄裀却，霜空曲蓋收。", "堪輿同顧饗，河嶽盡懷柔。", "麾日初鳴仗，旂風不滿旒。", "回鑾龍入馭，傳詔鶴爲郵。", "崇慶天雖老，華胥聖不憂。", "衣冠千玉簡，宇宙一金甌。", "可但豐年屢，當知世德求。", "慚無班馬手，作頌配商周。"]'),
('214064c2-c8f1-4d12-9449-1894ece0f68d','幽眠','秦觀','宋','宋诗','song-poetry','','[]','幽眠起常晚，冬晷復不長。',144,'全唐诗/poet.song.59000.json','["幽眠起常晚，冬晷復不長。", "中間數十刻，倏如驚燕翔。", "晨餐粗云畢，申鼓鳴相望。", "忽忽竟何就，念之動中腸。", "天地一逆旅，死生猶轉商。", "暫來旋云去，遲速乃所常。", "較計亦何補，徒然非慨慷。", "不如聽兩行，一槩付酒觴。", "北風吹老槐，白日轉紙窗。", "布衾一覺睡，身世成渺茫。", "宿莽冬不衰，蘭茞幽更芳。", "無庸傷局促，速此鬢髮霜。"]'),
('4a879ccd-d740-47cf-8a27-a3ca21630201','越王','秦觀','宋','宋诗','song-poetry','','[]','越王念吳役，寢興常不安。',120,'全唐诗/poet.song.59000.json','["越王念吳役，寢興常不安。", "有臣曰種蠡，實與同難艱。", "終酬會稽恥，列國不敢干。", "智者見未兆，愚夫暗前觀。", "范公拂衣去，扁舟五湖間。", "清輝照四海，秋月耿雲端。", "種也竟不悟，處之若無難。", "屬鏤一朝至，身與名俱殘。", "兔走獵狗悲，鳥盡良弓閑。", "自古身不退，多爲世所歎。"]'),
('606520ef-9d84-48c9-ba8f-491acd5e89c1','隕星石','秦觀','宋','宋诗','song-poetry','','[]','蕭然古丘上，有石傳隕星。',96,'全唐诗/poet.song.59000.json','["蕭然古丘上，有石傳隕星。", "胡爲霄漢間，墜地成此精。", "雖有堅白姿，塊然誰汝靈。", "犬眠牛礪角，終日蒙羶腥。", "疇昔同列者，到今司賞刑。", "森然事芒角，次第羅空青。", "俛仰一氣中，萬化無常經。", "安知風雲會，不復歸青冥。"]'),
('c4edd0ee-74bd-470e-88f0-ebf0221555a6','山陽阻淺','秦觀','宋','宋诗','song-poetry','','[]','一日行一尺，十日行一丈。',72,'全唐诗/poet.song.59000.json','["一日行一尺，十日行一丈。", "豈不歎淹留，所幸無波浪。", "悲風動深夜，原野眇林爽。", "青天行蟾蜍，枯水轉魍魎。", "此時蓬茅下，去心劇於癢。", "棄置勿復論，通塞如反掌。"]'),
('2245b690-886c-426b-b707-3299e75fc1ff','次韵參寥莘老','秦觀','宋','宋诗','song-poetry','','[]','迅風薄高林，萬象號虎豹。',96,'全唐诗/poet.song.59000.json','["迅風薄高林，萬象號虎豹。", "紛披枳與棘，爾復鼓狂鬧。", "我垣既已頹，我棟又以撓。", "豈無一木枝，橫力難與較。", "黎明忽自罷，晴日射魚罩。", "死水失狂瀾，衰木回故貌。", "勞生真夢事，往趨如睡覺。", "炊黍焚黄鶉，吾其理歸棹。"]'),
('b14b733b-1d02-403c-8146-f1934574430d','送洪景之循州參軍','秦觀','宋','宋诗','song-poetry','','[]','寒梅不自重，輒花桃李先。',120,'全唐诗/poet.song.59000.json','["寒梅不自重，輒花桃李先。", "矯枉有佳菊，最後衆芳妍。", "各因一時美，難以相嗤憐。", "物理固若是，士林亦宜然。", "夫子南國俊，聲猷推妙年。", "數奇晚方偶，參軍古龍川。", "龍川雖云遠，風物號清鮮。", "羅浮不相下，頡頏巉荒天。", "雲鬢二三子，聊足奉周旋。", "行矣試老拳，歸歟遠翔鶱。"]'),
('0e273614-3803-408c-825b-46e1d1b16379','茶','秦觀','宋','宋诗','song-poetry','','[]','茶實嘉木英，其香乃天育。',96,'全唐诗/poet.song.59000.json','["茶實嘉木英，其香乃天育。", "芳不愧杜蘅，清堪掩椒菊。", "上客集堂葵，圓月探奩盝。", "玉鼎注漫流，金碾響丈竹。", "侵尋發美鬯，猗狔生乳粟。", "經時不銷歇，衣袂带紛鬰。", "幸蒙巾笥藏，苦厭龍蘭續。", "願君斥異類，使我全芬馥。"]'),
('d618c1d2-5fb9-434f-8fda-dbd933859a68','茶臼','秦觀','宋','宋诗','song-poetry','','[]','幽人躭茗飲，刳木事擣撞。',96,'全唐诗/poet.song.59000.json','["幽人躭茗飲，刳木事擣撞。", "巧制合臼形，雅音侔柷椌。", "靈室困亭午，松然明鼎窗。", "呼奴碎圓月，搔首聞錚鏦。", "茶仙頼君得，睡魔資爾降。", "所宜玉兔擣，不必力士扛。", "願偕黄金碾，自比白玉缸。", "彼美制作妙，俗物難與雙。"]'),
('fcfcbd24-835a-443d-8b3e-e01fca489a5f','石魚','秦觀','宋','宋诗','song-poetry','','[]','佛宮琢琳瑯，懸魚警羣聰。',96,'全唐诗/poet.song.59000.json','["佛宮琢琳瑯，懸魚警羣聰。", "緩扣集方袍，急拊趨百工。", "雖無筍虛器，自協徵與宮。", "犂然當人心，邈有炎氏風。", "山泉自疏數，珮玉相玲瓏。", "朝昏間鍾鼓，清響傳無窮。", "惟有寶陀山，於音獲圓通。", "一聞如得解，石鞏亦投弓。"]'),
('bad83700-ca73-4f5f-851d-53cc9c8bebe1','劉公幹','秦觀','宋','宋诗','song-poetry','','[]','鄴中多賢豪，公幹氣飄逸。',84,'全唐诗/poet.song.59000.json','["鄴中多賢豪，公幹氣飄逸。", "弱歲頗徊徨，飄零低金室。", "君王事邀宴，下馬列琴瑟。", "豪吹挾哀彈，娛歡非一日。", "當年侍賡酬，珠玉在揮筆。", "五字一何工，妙絕冠儔匹。", "所得雖經奇，未得偏人失。"]'),
('8411e53f-4f7f-41cf-821a-15fad6aaabf4','贈醫者鄒放','秦觀','宋','宋诗','song-poetry','','[]','百工皆聖作，惟醫有書傳。',120,'全唐诗/poet.song.59000.json','["百工皆聖作，惟醫有書傳。", "緒餘起人死，妙處實通天。", "鄒子本淮海，弱齡加討研。", "岐扁逢卷中，遂知百病先。", "往歲遊京室，公侯紛薦延。", "國工不敢妬，遣兒求執鞭。", "晚棄本州役，青衫鬢蕭然。", "臨衢開大肆，旁午送金錢。", "嗣子頗不凡，文場早周旋。", "行期拾青紫，善積神所憐。"]'),
('63a94776-fac2-46d3-9aee-817635f2330d','贈張潜道','秦觀','宋','宋诗','song-poetry','','[]','張生何爲者，落魄不自拘。',108,'全唐诗/poet.song.59000.json','["張生何爲者，落魄不自拘。", "獨携三尺琴，笑別妻與孥。", "一來泊吾里，忽已月再虛。", "朝遊故人館，暮止佛子廬。", "雖無食羹餘，所樂常晏如。", "我欲有所進，生聞勿煩紆。", "君子閑有道，不專塊然居。", "無道祇深適，嗚戲亦已愚。", "願生脫塵鞅，從我滄海隅。"]'),
('903f0e78-54f3-432e-92ca-28c32b61081a','荷花','秦觀','宋','宋诗','song-poetry','','[]','方塘收雨脚，落日半遥岑。',144,'全唐诗/poet.song.59000.json','["方塘收雨脚，落日半遥岑。", "芙蕖浄娟娟，麗服撫翠衾。", "無言意自遠，欲渡秋水深。", "緬懷平生人，對此詎可尋。", "弄芳惜晼晚，酒至誰與斟。", "天涯有歸雲，聊寄相思心。", "心開獲清賞，芙蕖一何綺。", "美人艷新妝，斂袂照秋水。", "端如蕩子妻，顧自良家子。", "黄金選燕趙，搖落對江沚。", "薄暮風雨來，獨立淚如洗。", "望君君詎知，傾宮定誰似。"]'),
('23952f03-99de-4ceb-a076-4fcc13be1ece','酬曾逢原參寥上人見寄山陽作','秦觀','宋','宋诗','song-poetry','','[]','倦客當老秋，於忽少佳意。',120,'全唐诗/poet.song.59000.json','["倦客當老秋，於忽少佳意。", "孰云塵滓地，劉阮肯俱至。", "一披清骨毛，再見失身世。", "有如執盛熱，傃月濯凉吹。", "又如觀巨梓，却覘蕭葦細。", "十辰同遨遊，不覺日車逝。", "嗟予逃空虛，終日面林翳。", "聞人足音喜，況乃道所契。", "方念衣袖分，明月忽我畀。", "眷言何以酬，白髮同所詣。"]'),
('67927c2d-5c9c-4f72-b40d-ad4d53ddcc6b','吳興道中','秦觀','宋','宋诗','song-poetry','','[]','僶俛蓽門下，十年守一方。',48,'全唐诗/poet.song.59000.json','["僶俛蓽門下，十年守一方。", "胡爲御舟者，挽我置此傍。", "青山不肯盡，流水故意長。", "雖云道理遠，瓦樽有酒漿。"]'),
('5de94497-f08d-431a-916f-789f8847a6e5','無題二首  其一','秦觀','宋','宋诗','song-poetry','','[]','君子有常度，所遭能自如。',48,'全唐诗/poet.song.59000.json','["君子有常度，所遭能自如。", "不與死生變，豈爲憂患渝。", "西伯囚演易，馬遷罪成書。", "性剛趣和樂，淺淺非丈夫。"]'),
('2f30e74e-affd-47e3-9e81-ff10923474a4','無題二首  其二','秦觀','宋','宋诗','song-poetry','','[]','世事如浮雲，飄忽不相待。',48,'全唐诗/poet.song.59000.json','["世事如浮雲，飄忽不相待。", "欻然化蒼狗，俄頃成章蓋。", "達觀聽兩行，昧者乃多態。", "舍旃勿重陳，百年等銷壞。"]'),
('cabe8980-bdbd-4cb9-a595-2003dfa37e74','喜雨得城字','秦觀','宋','宋诗','song-poetry','','[]','陰陽有常職，代御不可并。',168,'全唐诗/poet.song.59000.json','["陰陽有常職，代御不可并。", "一氣或錯繆，愆伏相寇兵。", "惟時四月交，南國厭久晴。", "風師挾帝令，呼號肆徂征。", "雲師畏推逐，蓄意不敢爭。", "雨師曠厥官，所苟朝夕生。", "黄塵暗如霧，掩彼日月明。", "帝眷一昔回，旱議沮莫行。", "番然需膏澤，夜半來雨聲。", "黎明縱遐眺，溝澮各已盈。", "青秧散廣畝，白水涵孤城。", "耕夫欣有託，水鳥飛且鳴。", "乃知化工妙，悠然信難名。", "行矣耘我穡，歲終竚坻京。"]'),
('e1f24bd5-5842-48f1-957f-c76e7cea88ae','東城被盜得世字','秦觀','宋','宋诗','song-poetry','','[]','野人無機心，觸事少防衛。',168,'全唐诗/poet.song.59000.json','["野人無機心，觸事少防衛。", "所至輒酣寢，屢墮穿窬計。", "孤亭夜深墨，風死雨初霽。", "有盜穴壁來，攘取逮衾袂。", "微思不敵怒，弱力鼓虛銳。", "起搏且復呼，可否難量勢。", "誰云同室鬭，函丈莫相繼。", "兩奴眠牖旁，矯首但睥睨。", "棄之倚柱休，盜亦從此逝。", "慚無牛缺賢，幸脫燕人斃。", "亡弓豈須求，失馬不必涕。", "黎明成感歎，事往若異世。", "良賈號深藏，無閡稱善閉。", "君子勿我誇，得喪求無際。"]'),
('e828f495-c4a4-4159-9970-9a8e2379038e','夢伯收文公','秦觀','宋','宋诗','song-poetry','','[]','昨夜夢故人，心顔少歡趣。',156,'全唐诗/poet.song.59000.json','["昨夜夢故人，心顔少歡趣。", "自嗟棄有司，却言歸山路。", "君王下明詔，群英翕爭赴。", "焦鵬共揮翮，跛鱉亦騁步。", "擾擾天地間，飛鳥不知數。", "何意獨蕭條，命與時相忤。", "空復蔽馬牛，不爲匠人顧。", "昔爲土中花，行待東風煦。", "今爲簷下草，遠矣霑秋露。", "老母鬢成絲，寒妻被無絮。", "歲暮多嚴風，絺綌將焉度。", "覺來不復見，撫枕淚如注。", "安得萬頃波，活此舟中鮒。"]'),
('4b7bdb0a-005b-49f8-87ad-81ddd2b36442','送佛印','秦觀','宋','宋诗','song-poetry','','[]','抱包初捨蔚頭藍，江月松風處處參。',64,'全唐诗/poet.song.59000.json','["抱包初捨蔚頭藍，江月松風處處參。", "他日惠林爲上首，幾年彌勒作同龕。", "真珠撒帳開新座，飛鳥銜花繞舊庵。", "雲散虎溪蓮社友，獨依香火思何堪。"]'),
('96a240e9-3fe4-4518-a280-67b8877a2b77','次韵公闢會流觴亭','秦觀','宋','宋诗','song-poetry','','[]','偷引湖光一派飛，詠觴還却似當時。',64,'全唐诗/poet.song.59000.json','["偷引湖光一派飛，詠觴還却似當時。", "吳歌送酒隨流急，越艷浮花轉曲池。", "山廟早因前守徹，冰盤元是故工遺。", "年年禊飲今非昔，不到蘭亭到北池。"]'),
('8679c329-2656-4de8-99dc-12beeb67215d','次韵公闢會蓬萊閣','秦觀','宋','宋诗','song-poetry','','[]','林聲摵摵動秋風，共躡丹梯上卧龍。',64,'全唐诗/poet.song.59000.json','["林聲摵摵動秋風，共躡丹梯上卧龍。", "路隔西陵三兩水，門臨南鎮一千峰。", "湖吞碧落詩爭發，塔湧青冥畫幾重。", "非是登高能賦客，可憐猿鶴自相容。"]'),
('7f23741d-a04f-4e10-88e0-cfcf42e69340','送羅正之兩浙提刑','秦觀','宋','宋诗','song-poetry','','[]','豈爲鱸魚憶故丘，東南昏墊頼良謀。',64,'全唐诗/poet.song.59000.json','["豈爲鱸魚憶故丘，東南昏墊頼良謀。", "一封暮別雲間閣，三組秋歸海上州。", "子政暫爲都水使，千秋終作富民侯。", "贈君一語君應笑，競注江河本不流。"]'),
('0db1f3f7-8fd2-465b-9bb5-a233e5935807','秋夜病起懷端叔作詩寄之','秦觀','宋','宋诗','song-poetry','','[]','寢瘵當老秋，入夜庭軒空。',288,'全唐诗/poet.song.59000.json','["寢瘵當老秋，入夜庭軒空。", "天光脆如洗，月色清無縫。", "風飆戾戾輕，露氣霏霏重。", "簷花伴徐步，籠燭窺孤諷。", "緬惟情所親，佳辰誰與共。", "夫子淮海英，材大難爲用。", "秉心既絕俗，發語自驚衆。", "麈尾扣球琳，筆端攢螮蝀。", "雄深迫揚馬，妙麗該沈宋。", "浮沉任朝野，魚鳥狎鯤鳳。", "與時真楚越，於我實伯仲。", "爾來居邑鄰，頗便書札貢。", "上憑鴻雁傳，下託鯉魚送。", "二物或愆時，已辱移文訟。", "人生無根柢，泛若凌波葑。", "昧者復汲汲，晨暝趨一鬨。", "陰持含沙毒，射影期必中。", "自匿嫫母容，對客施錦幪。", "溘然一朝逝，萬事俱成夢。", "形骸猶汝辭，利勢猶君動。", "思之可太息，傷之爲長慟。", "所以古達人，脫身事高縱。", "我生尤不敏，胸腹常空洞。", "彊顔入規模，垂耳受羈鞚。"]'),
('32f35910-f0b7-4a71-b886-917a80b4d502','送孫誠之尉北海','秦觀','宋','宋诗','song-poetry','','[]','吾鄉如覆盂，地據揚楚脊。',212,'全唐诗/poet.song.59000.json','["吾鄉如覆盂，地據揚楚脊。", "環以萬頃湖，粘天四無壁。", "蜿蜒戲神珠，正晝飛霹靂。", "草木無異姿，靈氣殊鬰積。", "所以生群材，名抱荆山璧。", "小爲百夫防，大爲萬人敵。", "夫子少邁倫，喑嗚阻金石。", "奏賦明光宮，玉座瞻咫尺。", "翻身墮雲霄，十載迫窮厄。", "焚舟更一戰，得尉滄海北。", "五月乘畫船，簫鼓事遠適。", "天橫齊山青，雨带楚水黑。", "勿云晚方仕，四十乃古昔。", "勿云名位卑，九萬自此擊。", "幽求尉朝邑，鬢髮森已白。", "元振尉通泉，律令非所即。", "一朝會風雲，顧眄立四極。", "行矣壯舊圖，勉。"]'),
('6ebde752-f94e-45af-9371-e1767a329d0d','抱甕','秦觀','宋','宋诗','song-poetry','','[]','搰搰抱甕人，汒呼治其內。',48,'全唐诗/poet.song.59000.json','["搰搰抱甕人，汒呼治其內。", "仲尼爲所輕，子貢無以對。", "捨器欲還樸，爲量固已隘。", "苟得渾沌真，寧羞事機械。"]'),
('84b86bae-eb08-405f-b260-72c781916da1','讀列子','秦觀','宋','宋诗','song-poetry','','[]','咄咄兩小兒，多言空爾爲。',48,'全唐诗/poet.song.59000.json','["咄咄兩小兒，多言空爾爲。", "後之日無定，不覺心有期。", "尺棰探蒼溟，俱令傍者嗤。", "誰謂不能决，孔丘乃真知。"]'),
('32fa7b51-780e-4fb3-9bde-17fe7fe3d772','和顯之長老','秦觀','宋','宋诗','song-poetry','','[]','禪子觀因緣，寸晷無復餘。',48,'全唐诗/poet.song.59000.json','["禪子觀因緣，寸晷無復餘。", "講人治經論，艾夜猶未除。", "冷風奏哀松，寒月挂碧虛。", "此意了不諭，悲哉同翳如。"]'),
('6d6db4a1-9bb3-48ff-9823-ffc4324f208f','清夜','秦觀','宋','宋诗','song-poetry','','[]','子夜天無雲，稀星耿頑碧。',48,'全唐诗/poet.song.59000.json','["子夜天無雲，稀星耿頑碧。", "茫茫行役者，對此焉不息。", "胡爲蝸角端，相與競尋尺。", "勸君歸去來，飛空鳥無跡。"]'),
('5f4d3edd-b583-44d2-b5d9-af0c5e2e4774','南池','秦觀','宋','宋诗','song-poetry','','[]','汎汎池中鳬，上下與水俱。',48,'全唐诗/poet.song.59000.json','["汎汎池中鳬，上下與水俱。", "不與水爭力，所以全其軀。", "遇物貴含垢，修身戒明污。", "胡能若雲月，浪自驚群愚。"]'),
('a3f231a1-d513-4d70-8e53-dc6cbbc0ac7f','和王定國','秦觀','宋','宋诗','song-poetry','','[]','崢嶸歲月徂，物色莽於邑。',48,'全唐诗/poet.song.59000.json','["崢嶸歲月徂，物色莽於邑。", "歡言公子至，坐失百憂集。", "宵箔蕙烟橫，寒炮玉脂泣。", "勉旃决南圖，荷華行滿隰。"]'),
('b3725e60-77e6-46cf-953f-702580c53e77','宿金山','秦觀','宋','宋诗','song-poetry','','[]','山南山北江水流，半空金碧隨雲浮。',128,'全唐诗/poet.song.59000.json','["山南山北江水流，半空金碧隨雲浮。", "我來仍值風日好，十月未寒如晚秋。", "山僧引客尋蒼翠，歷盡參差到平地。", "萬里風來拂骨清，却憶人間如夢寐。", "夜深無風月入扉，相對老人如槁枝。", "流水與天爭入海，共笑此心誰得知。", "下山却向中𤃩望，番憶當時在屏幛。", "老母思兒且欲歸，回首雲峰已天上。"]'),
('5bfb195f-63b1-4b99-a99e-ad4a848dee78','別賈耘老','秦觀','宋','宋诗','song-poetry','','[]','若有人兮霅之濱，服火齊兮冠切雲。',208,'全唐诗/poet.song.59000.json','["若有人兮霅之濱，服火齊兮冠切雲。", "有才不爲世所掄，盡入詩句爲奇新。", "忘歸繁弱不浪陣，發必中的疑有神。", "目關飛鳥緡蒼鱗，俛仰自娛忘賤貧。", "繄我與君素參辰，孰爲一見同天倫。", "共指飛光易沉淪，莫若痛飲還我真。", "況有內子賢文君，終日叫呼不怒嗔。", "酒酣往往出前珍，瓦甌竹筯羞青芹。", "左列文史右紅裙，樽前不覺徂清晨。", "念我行當西道秦，挐舟來別非所欣。", "欲託毫素通殷勤，郢匠旁矚難揮斤。", "人生百齡同臂伸，斷梗流萍暫相親。", "行行飲酒且勿云，丈夫萬里猶比鄰。"]'),
('126a0942-b570-4a77-9be2-30f66f832476','李端叔見寄次韵','秦觀','宋','宋诗','song-poetry','','[]','君文豪贍無與儔，使我吟諷忘離憂。',192,'全唐诗/poet.song.59000.json','["君文豪贍無與儔，使我吟諷忘離憂。", "浩如沅湘起陽侯，翻星轉日吞數州。", "華章藻句饒風力，頃刻朱紅迷畛域。", "一班縱復爲管窺，萬派終難以蠡測。", "區區文墨倦高情，解鞅還游恍惚庭。", "半槽新水六尺簟，卧視雲物行空青。", "伊我籃輿抵京縣，溽暑黄埃負初願。", "君家只在御城東，彌月不能三兩見。", "求仙未若醉中真，蟻鬭蛾飛愁殺人。", "清都夢斷理歸棹，回首一樹瓊枝新。", "歸來草木春風換，世事蝟毛那可算。", "幸謝故人頻寄書，莫笑元郎自呼漫。"]'),
('3c091c70-50af-4037-8754-65459274e8df','陳令舉妙奴詩','秦觀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖水滑多嬌嬙，妙奴十二正芬芳。',160,'全唐诗/poet.song.59000.json','["西湖水滑多嬌嬙，妙奴十二正芬芳。", "肌膚晳白髮脚長，含語未發先有香。", "溪上夜燕侍簪裳，皎如華月墮滄浪。", "音聲入雲能斷腸，不許北客辭酒漿。", "主人藹藹邦之良，少年射策謁未央。", "俊詞偉氣森開張，玉杓貫斗生怒芒。", "天欲文采老更昌，故使斂翮窺群翔。", "五十僅補尚書郎，浩歌騎牛倚倡佯。", "東風戲雨花草狂，二溪泱泱青黛光。", "妙奴勿倦侑羽觴，主人正欲游醉鄉。"]'),
('b58b67a2-b91d-4b83-92c3-3522189c3970','自警','秦觀','宋','宋诗','song-poetry','','[]','古人去後音容寂，何處茫茫尋舊迹。',336,'全唐诗/poet.song.59000.json','["古人去後音容寂，何處茫茫尋舊迹。", "君看草遍北邙山，骼骴猶來丘壟積。", "那堪此地日黄昏，長途萬里傷行客。", "只知恩愛動傷情，豈悟區區頭已白。", "莫嫌天地少含弘，自是人心多褊窄。", "爭名競利走如狂，復被利名生怨隙。", "貪聲戀色鎮如癡，終被聲色迷阡陌。", "休言七十古稀有，最苦如今難半百。", "聞道蓬宮仙子閑，紅塵不染無瑕謫。", "日月遲遲異短明，三峰秀麗皆仙格。", "女蘿覆石蔓黄花，芝草琅玕知幾尺。", "桃源長占四時春，漾漾華池真水碧。", "乘槎擬欲扣金扃，巨浪紅波依舊隔。", "歸來芳舍與誰儔，老鶴松間三四隻。", "唳天聲動彩雲飛，對我時時振長翮。", "驂鸞未遇且悠悠，盡日琴書還有適。", "紛華任使投吾前，爭奈此心終匪石。", "拜命懷金誰謂榮，低頭未免拾言責。", "從茲俗態兩相忘，笑指青山歸路僻。", "同人有志覓長生，運氣休糧徒有益。", "須知下手向無爲，莫學迷徒頼針炙。"]'),
('d4b3a2af-eb67-414f-afc0-55ba8786a50e','陪李公擇觀金地佛牙','秦觀','宋','宋诗','song-poetry','','[]','薄伽梵相含空虛，化人分段同璠璵。',240,'全唐诗/poet.song.59000.json','["薄伽梵相含空虛，化人分段同璠璵。", "爾來示滅二千歲，真骨萬里傳中區。", "錢塘有尼號法照，得自禁掖藏金鋪。", "欲因此勝高構閣，假設象似開群愚。", "偶從好事至霅上，持出瞻玩相歡娛。", "靈牙寶色玉不如，上有無數光明珠。", "莊嚴一一出御帑，蜿蜒繡袋榮硨磲。", "是時賓客盡上士，回向已登十地初。", "殷勤稱讚出軟語，坐人顧眄驚俗污。", "因悲人生信如夢，浪逐聲勢霜鬢鬚。", "一源清浄誰復無，枉入諸趨更崎嶇。", "願因今日詣真際，古松白日常蕭疏。", "乃知金仙妙難測，餘潤普及霑凡枯。", "况復老尼亦才辯，朱甍碧瓦非難圖。", "行看岧嶢倚青嶂，翁嫗頌說傾三吳。"]'),
('ab401a7a-e65d-4a99-8b0e-c12c7f3ff31a','雪浪石','秦觀','宋','宋诗','song-poetry','','[]','漢庭卿士如雲屯，結綬彈冠朝至尊。',144,'全唐诗/poet.song.59000.json','["漢庭卿士如雲屯，結綬彈冠朝至尊。", "登高履危足在外，神色不變惟伯昏。", "金華掉頭不肯住，乞身欲老江南村。", "天恩許兼兩學士，將兵百萬守北門。", "居士彊名曰天元，寤寐山水勞心魂。", "高齋引泉注奇石，迅若飛浪來雲根。", "朔南修好八十載，兵法雖妙何足論。", "夜闌番漢人馬靜，想見雉堞低金盆。", "報罷五更人吏散，坐調一氣白元存。"]'),
('6e96babc-7a23-4cff-93dd-adeadb409f7b','和蔡天啟贈文潜之什','秦觀','宋','宋诗','song-poetry','','[]','蔡侯飽學困千釜，濯足清江起南土。',128,'全唐诗/poet.song.59000.json','["蔡侯飽學困千釜，濯足清江起南土。", "劇談頗似燕客豪，快奪范雎如墜雨。", "東城橋梓未足論，栢直何爲口方乳。", "蔣侯山中伴香火，三年不厭長蔬苦。", "平生瑰瑋有誰同，要得張侯三日語。", "晝閑那自運甓忙，時清不用聞鷄舞。", "桓榮歡喜見車馬，書冊辛勤立門戶。", "要當食肉似班超，猛虎何嘗窺案俎。"]'),
('ecb5447d-74a6-4078-adbe-17f6c63ee909','早春','秦觀','宋','宋诗','song-poetry','','[]','黄金蔌蔌滿垂楊，尚有春寒到畫堂。',32,'全唐诗/poet.song.59000.json','["黄金蔌蔌滿垂楊，尚有春寒到畫堂。", "酒力漸銷歌扇怯，入簾飛雪带梅香。"]'),
('19f8d8ab-320a-4e03-8ebe-c59454236bad','赴杭倅至汴上作','秦觀','宋','宋诗','song-poetry','','[]','俯仰觚稜十載間，扁舟江海得身閑。',32,'全唐诗/poet.song.59000.json','["俯仰觚稜十載間，扁舟江海得身閑。", "平生孤負僧床睡，准擬如今處處還。"]'),
('ca25647d-28d8-4356-b4fc-0e607ff26f0f','次韵孔彥常舍人曝書','秦觀','宋','宋诗','song-poetry','','[]','上帝圖書府，傳觀詔特容。',48,'全唐诗/poet.song.59000.json','["上帝圖書府，傳觀詔特容。", "嘉賓蒼佩玉，盛饌紫駝峰。", "散帙牙籤亂，開函錦襲重。", "君羹如可請，願備北堂供。"]'),
('db7aa2ea-7461-4031-a110-b258afb2d1ef','次韵莘老','秦觀','宋','宋诗','song-poetry','','[]','妙齡隨計日，紺髮度關年。',288,'全唐诗/poet.song.59000.json','["妙齡隨計日，紺髮度關年。", "較藝先豪俊，飛聲動眇綿。", "祕書窺甲乙，密室詣溫宣。", "已叶半千運，仍親五尺天。", "御香春晚炷，宮蠟夜深燃。", "漢殿螭頭筆，岐藩幕下蓮。", "孔鸞人共貴，蘭蕙世皆憐。", "附尾方瞠若，提刀獨砉然。", "皂囊封細札，青簡續遺編。", "璧府深難造，龍媒雋莫先。", "大農參奏計，宗伯與興賢。", "玉鉉行真即，金甌忽浪傳。", "兩輪苕上駕，百仗剡中牽。", "荏苒馮唐老，淹回賈傅還。", "星霜俄九換，金竹遽三遷。", "鼓吹吳雲外，旌旛楚水壖。", "經綸殊未倦，憂患復相連。", "惡草空搖毒，群蝸謾污涎。", "松筠終不易，雨露竟無偏。", "憔悴千株橘，荒凉二頃田。", "幾書借船帖，屢廣絕交篇。", "禪譽推龐藴，親評主閔騫。", "懶因閑處極，樂向靜中全。", "歲月黄塵裏，鶑花白髮前。"]'),
('87f0af4a-c4d2-4326-89a6-b4d2c4d32928','送陳太初道錄','秦觀','宋','宋诗','song-poetry','','[]','先生簪紱後，世系本綿瓜。',144,'全唐诗/poet.song.59000.json','["先生簪紱後，世系本綿瓜。", "駐馬生枯骨，回車濟病蛇。", "带雲眠酒市，和月醉漁家。", "落日千山路，西風一枕霞。", "幾年流俗笑，一旦五侯誇。", "棋惜春深日，琴憎雨後蛙。", "背因書字曲，髮爲注經華。", "地轉東淮水，天回北斗車。", "新宮黄道近，舊隠白雲遐。", "顧我身多累，逢君意謾誇。", "空提方士劍，未上客星槎。", "何日同歸去，重飛九轉砂。"]'),
('2f9f13b4-66c0-4e5c-942a-1acc318ee31d','贈蘇子瞻','秦觀','宋','宋诗','song-poetry','','[]','嘆息蘇子瞻，聲名絕後先。',120,'全唐诗/poet.song.59000.json','["嘆息蘇子瞻，聲名絕後先。", "衣冠傳盛事，兄弟固多賢。", "感慨詩三百，流離路八千。", "直心羞媚竈，忠力欲回天。", "縲紲終非罪，江湖秪自憐。", "饑寒常併日，疾病更連年。", "明主無終棄，西州稍內遷。", "奏言深意苦，感涕內人傳。", "前席須宣室，非熊起渭川。", "君臣悅相遇，願上角招篇。"]'),
('e95a0d1c-beb6-4715-a031-d133422f63ac','次韵安州晚行寄傳師','秦觀','宋','宋诗','song-poetry','','[]','投暮安州北，蒼烟亂眼昏。',48,'全唐诗/poet.song.59000.json','["投暮安州北，蒼烟亂眼昏。", "茅茨人外路，砧杵月邊村。", "野水飛雲薄，空林噪雀繁。", "幾人堪此樂，逢客莫輕論。"]'),
('802ecf62-2818-4dd3-8336-bb622a16a275','題五柳亭','秦觀','宋','宋诗','song-poetry','','[]','結構依流水，新題五柳亭。',36,'全唐诗/poet.song.59000.json','["結構依流水，新題五柳亭。", "登臨有遺味，攀折不勝情。", "隔岸閭閻鼓，遶軒舟舫橫。"]'),
('3c5114d3-dff1-490d-8424-31a5d9983564','觀寶林塔張燈次胡瑗韵','秦觀','宋','宋诗','song-poetry','','[]','飛來峰上塔，然蜜奉慈觀。',120,'全唐诗/poet.song.59000.json','["飛來峰上塔，然蜜奉慈觀。", "互照三山冢，分輝七寶欄。", "勢擎金界迥，影蘸玉奩寒。", "次第邊烽舉，高低祭燭攢。", "虹旌排陣堞，火傘御靈官。", "魏乘珠千顆，隋帆錦萬端。", "華敷連藏海，光集匝宮壇。", "冏冏連青昊，熒熒逼翠巒。", "月卿秋抒思，星將夜濡翰。", "繼聽鈞天奏，尤知屬和難。"]'),
('9ee2f845-f519-44a2-8088-6091f118bf27','還自湯泉十四韵','秦觀','宋','宋诗','song-poetry','','[]','歲晚倦城郭，聯驂度嶪峨。',168,'全唐诗/poet.song.59000.json','["歲晚倦城郭，聯驂度嶪峨。", "天黄雲脚亂，村黑鳥翎訛。", "潦水侵生路，晴天落慢坡。", "澄江練不卷，溫井鑑新磨。", "漁火分星遠，沙鷗散點多。", "霸祠題玉筯，龍窟受金波。", "琬琰存吳事，兒童記楚歌。", "孤龕瘦居士，雙塔老頭陀。", "飛鼠鳴深穴，胡蜂結巧窠。", "晚參圓白足，昏梵禮青螺。", "雲馭沉荒遊，仙舂沒淺莎。", "杖藜從莫逆，談笑入無何。", "慘澹日連霧，蕭騷風轉阿。", "華清俄夢斷，回首失烟蘿。"]'),
('09498cf4-96e6-4c7b-847b-b7dd768ab6c5','辨才法師嘗以詩見寄繼聞示寂追次其韵','秦觀','宋','宋诗','song-poetry','','[]','遥聞隻履去翛然，詩翰纔收數月前。',64,'全唐诗/poet.song.59000.json','["遥聞隻履去翛然，詩翰纔收數月前。", "江海盡頭人滅度，亂山深處塔孤圓。", "憶登夜閣天連雁，同看秋崖月破烟。", "尚有衆生未成佛，肯超欲界入諸禪。"]'),
('c1907439-b248-49e0-a22f-6305cd773d67','次韵公闢州宅月夜偶成  其一','秦觀','宋','宋诗','song-poetry','','[]','新秋過雨月如霜，緩足蓬萊徹上方。',64,'全唐诗/poet.song.59000.json','["新秋過雨月如霜，緩足蓬萊徹上方。", "翠木玲瓏藏寶界，白烟濃淡鎖華堂。", "書名越艷誰興發，角動單于自感傷。", "山似卧龍天似水，却疑身在海中央。"]'),
('2ea55b9d-a7eb-4c3d-ae1c-1f9ede18abb4','次韵公闢州宅月夜偶成  其二','秦觀','宋','宋诗','song-poetry','','[]','繚繞千重雨後凉，月含秋色上東方。',64,'全唐诗/poet.song.59000.json','["繚繞千重雨後凉，月含秋色上東方。", "風催絡紓歸金井，月轉檀欒蔭畫堂。", "游目騁懷佳興發，感時撫事壯心傷。", "歸來枕簟清無夢，卧看明星到未央。"]'),
('b485127a-1f22-4c85-9491-f3bf83ba53f5','次韵公闢即席呈太虛','秦觀','宋','宋诗','song-poetry','','[]','與君鄰並共烟霞，乘興時時過我家。',64,'全唐诗/poet.song.59000.json','["與君鄰並共烟霞，乘興時時過我家。", "更漏一新聞曉角，門闌數級看秋花。", "湖山對值全如買，風月相期不用賒。", "頼有醉毫吟更苦，他年分作句圖誇。"]'),
('7a4add0c-98f1-4fcc-97ab-c0efb9176fbe','次韵公闢將受代書蓬萊閣','秦觀','宋','宋诗','song-poetry','','[]','城連湖岸水爲關，旦暮樵風自往還。',64,'全唐诗/poet.song.59000.json','["城連湖岸水爲關，旦暮樵風自往還。", "龜負寶林新佛地，龍蟠使宅老仙山。", "平生仕宦今何得，終日登臨獨未閑。", "歲滿徘徊難遽別，就中瀟洒異人間。"]'),
('32fd1315-5efb-4466-82c1-d508797c3b83','次韵公闢聞角有感','秦觀','宋','宋诗','song-poetry','','[]','一聽胡笳動越吟，聲潜地底氣逾深。',64,'全唐诗/poet.song.59000.json','["一聽胡笳動越吟，聲潜地底氣逾深。", "千宮月色單于曲，萬里天光魏闕心。", "秉燭何人猶把盞，挑燈有女正穿針。", "早寒時節黄昏後，更逐西風應遠砧。"]'),
('94dc7cf5-e8a0-4242-8e17-4e54cda22b2c','呈公闢','秦觀','宋','宋诗','song-poetry','','[]','東歸行路歎賢哉，碧落新除寵上才。',64,'全唐诗/poet.song.59000.json','["東歸行路歎賢哉，碧落新除寵上才。", "白傅林塘隨畫去，吳山花鳥入詩來。", "唱酬自有微之在，談笑應容逸少陪。", "除此兩翁相見外，不知三徑爲誰開。"]'),
('f6ec4fcb-a21e-4da1-8d2a-dd6ec37d01d6','奉和莘老','秦觀','宋','宋诗','song-poetry','','[]','童子何知幸最深，父班籍湜奉登臨。',64,'全唐诗/poet.song.59000.json','["童子何知幸最深，父班籍湜奉登臨。", "挾經屢造芝蘭室，揮麈常聆金玉音。", "黄卷香焚春晼晚，絳紗人散夜蕭森。", "明朝只恐絲綸下，回首青雲萬里心。"]'),
('37917cf2-27fb-47d4-ab7a-f6b749d154d4','致政通議口號','秦觀','宋','宋诗','song-poetry','','[]','秋空畫隼照新晴，符隠庵前小隊停。',64,'全唐诗/poet.song.59000.json','["秋空畫隼照新晴，符隠庵前小隊停。", "玉斝金醪通繾綣，鳳笙龍管入青冥。", "靚妝釃酒花侵席，寶獸呀香霧滿庭。", "太史應占豫州分，上台星近老人星。"]'),
('fff8d795-32b2-4fa5-9d65-51054a747f16','口號','秦觀','宋','宋诗','song-poetry','','[]','平原居士今無影，鸚鵡空洲誰舉杯。',32,'全唐诗/poet.song.59000.json','["平原居士今無影，鸚鵡空洲誰舉杯。", "猶有漁陽摻檛鼓，爲君醉後作輕雷。"]'),
('8d7799c7-fb50-459d-a252-63c147bb14b1','悼王子開五首    其一','秦觀','宋','宋诗','song-poetry','','[]','我昔官房子，長懷忠穆賢。',48,'全唐诗/poet.song.59000.json','["我昔官房子，長懷忠穆賢。", "里無行馬第，山有卧牛阡。", "當代三公後，惟君五福全。", "桐棺遠歸祔，追舊幾潸然。"]'),
('d8690d5a-d1e0-4a20-ba79-8493d5d32f4e','悼王子開五首    其二','秦觀','宋','宋诗','song-poetry','','[]','卓爾金閨彥，頎然玉筍班。',45,'全唐诗/poet.song.59000.json','["卓爾金閨彥，頎然玉筍班。", "周旋三友益，零落十年間。", "轣轆靈輀動，悠揚素旐還。", "暮年還抱愛，應復。"]'),
('4ee1a606-c34f-45f7-a301-d4bee1b46029','悼王子開五首    其三','秦觀','宋','宋诗','song-poetry','','[]','蕭散竹林風，平生約略同。',48,'全唐诗/poet.song.59000.json','["蕭散竹林風，平生約略同。", "官班嵇叔夜，年輩晉安豐。", "民詠濡須政，朝推朐䏰功。", "九原無復作，埋玉恨何窮。"]'),
('0d10c5e7-08a7-4cef-be0d-0a6ad587bb97','悼王子開五首    其四','秦觀','宋','宋诗','song-poetry','','[]','南浦維舟訪，東堂抵榻眠。',48,'全唐诗/poet.song.59000.json','["南浦維舟訪，東堂抵榻眠。", "後期猶指日，輕別遂終天。", "墨妙今初貴，詩名久已傳。", "清風如未墜，諸子更翩翩。"]'),
('d12f6934-75e0-4bfe-894e-3c1697fc2a8c','悼王子開五首    其五','秦觀','宋','宋诗','song-poetry','','[]','已矣知無憾，賢愚共此途。',48,'全唐诗/poet.song.59000.json','["已矣知無憾，賢愚共此途。", "白駒馳白日，黄髮掩黄壚。", "和氏終歸趙，干將不葬吳。", "拏痾如可彊，猶擬奠生芻。"]'),
('d226a221-c135-476b-be7b-94163e4bdb68','秋興九首 擬韓退之','秦觀','宋','宋诗','song-poetry','','[]','逍遥北窗下，百事遠客慮。',72,'全唐诗/poet.song.59000.json','["逍遥北窗下，百事遠客慮。", "無端葉間蟬，催促時節去。", "愁起如亂絲，縈纏不如緒。", "日月豈得已，還復役朝暮。", "人生均有得，悲歎我不誤。", "春愁自天時，感憤亦真趣。"]'),
('7d568952-47ae-4c59-b0cc-af80d4ff912c','秋興九首 擬孟郊','秦觀','宋','宋诗','song-poetry','','[]','曉風有暴信，暮蟬無好聲。',60,'全唐诗/poet.song.59000.json','["曉風有暴信，暮蟬無好聲。", "曉風與暮蟬，自與時節爭。", "獨客辭故鄉，推車謁梁城。", "梁城道迢遞，區區役吾生。", "不如歸舊山，藜藿安性情。"]'),
('7a8c9ff1-67b0-4845-b7f1-add7fef6026f','秋興九首 擬韋應物','秦觀','宋','宋诗','song-poetry','','[]','坐投林下石，秋聲出疏林。',72,'全唐诗/poet.song.59000.json','["坐投林下石，秋聲出疏林。", "林間鳥驚棲，豈獨傷客心。", "物亦有代謝，此理共古今。", "鄰父縮新醅，林下邀同斟。", "癡兒踏吳歌，婭姹足訛音。", "日落相携手，凉風快虛襟。"]'),
('caa3af57-85b0-47ef-aa8e-6625514cdf04','秋興九首 擬李賀','秦觀','宋','宋诗','song-poetry','','[]','魚鱗甃空排嫩碧，露桂梢寒挂團璧。',64,'全唐诗/poet.song.59000.json','["魚鱗甃空排嫩碧，露桂梢寒挂團璧。", "白蘋風起吹北窗，尺鯉沉沒斷消息。", "燕子將雛欲歸去，沈郎病骨驚遲暮。", "濃愁茫茫寄何處，萬里江南芳草路。"]'),
('73209f97-0786-40e4-9648-e91f210bac56','秋興九首 擬李白','秦觀','宋','宋诗','song-poetry','','[]','芙蓉露濃紅壓枝，幽禽感秋花畔啼。',104,'全唐诗/poet.song.59000.json','["芙蓉露濃紅壓枝，幽禽感秋花畔啼。", "玉人一去未回馬，梁邊燕子三見歸。", "江頭白蘋老波底，尺書不來空相望。", "斜吹疏雨濕秋江，霜風暗引芙蕖香，石上菖蒲三尺長。", "綠頭鴨兒棲萍草，採蓮女郎笑花老。", "木蘭船上動江水，不覺鴛鴦带波起。"]'),
('6d12b7a5-bbd8-4bdf-8108-4f3688f25bec','秋興九首 擬玉川子','秦觀','宋','宋诗','song-poetry','','[]','南州有病客，起卧北窗下。',111,'全唐诗/poet.song.59000.json','["南州有病客，起卧北窗下。", "玉兔銜光照清夜，故人別我京洛遊，不寄一行三改秋。", "秋色變冷客裘薄，漸覺衣袂寒颼颼。", "作詩欲寄君，未語先有愁。", "不如呼童起，危坐北窗下，一杯寬我千日憂。", "眼前俗事何擾擾，此夕盡向杯中休，何必懷黄金印兮爵通侯。"]'),
('c4908a27-2717-45ae-9a1e-bf120f71d8f1','秋興九首 擬杜子美','秦觀','宋','宋诗','song-poetry','','[]','紫領寬袍漉酒巾，江頭蕭散作閑人。',64,'全唐诗/poet.song.59000.json','["紫領寬袍漉酒巾，江頭蕭散作閑人。", "悲風有意催林葉，落日無情下水濱。", "車馬憧憧諸道路，市朝滾滾共埃塵。", "覓錢稚子啼紅頰，不信山翁篋笥貧。"]'),
('f28c84b0-37a5-4354-b463-2d8274d30869','秋興九首 擬杜牧之','秦觀','宋','宋诗','song-poetry','','[]','鼓鼙夜戰北窗風，霜葉鋪階疊亂紅。',64,'全唐诗/poet.song.59000.json','["鼓鼙夜戰北窗風，霜葉鋪階疊亂紅。", "一段新愁驚枕上，幾聲悲雁落雲中。", "眼前時節看馳馬，日下生涯寄斷蓬。", "弟妹別來勞夢寐，杳無消息過江東。"]'),
('75da88ed-cd1e-423c-bcc6-64ecba2efd30','秋興九首 擬白樂天','秦觀','宋','宋诗','song-poetry','','[]','不因霜葉辭林去，的當山翁未覺秋。',64,'全唐诗/poet.song.59000.json','["不因霜葉辭林去，的當山翁未覺秋。", "北里酒錢煩屢索，南州詩債懶頻酬。", "欲歌金縷羞紅粉，擬插黄花避白頭。", "底事登臨好時節，等閑收拾許多愁。"]'),
('0ac1bf09-7331-417e-970f-a6ee62ece338','金山晚眺','秦觀','宋','宋诗','song-poetry','','[]','西津江口月初弦，水氣昏昏上接天。',32,'全唐诗/poet.song.59000.json','["西津江口月初弦，水氣昏昏上接天。", "清渚白沙茫不辨，只應燈火是漁船。"]'),
('17610f75-8839-4c0d-9085-849a71db326d','病中','秦觀','宋','宋诗','song-poetry','','[]','疏簾薄幔對青燈，鸜鵒喧喧自轉更。',32,'全唐诗/poet.song.59000.json','["疏簾薄幔對青燈，鸜鵒喧喧自轉更。", "風雨渺漫人卧病，地爐湯鼎更悲鳴。"]'),
('bdbbbcf7-b0cd-48e3-93d6-c7b08b8b4a90','聞雁懷邵仲恭','秦觀','宋','宋诗','song-poetry','','[]','楚澤吳天去未遲，煩君且傍蒜山飛。',32,'全唐诗/poet.song.59000.json','["楚澤吳天去未遲，煩君且傍蒜山飛。", "白袍居士如相問，爲說淄塵欲滿衣。"]'),
('b14830dd-e2c3-4d95-ad18-9dc76b9acf11','冬蚊','秦觀','宋','宋诗','song-poetry','','[]','蚤蠆蜂虻罪一倫，未如蚊子重堪嗔。',32,'全唐诗/poet.song.59000.json','["蚤蠆蜂虻罪一倫，未如蚊子重堪嗔。", "萬枝黄落風如射，猶自傳呼欲噬人。"]'),
('259c0b0a-6a78-42af-9d21-e087bb0e037d','白馬寺晚泊','秦觀','宋','宋诗','song-poetry','','[]','濛濛晚雨暗回塘，遠樹依微不辨行。',32,'全唐诗/poet.song.59000.json','["濛濛晚雨暗回塘，遠樹依微不辨行。", "人物漸稀疏磬斷，綠蒲叢底宿鴛鴦。"]'),
('b3ac71b3-565a-4c98-b35b-867100a6219f','霅上感懷','秦觀','宋','宋诗','song-poetry','','[]','七年三過白蘋洲，長與諸豪載酒游。',32,'全唐诗/poet.song.59000.json','["七年三過白蘋洲，長與諸豪載酒游。", "舊事欲尋無處問，雨荷風蓼不勝秋。"]'),
('13e6a002-b7cd-45f1-97ea-73a41e0743d5','和程給事贈虞道判六首  其一','秦觀','宋','宋诗','song-poetry','','[]','刀圭雲母具晨餐，門對三層步斗壇。',32,'全唐诗/poet.song.59000.json','["刀圭雲母具晨餐，門對三層步斗壇。", "夜考鶴經分七九，曉占歲氣辨黅丹。"]'),
('9cab0c2d-2690-4368-a000-9ea9b63b0f95','和程給事贈虞道判六首  其二','秦觀','宋','宋诗','song-poetry','','[]','火棗交梨近可餐，不須地肺及天壇。',32,'全唐诗/poet.song.59000.json','["火棗交梨近可餐，不須地肺及天壇。", "龜藏坎海毛皆綠，鳳宿離宮色自丹。"]'),
('53200399-1139-4b89-a630-e6200222e32b','和程給事贈虞道判六首  其三','秦觀','宋','宋诗','song-poetry','','[]','紫府沉沉掩夜關，竹陰清掃月中壇。',32,'全唐诗/poet.song.59000.json','["紫府沉沉掩夜關，竹陰清掃月中壇。", "歲星偷得桃枝碧，董奉栽成李子丹。"]'),
('cb3a4bda-60d3-4257-baa4-4cae7157c95e','和程給事贈虞道判六首  其四','秦觀','宋','宋诗','song-poetry','','[]','囊中玉色已經餐，醉拂絲桐坐杏壇。',32,'全唐诗/poet.song.59000.json','["囊中玉色已經餐，醉拂絲桐坐杏壇。", "應笑倦游塵滓客，鬢毛蕭瑟事鉛丹。"]'),
('cfcd56b3-806e-45e1-8b1c-c79a6a634651','和程給事贈虞道判六首  其五','秦觀','宋','宋诗','song-poetry','','[]','漢武遊心縹緲間，文成五利盡登壇。',32,'全唐诗/poet.song.59000.json','["漢武遊心縹緲間，文成五利盡登壇。", "何如屈曲韓夫子，不羨神君白玉丹。"]'),
('c7f02102-9578-4972-b2fa-b97e2935be38','和程給事贈虞道判六首  其六','秦觀','宋','宋诗','song-poetry','','[]','使君本住道家山，時訪玄都太古壇。',32,'全唐诗/poet.song.59000.json','["使君本住道家山，時訪玄都太古壇。", "陰惠已能追許令，治功不獨過韋丹。"]'),
('16af7861-56e5-4279-9a39-8901ef4a70b2','處州閑題','秦觀','宋','宋诗','song-poetry','','[]','清酒一盃甜似蜜，美人雙鬢黑如鴉。',32,'全唐诗/poet.song.59000.json','["清酒一盃甜似蜜，美人雙鬢黑如鴉。", "莫誇春色欺秋色，未信桃花勝菊花。"]'),
('7f9df762-1a3c-4892-bf67-470299a59b9c','春詞絕句五首  其一','秦觀','宋','宋诗','song-poetry','','[]','蒲萄裀暖蕙薰微，紅日窺軒睡覺時。',32,'全唐诗/poet.song.59000.json','["蒲萄裀暖蕙薰微，紅日窺軒睡覺時。", "人倦披衣雙燕出，青絲披罥木蘭枝。"]'),
('d283ee37-7d08-4f70-84c3-13e826b8dcd0','春詞絕句五首  其二','秦觀','宋','宋诗','song-poetry','','[]','弱雲亭午弄春嬌，高柳無風妥翠條。',32,'全唐诗/poet.song.59000.json','["弱雲亭午弄春嬌，高柳無風妥翠條。", "懶讀夜書搔短髮，隔垣時聽賣餳簫。"]'),
('b8f8fdff-c464-470e-9cb6-d674223b51ba','春詞絕句五首  其三','秦觀','宋','宋诗','song-poetry','','[]','都城春富百花披，長憶人歸駐馬時。',32,'全唐诗/poet.song.59000.json','["都城春富百花披，長憶人歸駐馬時。", "淺色御黄應好在，爲誰還發去年枝。"]'),
('5f154dd0-7d71-4ddf-903a-7a3625b5722a','春詞絕句五首  其四','秦觀','宋','宋诗','song-poetry','','[]','風驅白雨洗園林，蔽地飛花一寸深。',32,'全唐诗/poet.song.59000.json','["風驅白雨洗園林，蔽地飛花一寸深。", "狂紫浪紅俱已矣，老春雖在亦何心。"]'),
('34cafc48-b44a-4171-b8d1-14d825e46f42','春詞絕句五首  其五','秦觀','宋','宋诗','song-poetry','','[]','顛毛漸脫風情少，匣劍空存俠氣銷。',32,'全唐诗/poet.song.59000.json','["顛毛漸脫風情少，匣劍空存俠氣銷。", "人遠地偏無酒肉，春深花鳥謾相撩。"]'),
('6fe54a17-ff2e-4fbc-bf89-90859c900613','秋詞二首  其一','秦觀','宋','宋诗','song-poetry','','[]','雲惹低空不更飛，班班紅葉欲辭枝。',32,'全唐诗/poet.song.59000.json','["雲惹低空不更飛，班班紅葉欲辭枝。", "秋光未老仍微暖，恰似梅花結子時。"]'),
