('49e1daae-d248-47d6-8ef2-3bc754e4aff9','齊逸亭','秦觀','宋','宋诗','song-poetry','','[]','燄發郎君更不歸，故亭蕭瑟異當時。',32,'全唐诗/poet.song.59000.json','["燄發郎君更不歸，故亭蕭瑟異當時。", "玉笙金管渾如夢，只有梅花三四枝。"]'),
('2344dcde-f6d7-4c2f-993f-463481eb9e45','春日','秦觀','宋','宋诗','song-poetry','','[]','殘臘渺茫雲外日，新春彷彿夢中來。',32,'全唐诗/poet.song.59000.json','["殘臘渺茫雲外日，新春彷彿夢中來。", "雪霜便覺都無力，只見桃花次第開。"]'),
('5dd936c7-56d9-4d5f-873c-235e33454036','宿乾明方丈','秦觀','宋','宋诗','song-poetry','','[]','漫天白雪無端現，佛室夜艾烏更啼。',32,'全唐诗/poet.song.59000.json','["漫天白雪無端現，佛室夜艾烏更啼。", "相逢解頤足自慰，勿語俗子念心携。"]'),
('1bc30f7d-a820-442d-9ce6-23b6b3639edd','新開湖送孫誠之有龍見于東北因成絕句','秦觀','宋','宋诗','song-poetry','','[]','狂客走影暗悠悠，菡萏吹風五月秋。',32,'全唐诗/poet.song.59000.json','["狂客走影暗悠悠，菡萏吹風五月秋。", "黄綬不爲無氣概，蒼龍垂尾送行舟。"]'),
('f71d56f5-0a4f-41da-9d8e-632b355d2cb8','呈李公擇','秦觀','宋','宋诗','song-poetry','','[]','青箋擘處銀鈎斷，紅袂分時五筯懸。',32,'全唐诗/poet.song.59000.json','["青箋擘處銀鈎斷，紅袂分時五筯懸。", "雲脚漸收風色緊，半規斜日射歸船。"]'),
('55f6fea9-c10e-4830-a2fd-9a46c75b14c6','落日馬上','秦觀','宋','宋诗','song-poetry','','[]','日落荒阡白霧深，紫騮嘶顧出疏林。',32,'全唐诗/poet.song.59000.json','["日落荒阡白霧深，紫騮嘶顧出疏林。", "回頭已失來時路，杳杳金盤墮翠岑。"]'),
('a2b1710d-819d-4aff-913b-f4480c553f2a','次韵參寥三首  其一','秦觀','宋','宋诗','song-poetry','','[]','武陵漁子入花源，但見秦人不得仙。',32,'全唐诗/poet.song.59000.json','["武陵漁子入花源，但見秦人不得仙。", "會有黄鸝鳴翠柳，何妨白眼望青天。"]'),
('b354e60b-292f-4a36-8724-81f200fae675','次韵參寥三首  其二','秦觀','宋','宋诗','song-poetry','','[]','長安仕路與雲齊，倦僕羸驂不可躋。',32,'全唐诗/poet.song.59000.json','["長安仕路與雲齊，倦僕羸驂不可躋。", "但得玄暉曾折簡，何須平子更安題。"]'),
('2c8e561f-dbaa-41d1-a2ac-b041a09141a9','次韵參寥三首  其三','秦觀','宋','宋诗','song-poetry','','[]','且折花枝醉復醒，人間時節易崢嶸。',32,'全唐诗/poet.song.59000.json','["且折花枝醉復醒，人間時節易崢嶸。", "屠龍肯自羞無用，畫虎從人笑不成。"]'),
('bdc372ae-8bc6-46dd-995e-fea63668cd02','和書天慶觀賀祕監堂三首  其一','秦觀','宋','宋诗','song-poetry','','[]','老仙舊地枕東城，古木參天警晝聲。',32,'全唐诗/poet.song.59000.json','["老仙舊地枕東城，古木參天警晝聲。", "我亦願爲方外友，風流何必並時生。"]'),
('18b4e16f-14d9-451f-aad9-11f0de13c57b','和書天慶觀賀祕監堂三首  其二','秦觀','宋','宋诗','song-poetry','','[]','史君平昔慕玄清，一到祠堂意一新。',32,'全唐诗/poet.song.59000.json','["史君平昔慕玄清，一到祠堂意一新。", "戶外黄冠應指點，公應便是謫仙人。"]'),
('50082dcb-b23c-43a6-bd6c-32055554489f','和書天慶觀賀祕監堂三首  其三','秦觀','宋','宋诗','song-poetry','','[]','衣屨蕭條氣久清，豪家門館未嘗行。',32,'全唐诗/poet.song.59000.json','["衣屨蕭條氣久清，豪家門館未嘗行。", "朱甍碧瓦何從得，疑有陰兵夜助成。"]'),
('c4d7f53e-ca68-409b-ae82-063cbc3758aa','和書觀妙庵','秦觀','宋','宋诗','song-poetry','','[]','龍瑞宮中種玉人，誅茅結室傍秋雲。',32,'全唐诗/poet.song.59000.json','["龍瑞宮中種玉人，誅茅結室傍秋雲。", "自言洞裏山川別，此處千分未一分。"]'),
('68b49866-af59-45aa-a9f2-b8e5dc6ec82e','早春題僧舍','秦觀','宋','宋诗','song-poetry','','[]','東園紫梅初破蕾，北澗淥水方通流。',32,'全唐诗/poet.song.59000.json','["東園紫梅初破蕾，北澗淥水方通流。", "歸去一春花月夢，定應多在此中遊。"]'),
('ff35fac1-2cef-4a50-a6ad-3488f191d18e','盆池釣翁','秦觀','宋','宋诗','song-poetry','','[]','誰刻仙材作釣翁，尺池終日釣微風。',32,'全唐诗/poet.song.59000.json','["誰刻仙材作釣翁，尺池終日釣微風。", "令人却憶鴟夷子，散髮五湖狂醉中。"]'),
('7a1e46a6-bb8b-41d0-95bf-fdf068349553','賞酴醾有感','秦觀','宋','宋诗','song-poetry','','[]','春來百物不入眼，唯見此花堪斷腸。',32,'全唐诗/poet.song.59000.json','["春來百物不入眼，唯見此花堪斷腸。", "借問斷腸緣底事，羅衣曾似此花香。"]'),
('6a19b629-26d3-49c3-a4c4-4c1198574099','王昭君','秦觀','宋','宋诗','song-poetry','','[]','漢宮選女適單于，明妃斂袂登氈車。',64,'全唐诗/poet.song.59000.json','["漢宮選女適單于，明妃斂袂登氈車。", "玉容寂寞花無主，顧影低回泣路隅。", "行行漸入陰山路，目送征鴻入雲去。", "獨抱琵琶恨更深，漢宮不見空回顧。"]'),
('e4823be1-730f-419a-aaa4-288123894c35','樂昌公主','秦觀','宋','宋诗','song-poetry','','[]','金陵往昔帝王州，樂昌主第最風流。',64,'全唐诗/poet.song.59000.json','["金陵往昔帝王州，樂昌主第最風流。", "一朝隋兵到江上，共抱悽悽去國愁。", "越公萬騎鳴笳鼓，劍擁玉人天上去。", "空携破鏡望紅塵，千古江楓籠輦路。"]'),
('3b0209a2-9a5a-43e6-abe5-387d05404cbf','崔徽','秦觀','宋','宋诗','song-poetry','','[]','蒲中有女號崔徽，輕似南山翡翠兒。',64,'全唐诗/poet.song.59000.json','["蒲中有女號崔徽，輕似南山翡翠兒。", "使君當日最寵愛，坐中對客常擁持。", "一見裴郎心似醉，夜解羅衣與門吏。", "西門寺里樂未央，樂府至今歌翡翠。"]'),
('11660a30-2b09-4e80-bf9d-b03f40debab7','無雙','秦觀','宋','宋诗','song-poetry','','[]','尚書有女名無雙，蛾眉如畫學新妝。',64,'全唐诗/poet.song.59000.json','["尚書有女名無雙，蛾眉如畫學新妝。", "伊家仙客最明俊，舅母唯只呼王郎。", "尚書往日先曾許，數載暌違今復遇。", "聞說襄江二十年，當時未必輕相慕。"]'),
('5751786d-e569-46d9-8f86-f4e9b886a58f','灼灼','秦觀','宋','宋诗','song-poetry','','[]','錦城春暖花欲飛，灼灼當庭舞柘枝。',64,'全唐诗/poet.song.59000.json','["錦城春暖花欲飛，灼灼當庭舞柘枝。", "相公上客河東秀，自言那得傍人知。", "妾願身爲梁上燕，朝朝暮暮長相見。", "雲收月墮海沉沉，淚滿紅綃寄腸斷。"]'),
('0b14333c-9b2d-4ea1-a513-41e53538fd24','盼盼','秦觀','宋','宋诗','song-poetry','','[]','百尺樓高燕子飛，樓上美人顰翠眉。',64,'全唐诗/poet.song.59000.json','["百尺樓高燕子飛，樓上美人顰翠眉。", "將軍一去音容遠，只有年年舊燕歸。", "春風昨夜來深院，春色依然人不見。", "只餘明月照孤眠，回望舊恩空戀戀。"]'),
('3c115404-c3c3-46a9-a2ae-abcb36fe7b20','崔鶑鶑','秦觀','宋','宋诗','song-poetry','','[]','崔家有女名鶑鶑，未識春光先有情。',64,'全唐诗/poet.song.59000.json','["崔家有女名鶑鶑，未識春光先有情。", "河橋兵亂依蕭寺，紅愁綠慘見張生。", "張生一見春情重，明月拂牆花影動。", "夜半紅娘擁抱來，脈脈驚魂若春夢。"]'),
('8ccd648e-3e35-499c-a805-62ba4ba72673','採蓮','秦觀','宋','宋诗','song-poetry','','[]','若耶溪邊天氣秋，採蓮女兒溪岸頭。',64,'全唐诗/poet.song.59000.json','["若耶溪邊天氣秋，採蓮女兒溪岸頭。", "笑隔荷花共人語，烟波渺渺蕩輕舟。", "數聲水調紅嬌晚，棹轉舟回笑人遠。", "腸斷誰家遊冶郎，盡日踟躕臨柳岸。"]'),
('2dcaa0b5-c1e0-4be6-8bbc-9563deb82541','烟中怨','秦觀','宋','宋诗','song-poetry','','[]','鑑湖樓閣與雲齊，樓上女兒名阿溪。',64,'全唐诗/poet.song.59000.json','["鑑湖樓閣與雲齊，樓上女兒名阿溪。", "十五能爲綺麗句，平生未解出幽閨。", "謝郎巧思詩裁剪，能使佳人動幽怨。", "瓊枝璧月結芳期，斗帳雙雙成眷戀。"]'),
('77209078-705b-4074-a168-3a1c80a65591','離魂記','秦觀','宋','宋诗','song-poetry','','[]','深閨女兒嬌復癡，春愁春恨那復知。',64,'全唐诗/poet.song.59000.json','["深閨女兒嬌復癡，春愁春恨那復知。", "舅兄唯有相拘意，暗想花心臨別時。", "離舟欲解春江暮，冉冉香魂逐君去。", "重來兩身復一身，夢覺春風話心素。"]'),
('4f9db7da-ad71-4bc8-9ec7-854004061f15','遣朝華','秦觀','宋','宋诗','song-poetry','','[]','夜霧茫茫曉柝悲，玉人揮手斷腸時。',32,'全唐诗/poet.song.59000.json','["夜霧茫茫曉柝悲，玉人揮手斷腸時。", "不須重向燈前泣，百歲終當一別離。"]'),
('9dd06364-7fb2-49d3-a30b-6aff77b29f53','再遣朝華','秦觀','宋','宋诗','song-poetry','','[]','玉人前去却重來，此度分携更不回。',32,'全唐诗/poet.song.59000.json','["玉人前去却重來，此度分携更不回。", "腸斷龜山離別處，夕陽孤塔自崔嵬。"]'),
('927b7d41-0e08-453c-94ac-0ddc1e6a53f0','閒燕堂聯句','秦觀','宋','宋诗','song-poetry','','[]','黄葉山頭初带雪，綠波尊酒暫回春。',64,'全唐诗/poet.song.59000.json','["黄葉山頭初带雪，綠波尊酒暫回春。", "已聞璧月瓊枝句，更看朝雲暮雨人。", "老醜紅妝翻曲妙，喜逢佳客放懷新。", "天明又出桃源去，仙境何時再問津。"]'),
('f6397233-1980-4640-a54f-54ea9244805e','納凉','秦觀','宋','宋诗','song-poetry','','["\u751f\u6d3b", "\u5199\u666f", "\u590f\u5929", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','携杖來追柳外凉，畫橋南畔倚胡床。',32,'全唐诗/poet.song.59000.json','["携杖來追柳外凉，畫橋南畔倚胡床。", "月明船笛參差起，風定池蓮自在香。"]'),
('3b2acf1a-57fb-44a2-811c-65ed00b04d70','東坡守杭','秦觀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十里荷花菡萏初，我公所至有西湖。',32,'全唐诗/poet.song.59000.json','["十里荷花菡萏初，我公所至有西湖。", "欲將公事湖中了，見說官閒事亦無。"]'),
('148a94a0-c527-4bfb-906a-1a427ca383b0','牽牛花','秦觀','宋','宋诗','song-poetry','','[]','銀漢初移漏欲殘，步虛人倚玉闌干。',32,'全唐诗/poet.song.59000.json','["銀漢初移漏欲殘，步虛人倚玉闌干。", "仙衣染得天邊碧，乞與人間向曉看。"]'),
('445248d3-dd52-4303-99fa-bf27d6313312','即席次君禮年兄韵','秦觀','宋','宋诗','song-poetry','','[]','情舒喜面山浮翠，袖滿薰風凉透時。',64,'全唐诗/poet.song.59000.json','["情舒喜面山浮翠，袖滿薰風凉透時。", "萍碎錦鱗金網舉，影差簾燕玉鈎垂。", "輕輕篆鼎凝香細，款款方壺轉漏遲。", "清興比來同約久，趣多深意古人詩。"]'),
('0465f159-aaf7-4245-9c67-bd4f2dddc824','醉眠亭','秦觀','宋','宋诗','song-poetry','','[]','醉來豐瘁同，眠去身世失。',48,'全唐诗/poet.song.59000.json','["醉來豐瘁同，眠去身世失。", "二樂擅一亭，夫子信超逸。", "杯行徂老春，肱枕頹昇日。", "壯志未及伸，幽願良自畢。"]'),
('c463a207-1abc-49c5-9b0e-a14d9114cdcc','遊杭州佛日水浄慧寺','秦觀','宋','宋诗','song-poetry','','[]','五里喬松徑，千年古道場。',24,'全唐诗/poet.song.59000.json','["五里喬松徑，千年古道場。", "泉聲與嵐影，收拾入僧房。"]'),
('3584af4c-9940-4311-ba9c-38b3e97198bf','觀音洞','秦觀','宋','宋诗','song-poetry','','[]','匹馬驕嘶石路斜，觀音洞口踏烟霞。',32,'全唐诗/poet.song.59000.json','["匹馬驕嘶石路斜，觀音洞口踏烟霞。", "普陀風景差相似，祇欠潮音小白花。"]'),
('95fc4735-829b-4a33-87bc-0c70fe8ddc71','光華寺','秦觀','宋','宋诗','song-poetry','','[]','霞通海天曙，月來東山白。',24,'全唐诗/poet.song.59000.json','["霞通海天曙，月來東山白。", "共是憑欄人，誰足當秋色。"]'),
('ff10b8b2-dba6-4515-b606-ba8c971f494a','玉井泉','秦觀','宋','宋诗','song-poetry','','[]','雲蒸崑山液，月浸藍田英。',24,'全唐诗/poet.song.59000.json','["雲蒸崑山液，月浸藍田英。", "臨風咽沆瀣，滿腹珠璣鳴。"]'),
('61d57b97-06b7-4c86-8000-754ef4dbc9f4','流杯橋','秦觀','宋','宋诗','song-poetry','','[]','曲水分山陰，輿梁勝溱洧。',24,'全唐诗/poet.song.59000.json','["曲水分山陰，輿梁勝溱洧。", "一詠見高風，駟馬安足取。"]'),
('f40b35ea-f9e1-4607-b0a8-5e81d25d1165','江月樓  其一','秦觀','宋','宋诗','song-poetry','','[]','仙翁看月三百秋，江波日去月不流。',32,'全唐诗/poet.song.59000.json','["仙翁看月三百秋，江波日去月不流。", "肯因炎塵暝空闊，直與江月同清幽。"]'),
('c461010c-1ca6-4170-bb4d-e7afd7a53bc5','江月樓  其二','秦觀','宋','宋诗','song-poetry','','[]','蒼梧雲氣眉山雨，玉簫三年無今古。',32,'全唐诗/poet.song.59000.json','["蒼梧雲氣眉山雨，玉簫三年無今古。", "九天雨露蟄蛟龍，琅玕長憑清虛府。"]'),
('8442e390-18c6-4de6-bbc6-6d2abae87247','墨竹','秦觀','宋','宋诗','song-poetry','','[]','墨君颯颯風雨鳴，垂鸞舞鳳翻青綬。',176,'全唐诗/poet.song.59000.json','["墨君颯颯風雨鳴，垂鸞舞鳳翻青綬。", "一竿珍重幾百緡，奚啻渭川三萬畝。", "金鏘玉戛空琴聲，婢行奴顔謝花柳。", "得亭真從寂寞間，卓古高標壓群醜。", "不須辨直致湘江，便覺滿窗凉意透。", "挺然葉節抱風孤，頓應君子虛心受。", "雷迸籜龍龍欲走，櫻笋紛紛徒適口。", "破除肉味若聞韶，王猷笑詠還依舊。", "藉檻湘陰凈簡書，接地春華幻塵垢。", "拂手筆端別有神，往來平安報良友。", "前時無偶後無繼，奇寶秘靈宜永久。"]'),
('47b60835-1183-477c-8b93-e9c622980ebe','白鶴觀','秦觀','宋','宋诗','song-poetry','','[]','複殿重樓墮杳冥，故基喬木尚崢嶸。',64,'全唐诗/poet.song.59000.json','["複殿重樓墮杳冥，故基喬木尚崢嶸。", "銀河不改三千尺，鐵馬曾經十萬兵。", "華表故應終化鶴，謫仙未解獨騎鯨。", "井泉一一兒童舊，白髮衰顔祇自驚。"]'),
('aa033e00-c98a-4ce8-b993-3151c25cdbaa','清溪逢故人','秦觀','宋','宋诗','song-poetry','','[]','共約來春會，牙檣發畫船。',48,'全唐诗/poet.song.59000.json','["共約來春會，牙檣發畫船。", "和風楊柳岸，微雨杏花天。", "故國應携手，前途共著鞭。", "吳兒看環佩，珠樹秀嬋娟。"]'),
('b34ae59f-f68e-4469-be43-3a5800403101','文英閣二首  其一','秦觀','宋','宋诗','song-poetry','','[]','都門將酒惜分携，歸路駸駸望欲迷。',64,'全唐诗/poet.song.59000.json','["都門將酒惜分携，歸路駸駸望欲迷。", "千里又看新燕語，一聲初聽子規啼。", "春風天上曾揮翰，遲日江邊獨杖藜。", "回首三山樓閣晚，斷雲流水自東去。"]'),
('ee5f933e-d94b-4b5c-beb0-cfa1ccac8012','文英閣二首  其二','秦觀','宋','宋诗','song-poetry','','[]','流落天涯思故園，散愁郊外任蹣跚。',64,'全唐诗/poet.song.59000.json','["流落天涯思故園，散愁郊外任蹣跚。", "雲歸邃谷知無雨，風卷寒溪沒近灘。", "已見雁將歸楚澤，遥知春又到長安。", "桑林壠麥依稀是，祇見秦川萬里寬。"]'),
('80b55ff7-e307-4bf6-a02f-80d2c0487a91','句  其一','秦觀','宋','宋诗','song-poetry','','[]','斷霞一抹海天低。',8,'全唐诗/poet.song.59000.json','["斷霞一抹海天低。"]'),
