('0707bc6d-7fae-4dfe-b7fd-ca5310b63627','存目  其一一','秦觀','宋','宋诗','song-poetry','','[]','詩題：蘇子瞻記江南所題詩本不全余嘗見之記其五絕今以補子瞻之遺首句：紅窗小泣低聲怨齎草露如郎倖薄琴詩斷續愁兼恨參橫霽色天沉水寒信風霜似葉黄。',69,'全唐诗/poet.song.59000.json','["詩題：蘇子瞻記江南所題詩本不全余嘗見之記其五絕今以補子瞻之遺首句：紅窗小泣低聲怨齎草露如郎倖薄琴詩斷續愁兼恨參橫霽色天沉水寒信風霜似葉黄。"]'),
('d8e701a4-37b9-4dbb-9613-f970af8d78e2','存目  其一二','秦觀','宋','宋诗','song-poetry','','[]','詩題：寄公闢首句：憶昔都門手一携。',17,'全唐诗/poet.song.59000.json','["詩題：寄公闢首句：憶昔都門手一携。"]'),
('af85adf5-4ec2-4dcd-be95-469180d39bb4','和鄧慎思詩呈同院諸公三首  其一','李公麟','宋','宋诗','song-poetry','','[]','苦學鄧夫子，仁風良可依。',48,'全唐诗/poet.song.59000.json','["苦學鄧夫子，仁風良可依。", "顔回樂也內，曾點詠而歸。", "盛德彌年劭，知音貴我稀。", "瀟湘逢此地，咳唾得明璣。"]'),
('b983282b-30e3-4faa-9490-aa5b2304dc4f','和鄧慎思詩呈同院諸公三首  其二','李公麟','宋','宋诗','song-poetry','','[]','瑠璃墨客堂，太乙助燈光。',48,'全唐诗/poet.song.59000.json','["瑠璃墨客堂，太乙助燈光。", "紬史探金柜，摛辭和柏梁。", "近傳江綵筆，遠緝漢珠囊。", "吏部文難可，猶稱萬丈長。"]'),
('f62db4aa-cf81-4988-822c-31b9a2c74fa2','和鄧慎思詩呈同院諸公三首  其三','李公麟','宋','宋诗','song-poetry','','[]','共校南宮藝，多年復此回。',48,'全唐诗/poet.song.59000.json','["共校南宮藝，多年復此回。", "羣賢主堂奧，一榻占廊隈。", "步屧朝追逐，詩筒夜往來。", "故人情不淺，無乃困慳才。"]'),
('be6e747a-ac0a-41df-9edb-502872e25fb5','和鄧慎思秋日同文館詩三首  其一','李公麟','宋','宋诗','song-poetry','','[]','鎖寂身如隠，幽清物向齊。',48,'全唐诗/poet.song.59000.json','["鎖寂身如隠，幽清物向齊。", "忘憂經露菊，蘇肺到霜梨。", "白髮知談笑，朱籤歷品題。", "賢書天下望，鵲喜遍深閨。"]'),
('3a7a49ef-9346-46e5-a719-3144a3deb0b7','和鄧慎思秋日同文館詩三首  其二','李公麟','宋','宋诗','song-poetry','','[]','呦呦鳴鹿野，皎皎白駒場。',48,'全唐诗/poet.song.59000.json','["呦呦鳴鹿野，皎皎白駒場。", "朋盍連茅茹，文程琢玉章。", "門通三級峻，桂露一年香。", "慶及飛龍旦，同歌庶事康。"]'),
('65e4e065-ca0c-4e60-b9d9-de1e5ce33213','和鄧慎思秋日同文館詩三首  其三','李公麟','宋','宋诗','song-poetry','','[]','寄棲容幕燕，覆節等醯雞。',48,'全唐诗/poet.song.59000.json','["寄棲容幕燕，覆節等醯雞。", "欲雨風多北，窮秋日易西。", "官書便夜讀，家報索親題。", "早晚驂騑入，重門坼印泥。"]'),
('a4f3c0a0-32c0-44d0-9a42-b3255a7ec874','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其一','李公麟','宋','宋诗','song-poetry','','[]','樹乾風索索，霜葉到書闈。',48,'全唐诗/poet.song.59000.json','["樹乾風索索，霜葉到書闈。", "枝並鷦鷯宿，床吟蟋蟀歸。", "幽人知坦履，游子念縫衣。", "暗喜還家近，承顔慰久違。"]'),
('27a96be9-8b2c-409e-bf90-e8e41aaf9e64','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其二','李公麟','宋','宋诗','song-poetry','','[]','莫以多爲贅，須知寸有長。',48,'全唐诗/poet.song.59000.json','["莫以多爲贅，須知寸有長。", "掄才何濟濟，顧我獨凉凉。", "雷雨龍皆起，江湖魚兩忘。", "攀依聊假手，賢立本無方。"]'),
('8b75a0a4-0e3a-45d1-aa91-f1cfae9dfd34','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其三','李公麟','宋','宋诗','song-poetry','','[]','今朝庭鵲喜，燈爲一花開。',48,'全唐诗/poet.song.59000.json','["今朝庭鵲喜，燈爲一花開。", "側指皂囊去，轉頭驄馬來。", "新橙家斫鱠，殘菊客浮杯。", "樂事連休日，須憑酒作媒。"]'),
('b3506b32-0dfa-4a49-aa37-a97854a52133','洋州','韓億','宋','宋诗','song-poetry','','[]','梁州鄰左右洋川，氣候融融別是天。',320,'全唐诗/poet.song.6000.json','["梁州鄰左右洋川，氣候融融別是天。", "地僻過冬稀見雁，箐深初夏已聞蟬。", "鄉風與蜀微相似，驛路見秦舊接連。", "駱谷轉山圍境內，漢江奔浪繞城邊。", "展開步障蘩花地，畫出棋枰早稻田。", "遠寺徑危攢迸筍，後園池冷軟飛泉。", "秋深滿院芭蕉雨，晚色臨軒薜荔煙。", "南浦採蒲當凜冽，西溪踏石向暄妍。", "夕陽道觀鳴鐘鼓，夜月人家奏管絃。", "楊柳影中沽酒市，芰荷香裏釣魚船。", "珍禽聽久名難辨，新果嘗餘味更全。", "野渡潮平分淺瀨，羣樓雲散露高巔。", "喧闐鼓吹迎神社，狼籍杯盤送客筵。", "慈竹清筠霜鬭膩，海棠堆艷火爭燃。", "蒼崖險峻應藏虎，碧洞陰深恐隠僊。", "妓女從游持翠蓋，士流尋勝擘香箋。", "戚姬廟宇青蕪沒，和相詩碑綠蘚沿。", "三縣俗淳宜靜理，兩衙事簡可閒眠。", "紛華度歲他鄉外，幽趣終朝在眼前。", "不爲近頒明詔下，及瓜情願滿三年。"]'),
('b13b1c85-f2e1-4e31-9b7a-ccd7e4288d2a','送僧歸護國寺','石中立','宋','宋诗','song-poetry','','[]','振錫來京輦，薰蘭近賜衣。',48,'全唐诗/poet.song.6000.json','["振錫來京輦，薰蘭近賜衣。", "種蓮曾結社，指栢迥投機。", "舊寺千巖隔，歸艎片席飛。", "禪心天海外，永夕望台輝。"]'),
('a04dde82-776f-4bd7-ac78-54d73d6fb2f3','句','石中立','宋','宋诗','song-poetry','','[]','尋常不召猶相造，況是今朝得指揮。',16,'全唐诗/poet.song.6000.json','["尋常不召猶相造，況是今朝得指揮。"]'),
('fa5fe8e3-049d-4f2c-bb87-5ea29375f619','野外即事','吳濟','宋','宋诗','song-poetry','','[]','橫木渡前溪，藤深路欲迷。',48,'全唐诗/poet.song.6000.json','["橫木渡前溪，藤深路欲迷。", "瘦筇諳亂石，老屐带新泥。", "盡日綠陰合，有時黄鳥啼。", "多情雙蛺蝶，飛傍帽簷低。"]'),
('8ae8ed0e-248b-4d59-b515-9d62280f27af','欄邊','吳濟','宋','宋诗','song-poetry','','[]','潮信欄邊見，人家樹杪分。',48,'全唐诗/poet.song.6000.json','["潮信欄邊見，人家樹杪分。", "筍鞭遮過蟻，蛛網礙飛蚊。", "松古藏靈藥，山高落冷雲。", "吾廬遠城市，花草故欣欣。"]'),
('23657fad-3672-4211-adfb-2d2f90cedc42','鮑家田','吳濟','宋','宋诗','song-poetry','','[]','摇旆家家酒，收犂處處村。',48,'全唐诗/poet.song.6000.json','["摇旆家家酒，收犂處處村。", "草深迷井口，槿密擁籬根。", "綠水明秧本，青山失燒痕。", "多應忌蠶事，畏客掩柴門。"]'),
('766ff500-c6d1-4982-9447-36bddba4db2b','秋興','吳濟','宋','宋诗','song-poetry','','[]','傷秋愁不斷，鄰杵已鳴霜。',48,'全唐诗/poet.song.6000.json','["傷秋愁不斷，鄰杵已鳴霜。", "寶扇鸞收影，篘蟻带香疏。", "花停懶蝶細，草庇寒螿蟲。", "落葉無人掃，庭空下夕陽。"]'),
('92da4401-c8f1-4f99-b1f6-80413846e77b','題甘露寺','吳濟','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','雲闕漏微照，長江得半明。',48,'全唐诗/poet.song.6000.json','["雲闕漏微照，長江得半明。", "心隨帆影遠，鷗似我身輕。", "今古幾興廢，山川無變更。", "倚欄吟未斷，拍拍又潮生。"]'),
('30323225-cd70-4ce0-9313-2272b96408d2','亞字謎','陳亞','宋','宋诗','song-poetry','','[]','若教有口便啞，且要無心爲惡。',28,'全唐诗/poet.song.6000.json','["若教有口便啞，且要無心爲惡。", "中間全沒肚腸，外面强生稜角。"]'),
('11d34e6f-b51c-440b-85f3-8775c5387bd6','藥名詩','陳亞','宋','宋诗','song-poetry','','[]','地居京界足親知，倩借尋常無歇時。',32,'全唐诗/poet.song.6000.json','["地居京界足親知，倩借尋常無歇時。", "但看車前牛領上，十家皮沒五家皮。"]'),
('fc354c80-369d-40bd-b940-78ad26c46453','戒子孫詩','陳亞','宋','宋诗','song-poetry','','[]','滿室圖書雜典墳，華亭仙客岱雲根。',32,'全唐诗/poet.song.6000.json','["滿室圖書雜典墳，華亭仙客岱雲根。", "他年若不和花賣，便是吾家好子孫。"]'),
('82a3a4a9-6a9b-4347-a371-da295ddeb5a8','登湖州銷暑樓','陳亞','宋','宋诗','song-poetry','','[]','重樓肆登賞，豈羨石爲廊。',48,'全唐诗/poet.song.6000.json','["重樓肆登賞，豈羨石爲廊。", "風月前湖近，軒窗半夏凉。", "罾青識漁浦，芝紫認仙鄉。", "却恐當歸闕，靈臺爲別傷。"]'),
('02bc708d-a753-4b47-ba61-b2655b13f246','惜竹','陳亞','宋','宋诗','song-poetry','','[]','出檻亦不翦，從教長舊叢。',24,'全唐诗/poet.song.6000.json','["出檻亦不翦，從教長舊叢。", "年年到朱夏，葉葉是清風。"]'),
('fbdcbbc2-e1b9-466d-9a85-85bd9a226532','和魏周輔','陳亞','宋','宋诗','song-poetry','','[]','昔賢自是堪加罪，非敢言君愛竊詩。',32,'全唐诗/poet.song.6000.json','["昔賢自是堪加罪，非敢言君愛竊詩。", "尀耐古人多意智，預先偷子一聯詩。"]'),
('e99581b2-811e-41d1-968b-9afbaec0b218','戲答楊球','陳亞','宋','宋诗','song-poetry','','[]','蒙君遺長牋，語意如何說。',24,'全唐诗/poet.song.6000.json','["蒙君遺長牋，語意如何說。", "請看身上衣，裩中本無蝎。"]'),
('9d484c0d-3e83-4dd8-ab46-7dff0156a591','嗤人面黑','陳亞','宋','宋诗','song-poetry','','[]','笑似烏梅裂，啼如豉汁流。',24,'全唐诗/poet.song.6000.json','["笑似烏梅裂，啼如豉汁流。", "眉間粘帖子，已上是幞頭。"]'),
('1688bcd6-a319-4f8a-a256-5264cb044322','懷舊隠','陳亞','宋','宋诗','song-poetry','','[]','多媿當年未第間，卜居人外得清閑。',64,'全唐诗/poet.song.6000.json','["多媿當年未第間，卜居人外得清閑。", "排聯花品曾非僭，愛惜苔錢不是慳。", "秋閣詩情天淡淡，夕溪漁思月彎彎。", "而今慚厚明朝祿，敢念藏愚莫買山。"]'),
('6e1dc534-b023-406b-b612-f3e0f4c79205','詩一首','陳亞','宋','宋诗','song-poetry','','[]','張公喫酒李公醉，自古人言信有之。',32,'全唐诗/poet.song.6000.json','["張公喫酒李公醉，自古人言信有之。", "陳亞今年新及第，滿城人賀李衙推。"]'),
('f6e4a2d8-d7f5-4632-9bb5-ba0e3d785940','句  其一','陳亞','宋','宋诗','song-poetry','','[]','若是道人頭不白，老人當日合烏頭。',16,'全唐诗/poet.song.6000.json','["若是道人頭不白，老人當日合烏頭。"]'),
('4b53e9c3-bc92-432c-8865-e336fd9ef838','句  其二','陳亞','宋','宋诗','song-poetry','','[]','棋怕臘寒呵子下，衣嫌春暖縮紗裁。',16,'全唐诗/poet.song.6000.json','["棋怕臘寒呵子下，衣嫌春暖縮紗裁。"]'),
('dcc6d241-f769-4224-9a45-ef7b5c4855c9','句  其三','陳亞','宋','宋诗','song-poetry','','[]','布袍袖里懷漫刺，到處遷延胡索人。',16,'全唐诗/poet.song.6000.json','["布袍袖里懷漫刺，到處遷延胡索人。"]'),
('8cfae7f4-470d-4699-bcbd-6447da3b610c','句  其四','陳亞','宋','宋诗','song-poetry','','[]','馬嘶曾到寺，犬吠乍行村。',12,'全唐诗/poet.song.6000.json','["馬嘶曾到寺，犬吠乍行村。"]'),
('bc7fc046-f888-4725-9b52-8ed859ed0bd7','句  其五','陳亞','宋','宋诗','song-poetry','','[]','收寒歸地底，表老向人間。',12,'全唐诗/poet.song.6000.json','["收寒歸地底，表老向人間。"]'),
('6e81fbac-bbcf-4053-b796-3064543410fe','句  其六','陳亞','宋','宋诗','song-poetry','','[]','吏辭如賀日，民送似迎時。',12,'全唐诗/poet.song.6000.json','["吏辭如賀日，民送似迎時。"]'),
('22859693-d597-45f1-9413-cf853531c4b2','句  其七','陳亞','宋','宋诗','song-poetry','','[]','無雨若還過半夏，和師曬作葫蘆巴。',16,'全唐诗/poet.song.6000.json','["無雨若還過半夏，和師曬作葫蘆巴。"]'),
('47303e5a-26d2-4386-94f7-d63db91333ec','句  其八','陳亞','宋','宋诗','song-poetry','','[]','如僧清早厨邊過，偷却黄興料裏蹄。',16,'全唐诗/poet.song.6000.json','["如僧清早厨邊過，偷却黄興料裏蹄。"]'),
('2e48a0e7-f42a-48df-88cf-369ed3ed5209','句  其九','陳亞','宋','宋诗','song-poetry','','[]','蔡襄無口便成衰。',8,'全唐诗/poet.song.6000.json','["蔡襄無口便成衰。"]'),
('ed114ad7-b5e3-404d-a314-0cd685ed165b','句  其一○','陳亞','宋','宋诗','song-poetry','','[]','浪平山接影，山盡樹回根。',12,'全唐诗/poet.song.6000.json','["浪平山接影，山盡樹回根。"]'),
('5578ac82-284d-4fef-a5a5-ce90b28cc151','句','段全','宋','宋诗','song-poetry','','[]','斜搊花脚面，闊大打廉搋。',12,'全唐诗/poet.song.6000.json','["斜搊花脚面，闊大打廉搋。"]'),
('d136359b-3957-4ee6-bb57-bf06a747328e','句','周世昌','宋','宋诗','song-poetry','','[]','畫鼓雷奔天不雨，綵旗雲聳地生風。',16,'全唐诗/poet.song.6000.json','["畫鼓雷奔天不雨，綵旗雲聳地生風。"]'),
('cd5df7eb-3815-4329-bad1-d790e54e872a','休沐端居有懷希聖少卿學士','陳越','宋','宋诗','song-poetry','','[]','玉甃銀床蔭碧桐，北窗珍簟水紋融。',64,'全唐诗/poet.song.6000.json','["玉甃銀床蔭碧桐，北窗珍簟水紋融。", "衣裁練布如王導，扇執蒲葵學謝公。", "瓊屑半和仙掌露，蘭苕輕泛楚臺風。", "若非冰雪神仙骨，相樂誰同一笑中。"]'),
('05f3ee3e-4fb2-4a4b-bfb1-4d142aa7f517','送張無夢歸天台','陳越','宋','宋诗','song-poetry','','[]','紫籍仙階貴，丹丘隠路深。',48,'全唐诗/poet.song.6000.json','["紫籍仙階貴，丹丘隠路深。", "五圖傳祕訣，三祝契堯心。", "瓢飲和瓊蕊，樓居接桂陰。", "宸歌旌有道，垂象賁中林。"]'),
