('863502d1-e1ad-4e88-874b-e75f71b043ee','吳中送僧','唐肅','宋','宋诗','song-poetry','','["\u592a\u6e56"]','師向何方去，太湖西復西。',48,'全唐诗/poet.song.6000.json','["師向何方去，太湖西復西。", "風傳孤磬遠，松偃舊房低。", "暖榻常留兔，浮杯不駁犀。", "何時城北寺，重聽木鷄啼。"]'),
('c097859e-b1c4-4b6d-824f-706766a04de8','季子挂劍歌','唐肅','宋','宋诗','song-poetry','','[]','季子讓一國，視之敝屣然。',56,'全唐诗/poet.song.6000.json','["季子讓一國，視之敝屣然。", "寧當寶一劍，不爲徐君懸。", "徐君雖亡骨未朽，劍挂墳前白楊柳。", "君知不知不足悲，我心許君終不移。"]'),
('b758da0a-157d-42c7-9481-16692afe6476','臨終作','王隨','宋','宋诗','song-poetry','','[]','畫堂燈已滅，彈指向誰說。',24,'全唐诗/poet.song.6000.json','["畫堂燈已滅，彈指向誰說。", "去住本尋常，春風掃殘雪。"]'),
('c628577e-97f0-441c-a4e0-5c0bc97a9d23','送餘姚知縣張太博','王隨','宋','宋诗','song-poetry','','[]','才名登仕路，芝綍奉龍光。',96,'全唐诗/poet.song.6000.json','["才名登仕路，芝綍奉龍光。", "出宰神仙邑，吟辭鵷鷺行。", "烟波迎去棹，圖籍富行裝。", "淮月蒹葭影，江風橘柚香。", "新詩留禹穴，舊理過錢塘。", "市井魚鹽聚，亭臺水石凉。", "雲山接秦望，花木勝河陽。", "暫布惠和政，即看鵬翼翔。"]'),
('93c8e322-5f55-4119-ade6-ae4477c8ec58','送妙明規長老','王隨','宋','宋诗','song-poetry','','[]','振衣辭帝里，歸路指禪林。',48,'全唐诗/poet.song.6000.json','["振衣辭帝里，歸路指禪林。", "勝地江山寺，澄明水月心。", "卸帆烟浦近，鳴磬夜船深。", "到喜清凉境，門開松桂陰。"]'),
('360e6470-259d-4a3f-af38-efefb05d69d0','憶越州  其一','王隨','宋','宋诗','song-poetry','','[]','賀監賜湖名價高，雲山吟賞抽江毫。',32,'全唐诗/poet.song.6000.json','["賀監賜湖名價高，雲山吟賞抽江毫。", "澄波杳渺醉欲去，烟光水月留歸舠。"]'),
('efb26269-efad-4eb8-8654-303366072875','憶越州  其二','王隨','宋','宋诗','song-poetry','','[]','越上湖山何絕奇，昔聞尋勝寧遐遺。',32,'全唐诗/poet.song.6000.json','["越上湖山何絕奇，昔聞尋勝寧遐遺。", "烟波無憶舊吟醉，方是致君堯舜時。"]'),
('2e208802-faf4-4cc7-b666-293058cdd0d7','棲霞寺  其一','王隨','宋','宋诗','song-poetry','','[]','翠巘聳層雲，珍祠古迹存。',48,'全唐诗/poet.song.6000.json','["翠巘聳層雲，珍祠古迹存。", "獲登千佛嶺，仰荷九天恩。", "塔影凌虛閣，鐘聲度遠村。", "僧言前太守，罕有到松門。"]'),
('5c51c786-a6d2-4490-8601-1cb5ba971680','棲霞寺  其二','王隨','宋','宋诗','song-poetry','','[]','虛窗殘燭明，欹枕旅懷清。',48,'全唐诗/poet.song.6000.json','["虛窗殘燭明，欹枕旅懷清。", "永夜起松籟，蒲山疑雨聲。", "吟餘閑景象，道勝小榮名。", "鐘罷星河曙，悠悠迴旆旌。"]'),
('b852c0b3-842e-446f-bca8-20fdfdce1177','寄張明真','王隨','宋','宋诗','song-poetry','','[]','紺髮丹顔氣粹和，大茅峰畔隠雲蘿。',64,'全唐诗/poet.song.6000.json','["紺髮丹顔氣粹和，大茅峰畔隠雲蘿。", "至人朝斗傳靈訣，先帝觀龍賜御歌。", "町疃瑞文眠徑草，蜿蜒神物戲池波。", "自慚五馬來塵外，一挹仙風幸已多。"]'),
('3f3a2f97-4d11-4e18-8f1f-869dfb4c38ac','天開巖','王隨','宋','宋诗','song-poetry','','[]','棲霞山後峰，天開一巖秀。',48,'全唐诗/poet.song.6000.json','["棲霞山後峰，天開一巖秀。", "中有坐禪人，形容竹栢瘦。", "饑餐巖下松，渴飲巖上溜。", "愛步巖室前，白雲起孤岫。"]'),
('14c68593-fe2e-44fc-921f-52cbf91b653a','玉兔寺  其一','王隨','宋','宋诗','song-poetry','','[]','霜毫感應早呈祥，誰布黄金建寶坊。',32,'全唐诗/poet.song.6000.json','["霜毫感應早呈祥，誰布黄金建寶坊。", "古殿幡花遶真聖，美名靈跡異諸方。"]'),
