('dd4a1ea1-54da-41c1-9f8c-f253a22b92bf','存目  其四','王隨','宋','宋诗','song-poetry','','[]','附注：已錄王曙詩。',9,'全唐诗/poet.song.6000.json','["附注：已錄王曙詩。"]'),
('e2007dd5-edec-4f49-92e4-39f48344db54','宿靈巖寺','李冠','宋','宋诗','song-poetry','','[]','疊翠圍僧國，幽棲孰有才。',48,'全唐诗/poet.song.6000.json','["疊翠圍僧國，幽棲孰有才。", "名高仍可隠，骨俗豈宜來。", "花發松香沒，雲銷石色迴。", "何年脫身去，心委像前灰。"]'),
('fbabd127-434f-41df-adc3-cd2e6dfc43b4','寄王樵','李冠','宋','宋诗','song-poetry','','[]','霜臺御史新爲郡，棘手廷評繼下車。',32,'全唐诗/poet.song.6000.json','["霜臺御史新爲郡，棘手廷評繼下車。", "首謁梓桐王處士，教風從此重詩書。"]'),
('ac37da3d-9f79-47e8-aeed-dc4244863553','句','孫頎','宋','宋诗','song-poetry','','[]','星分紀軫三湘尾，萬頃湖邊舊晉都。',16,'全唐诗/poet.song.6000.json','["星分紀軫三湘尾，萬頃湖邊舊晉都。"]'),
('44bf456f-acc5-4db0-a3df-95eda47374ad','均慶寺','季咸','宋','宋诗','song-poetry','','[]','一方靈跡兩峰間，左右芒山與碭山。',64,'全唐诗/poet.song.6000.json','["一方靈跡兩峰間，左右芒山與碭山。", "勝地昔曾鍾王氣，高僧誰此掩禪關。", "翬飛巍殿烟瓴碧，翠削層崖苔蘚斑。", "千古英雄無處問，嶺頭依舊白雲閑。"]'),
('60db0490-2643-47ef-b3ec-9b05dc47b419','句','王貽永','宋','宋诗','song-poetry','','[]','河朔雪深思愛月，并門春暖詠甘棠。',16,'全唐诗/poet.song.6000.json','["河朔雪深思愛月，并門春暖詠甘棠。"]'),
('c54af826-919d-4149-85f2-a4e78e3dbf5e','奉和御製社日詩','楊億','宋','宋诗','song-poetry','','[]','仙掌凌空沆瀣秋，大田多稼似雲浮。',64,'全唐诗/poet.song.6000.json','["仙掌凌空沆瀣秋，大田多稼似雲浮。", "天邊霽景芙蓉闕，江上殘芳杜若洲。", "東觀羣儒宣宴樂，南荆遺俗重嬉遊。", "宸章忽降容瞻睹，疑是神龜負九疇。"]'),
('a0c39b6f-6a31-4938-af6b-df8d8377de76','奉和御製重陽五七言詩  其一','楊億','宋','宋诗','song-poetry','','[]','宸居瑞靄重，閶闔正來風。',48,'全唐诗/poet.song.6000.json','["宸居瑞靄重，閶闔正來風。", "憀慄驚秋氣，豐穰美歲功。", "曉煙籬菊嫩，霄露畹蘭紅。", "重九登高會，歡娛處處同。"]'),
('df27a8ef-60fc-4a17-94c8-d2a879492d0e','奉和御製重陽五七言詩  其二','楊億','宋','宋诗','song-poetry','','[]','民在華胥正樂康，高秋賓雁指衡陽。',64,'全唐诗/poet.song.6000.json','["民在華胥正樂康，高秋賓雁指衡陽。", "蒹葭漸見凝清露，鶗鴂先驚歇衆芳。", "節值登高真勝會，年逢大有是殊祥。", "宸心悦豫流新唱，星漢垂文示八方。"]'),
('d532bd50-a470-416e-8646-9c3c376c88dd','奉和聖製南郊禮畢五言六韻詩','楊億','宋','宋诗','song-poetry','','[]','燔柴就陽位，煙燎達高穹。',72,'全唐诗/poet.song.6000.json','["燔柴就陽位，煙燎達高穹。", "掃地鉶㽅潔，嚴更鼓角雄。", "天心侔兑悦，皇澤比春融。", "帝享惟馨德，民蘇解愠風。", "周郊四祭重，漢畤五祠同。", "靈貺昭玄感，神光望拜中。"]'),
('340048f8-b1a2-49b0-be67-bab4be11ffdf','奉和御製契丹出境將議迴鑾五言六韻詩','楊億','宋','宋诗','song-poetry','','[]','戎輅巡河右，天威讋鬼方。',72,'全唐诗/poet.song.6000.json','["戎輅巡河右，天威讋鬼方。", "五營開細柳，三令凛飛霜。", "氛祲消千里，聲名耀八荒。", "靈旗風助順，黄道日呈祥。", "偃革邊關靜，迴鑾海縣康。", "欣陪從臣末，歸蹕奉高驤。"]'),
('29bc0cc2-38a3-4669-9623-c12181edc87c','奉和御製南郊七言六韻詩','楊億','宋','宋诗','song-poetry','','[]','潔齋恭己奉蒼旻，報本圜壇備物陳。',96,'全唐诗/poet.song.6000.json','["潔齋恭己奉蒼旻，報本圜壇備物陳。", "酒縮楚茅三獻畢，灰飛嶰管一陽新。", "高空瑞氣長隨輦，永夕清霜暗濕巾。", "泰畤迎年嚴漢祀，六宗祈福盛虞禋。", "鴻恩渙汗霑窮髮，睿藻昭回動紫宸。", "庶彙熙熙蒙帝力，徒知擊壤傚堯民。"]'),
('20aa3f05-68c7-472b-8ef9-653351cf1035','奉和御製喜降時雪七言四韻詩','楊億','宋','宋诗','song-poetry','','[]','一夕香街布玉塵，檀欒勁節露貞筠。',64,'全唐诗/poet.song.6000.json','["一夕香街布玉塵，檀欒勁節露貞筠。", "兔園置酒皇歡洽，柏殿賡歌睿唱新。", "麥秀原田初望歲，花開苑樹忽驚春。", "豐穰薦瑞民心悦，高下還隨帝澤均。"]'),
('cec76e32-c58e-4350-b272-17f5c3c3f9dd','後苑賞花應制','楊億','宋','宋诗','song-poetry','','[]','宫花如錦水連漪，翠輦尋芳正是時。',64,'全唐诗/poet.song.6000.json','["宫花如錦水連漪，翠輦尋芳正是時。", "禁苑定知人未識，朱欄除有蝶偷窺。", "艶烘曉日迷天仗，香逐輕風落酒巵。", "何幸微臣陪鎬宴，蓬壺春漏正遲遲。"]'),
('2bdceaa6-2d69-4a44-a08c-8522e4168b77','應制賦射弓詩','楊億','宋','宋诗','song-poetry','','[]','水漲方塘綠，花開禁籞紅。',72,'全唐诗/poet.song.6000.json','["水漲方塘綠，花開禁籞紅。", "同瞻萬乘主，親御六鈞弓。", "曲應騶虞節，春迴太皥功。", "還須殪大兕，何只落驚鴻。", "一箭天山定，三邊虎穴空。", "潯陽射蛟者，寧與此時同。"]'),
('c21f88bd-2be4-4245-b64e-5b48d0154c40','後苑賞花應制','楊億','宋','宋诗','song-poetry','','[]','雲羅霞綺媚芳辰，瓊圃花開爛漫春。',64,'全唐诗/poet.song.6000.json','["雲羅霞綺媚芳辰，瓊圃花開爛漫春。", "風遞清香隨鳳輦，波涵倒影落龍津。", "仙葩四照烘初日，濃艶千苞賜近臣。", "向晚天街戴歸處，遊蜂舞蝶自隨人。"]'),
('f90dc08d-6018-43e6-b537-fd2e43a2746a','宣召赴龍圖閣觀太宗御書應制','楊億','宋','宋诗','song-poetry','','[]','非煙葱蔚蒼龍闕，紫府深沉大帝居。',64,'全唐诗/poet.song.6000.json','["非煙葱蔚蒼龍闕，紫府深沉大帝居。", "羣玉中天開策府，神龜温洛薦圖書。", "珠宫岑寂經行處，金簡熒煌拭目初。", "曾是先朝受恩者，因探禹穴涕漣如。"]'),
('2914aabb-3e57-4358-a77a-99f37c1e9fd9','後苑賞花釣魚應制','楊億','宋','宋诗','song-poetry','','[]','宜春小苑斗城旁，錫宴羣仙奉紫皇。',64,'全唐诗/poet.song.6000.json','["宜春小苑斗城旁，錫宴羣仙奉紫皇。", "漢沼乳魚偏傍釣，青陵舞蝶自尋芳。", "波平鼇背浮崑閬，日轉金莖艶赭黄。", "滿酌流霞侍臣醉，暖風宫蘂雜爐香。"]'),
('f7ed3ab5-c748-4417-8332-7940be780e09','别賦賞花一首','楊億','宋','宋诗','song-poetry','','[]','仙山靈沼五城西，曉日花光照彩霓。',64,'全唐诗/poet.song.6000.json','["仙山靈沼五城西，曉日花光照彩霓。", "露濯冰蠶鋪瑞錦，風吹水麝拆香臍。", "芳葩散採添蜂蜜，紅片狂飄雜燕泥。", "曾識壺中舊春色，桃源重到路猶迷。"]'),
('0dc5e922-f77c-4ed7-b401-275ef01d5e7e','龍圖閣會宴應制','楊億','宋','宋诗','song-poetry','','[]','册府藏書在紫微，退朝稽古助論思。',64,'全唐诗/poet.song.6000.json','["册府藏書在紫微，退朝稽古助論思。", "中天召宴衢樽滿，乙夜觀文列象垂。", "綵鳯翩翻巢綺閣，靈龜夭矯冠金碑。", "大風發唱羣臣和，元首康哉庶績熙。"]'),
('e08a72d5-1257-4029-8825-476f9ede2e57','秘閣賜讌送右諫議大夫种放得假歸終南山應制','楊億','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','瑣闈聊輟皂囊封，賜告歸尋一畝宫。',64,'全唐诗/poet.song.6000.json','["瑣闈聊輟皂囊封，賜告歸尋一畝宫。", "關路蒲輪千里遠，巖扉蕙帳幾年空。", "百壺天酒凝甘露，二雅宸章掩大風。", "舊隱暫還非久住，心期獻可沃堯聰。"]'),
('79eaf36a-90c2-4463-bafb-749650459bff','初至郡齋書事','楊億','宋','宋诗','song-poetry','','[]','地去京華遠，年逢旱暵餘。',120,'全唐诗/poet.song.6000.json','["地去京華遠，年逢旱暵餘。", "羣胥同黠馬，比戶甚枯魚。", "煦嫗心空切，澄清志莫舒。", "棼絲殊未治，錯節詎能除。", "聽訟棠陰密，行春柳影疏。", "賓筵求婉畫，僧舍問真如。", "踰月窺除目，經時絕傳車。", "素餐徒自飽，投刃豈曾虚。", "盈耳嫌敲扑，堆牀厭簿書。", "故園無數舍，長日歎歸歟。"]'),
('e54c95cb-5e14-47d2-9fea-9191c015046d','次韻和十六兄先輩見寄','楊億','宋','宋诗','song-poetry','','[]','秋風苦憶鱠霜鱗，暫剖銅符出紫宸。',128,'全唐诗/poet.song.6000.json','["秋風苦憶鱠霜鱗，暫剖銅符出紫宸。", "一路雪寒多挾纊，幾程山險欲摧輪。", "清香撲鼻梅林近，秀色凝眸麥壠新。", "閉閣草玄終寂寞，下車爲政尚因循。", "尋僧不厭攜笻遠，愛客寧辭舉白頻。", "簿領孜孜防黠吏，邱園矻矻訪通民。", "魚鹽自與滄溟接，雞犬仍將白社鄰。", "官滿會須抛印綬，武夷歸去作閑人。"]'),
('cb5e7842-2bac-4ec3-a239-fb06c87b327a','次韻和章子美對雪','楊億','宋','宋诗','song-poetry','','[]','破臘連空粉絮飄，離離一番長山苗。',64,'全唐诗/poet.song.6000.json','["破臘連空粉絮飄，離離一番長山苗。", "旗亭誰氏來沽酒，臺笠何人去採樵。", "背日旋依松澗積，迎風先傍藥畦消。", "袁安此際偏無賴，獨掩閑門對一瓢。"]'),
('6c95702f-662b-4a9e-aaf0-2e4d17dbe14b','送章頔歸鄉','楊億','宋','宋诗','song-poetry','','[]','蕪穢休嗟負郭田，蹉跎自過鹿鳴筵。',128,'全唐诗/poet.song.6000.json','["蕪穢休嗟負郭田，蹉跎自過鹿鳴筵。", "荆山玉璞空三獻，梁苑風塵已十年。", "疏入禁中猶未報，賦成都下早曾傳。", "獨攜書劍歸閩嶺，共泛煙波入楚天。", "獵獵酒旗邀舉白，招招漁艇勸烹鮮。", "棋枰鬭勝疑成癖，砧杵驚愁幾廢眠。", "驛路數程煩託乘，郡齋終日喜談玄。", "如何弃我還家去，相送津亭一黯然。"]'),
('73be8205-0e30-4609-a3fe-3a624afbdd80','郡齋即事書懷十二韻呈諸官','楊億','宋','宋诗','song-poetry','','[]','長樂疏鐘自厭聞，漢庭誰不惜離羣。',192,'全唐诗/poet.song.6000.json','["長樂疏鐘自厭聞，漢庭誰不惜離羣。", "舟浮一水波瀾闊，路入千山杳靄分。", "郡閣先憂迷簿領，村田聊得問耕耘。", "疲民深喜猶安堵，黠吏那知便舞文。", "照膽求瑕空察察，飲冰爲政漫云云。", "玄臺已分嘲揚子，桑野須防誚使君。", "别派東傾連漲海，故園西望隔晴氛。", "黛鋪遠岫秋將晚，綺散餘霞日欲曛。", "小檻報春梅爛漫，滿空呈瑞雪繽紛。", "題詩到處尋紅葉，置酒終朝看白雲。", "符竹偶分慚出守，櫜鞬暫佩愧從軍。", "石渠舊署頻牽夢，室有芝蘭閣有芸。"]'),
('d971e421-277d-416f-9c69-2c4522d54223','郡齋西亭即事十韻招麗水殿丞武功從事','楊億','宋','宋诗','song-poetry','','[]','郡齋退食復何爲，縱目西亭景物奇。',160,'全唐诗/poet.song.6000.json','["郡齋退食復何爲，縱目西亭景物奇。", "疊嶂雨餘泉眼出，澄潭風靜釣絲垂。", "城臨古戍寒蕪闊，路轉荒村野彴危。", "幾處唱歌聞白紵，誰家酤酒見青旗。", "蝶隨游妓穿花徑，犬吠行人隔槿籬。", "桃李成蹊春盡後，魚鹽爲市日中時。", "桑麻萬頃晴氛散，絲竹千門夕照移。", "吟際嶺雲飛冉冉，望中壠麥秀離離。", "煙迷喬木鶯遷早，水滿芳塘鷺下遲。", "鶴蓋翩然肯相顧，主人終宴豈知疲。"]'),
('61ffbc5c-4f3c-4857-b04c-a9f4813f7dc2','送張彝憲歸鄉','楊億','宋','宋诗','song-poetry','','[]','處處春波滿稻畦，海棠零落子規啼。',64,'全唐诗/poet.song.6000.json','["處處春波滿稻畦，海棠零落子規啼。", "一麾遠郡方留滯，十里長亭又解攜。", "後夜灘聲妨客夢，初晴雲物入詩題。", "到家爲問田園事，桃李猶應有舊蹊。"]'),
('0e4be7ce-8d42-48a6-9c20-470cbff967fd','送韓永錫歸闕','楊億','宋','宋诗','song-poetry','','[]','縉雲六載掌關征，學得陽冰小篆成。',64,'全唐诗/poet.song.6000.json','["縉雲六載掌關征，學得陽冰小篆成。", "逋客幾人曾識面，仙山到處便題名。", "桑郊又是乘軺去，鈴閣虚煩解榻迎。", "舊讀春秋究微旨，何須苦說不知兵。"]'),
('64abf99c-e6ea-4edc-a57e-9c74697aa858','次韻和致仕李殿丞寅見寄之什因以紀贈','楊億','宋','宋诗','song-poetry','','[]','鄉國馳名幾十春，鳴臯一旦九天聞。',160,'全唐诗/poet.song.6000.json','["鄉國馳名幾十春，鳴臯一旦九天聞。", "翔鸞棲棘曾爲吏，金鼎調梅未致君。", "百里象雷嫌碌碌，片言折獄厭云云。", "詩名已是齊康樂，筆力何曾减右軍。", "抗表忽然干鳳扆，拂衣殊欲謝人羣。", "都緣梁苑慵爲賦，且免鍾山被勒文。", "清夜獨吟牛渚月，高秋時望帝鄉雲。", "鯉庭禀訓門逾盛，蘭畹傳芳氣益薫。", "盡室遠依洪井側，直鈎猶釣楚江濆。", "西山有藥應須餌，待看蜺旌入紫氛。"]'),
('691d36bc-3bc5-46ea-9aad-37d021fe2fdd','京師故人有以隴西鸚鵡遺予者因畜養之去年出守縉雲提挈而至性靈甚慧觸類能言公退翫之常若不足忽遇疾而逝因命瘞於小園作詩一章聊以追悼識者無罪予以貴畜也','楊億','宋','宋诗','song-poetry','','[]','隴山秋樹舊巢傾，遠向江東逐斾旌。',96,'全唐诗/poet.song.6000.json','["隴山秋樹舊巢傾，遠向江東逐斾旌。", "去國夢魂應繚繞，入春喉舌漸分明。", "一聲警露何慚鶴，百囀遷喬肯讓鶯。", "終日雕籠心不戀，經年丹觜色猶輕。", "思歸悒悒因成疾，顧主依依尚有情。", "死葬小園芳草地，夜來經雨綠苔生。"]'),
('93fee7e3-6867-4bed-ada1-312559888bd9','麗水甄殿丞移疾請告','楊億','宋','宋诗','song-poetry','','[]','數日不逢黄叔度，胸中鄙吝一時生。',64,'全唐诗/poet.song.6000.json','["數日不逢黄叔度，胸中鄙吝一時生。", "如何民瘼偏能療，却是詩魔未得平。", "夏景清和妨命駕，玄臺寂寞阻飛觥。", "欲親高論無由得，須作文殊問疾行。"]'),
('3f2e3405-a892-4162-824e-1e07bc185854','威上人','楊億','宋','宋诗','song-poetry','','[]','五藴已空諸漏盡，冢間行道十年餘。',64,'全唐诗/poet.song.6000.json','["五藴已空諸漏盡，冢間行道十年餘。", "吟成南國碧雲句，讀徧西方貝葉書。", "清論彌天居士伏，高情出世俗流疏。", "問師心法都無語，笑指孤雲在太虚。"]'),
('57eabaeb-579b-4d42-8467-9edb71c8a0c7','次韻和係郡齋書事之什','楊億','宋','宋诗','song-poetry','','[]','竹使貪爲郡，金門懶上書。',120,'全唐诗/poet.song.6000.json','["竹使貪爲郡，金門懶上書。", "征途沿木合，官舍類樓居。", "密葉藏啼鳥，澄潭躍戲魚。", "波光搖島嶼，霽色露閻閭。", "圃蕙光風拂，山苗淑氣噓。", "開樽空愛客，函丈孰宗予。", "清唳頻思鶴，長鳴幾厭驢。", "顔貧一瓢足，嵇懶尺題疏。", "薄宦無勞說，長謠任所如。", "神明定來舍，莊室正虚虚。"]'),
('ba22f301-2f49-4b75-83bc-678d8cf6bae0','次韻和章頔見寄','楊億','宋','宋诗','song-poetry','','[]','雞窗十載共論文，蘭室依然有舊薫。',64,'全唐诗/poet.song.6000.json','["雞窗十載共論文，蘭室依然有舊薫。", "雨雪共抛修竹苑，煙霞獨訪武夷君。", "隨珠照乘元無類，天驥追風定不羣。", "犬子賦成猶未獻，飄飄詞氣已凌雲。"]'),
('e66c4706-06ba-419b-8677-ca037e8bf031','孫及歸吳興','楊億','宋','宋诗','song-poetry','','[]','家在霅溪傍，汀蘋遶舍香。',96,'全唐诗/poet.song.6000.json','["家在霅溪傍，汀蘋遶舍香。", "草玄偏寂寞，爲客苦恓惶。", "澤國聊傾蓋，春闈早擅場。", "陔蘭行可採，月桂自應芳。", "税駕臨滄海，迴轅指大梁。", "裂裳趨遠道，負米及高堂。", "季子裘雖敝，安仁鬢未蒼。", "明年杏園裏，輙莫負春光。"]'),
('ffc3121c-5f26-4a27-9bf8-b870b9b7f6cf','己亥年郡中夏旱徧禱羣望喜有甘澤之應','楊億','宋','宋诗','song-poetry','','[]','旱魃偏爲虐，陽烏益以驕。',144,'全唐诗/poet.song.6000.json','["旱魃偏爲虐，陽烏益以驕。", "何曾柱礎潤，惟恐土山焦。", "請禱彌增潔，陰靈亦孔昭。", "雲興不待族，風細欲鳴條。", "隱轔雷車轉，霏微雨足飄。", "層陰低匝野，鴻霈近連宵。", "庭樹含佳色，村田長善苗。", "蘚痕緣屋壁，泉脈吐山椒。", "轍鮒那憂涸，園蔬豈待澆。", "官渠逗水急，客路裛塵銷。", "掾吏階前賀，耕夫壠上謠。", "秋成知有幸，歲欲近玄枵。"]'),
('297d8f98-8c16-489b-8a82-d16e68e5bca8','寄章徵君','楊億','宋','宋诗','song-poetry','','[]','水陸都無數舍程，魚符龜印苦相縈。',128,'全唐诗/poet.song.6000.json','["水陸都無數舍程，魚符龜印苦相縈。", "夢魂長繞龍門坂，姓字終懸月旦評。", "鮑室清琴應獨撫，融樽渌醑共誰傾。", "春深詩石苔衣駮，雨過書齋草带生。", "鴻寶枕中初得術，丹臺籍上已題名。", "清談宛有南朝體，嘉遯全忘北闕情。", "金馬深嚴堪避世，滄浪清淺未沾纓。", "諸儒正議明堂事，軋軋蒲輪即奉迎。"]'),
('3b714d76-32e6-4295-8e16-e5e0aa04eeed','次韻和衢州席刑部早秋','楊億','宋','宋诗','song-poetry','','[]','朱火熒熒向夕流，林間一葉忽驚秋。',64,'全唐诗/poet.song.6000.json','["朱火熒熒向夕流，林間一葉忽驚秋。", "風來野渡聞漁笛，霧斂晴天見蜃樓。", "艶愛芙蓉開幕府，香憐杜若老汀洲。", "使君鬢畔多玄髪，臨水登山不用愁。"]'),
('86715237-8ce2-4cc9-8e76-2697073a862a','次韻和席衢州憶洛陽春遊十四韻','楊億','宋','宋诗','song-poetry','','[]','周漢經營跡未遐，山川形勝最堪嘉。',224,'全唐诗/poet.song.6000.json','["周漢經營跡未遐，山川形勝最堪嘉。", "前瞻闕塞千尋出，旁逗伊流一派斜。", "子晉鳳笙調夜月，宓妃羅襪映朝霞。", "何人貰酒青樓曉，幾處尋春紫陌賒。", "駿足每從金埒試，芳叢多展翠帷遮。", "出逢勝境爭飛蓋，歸逼殘陽競走車。", "庭竹惹煙披嫩籜，臯蘭裛露長新芽。", "嵩峰崷崪疑摩斗，洛水清泠欲見沙。", "萬井閭閻真陸海，九重宫闕是天家。", "禁林日暖空啼鳥，御苑風微自落花。", "關路行人偏絡繹，津橋賈客苦諠譁。", "何當獻賦論遷鼎，便欲抛官學種瓜。", "江海三年勞夢想，田園二頃有生涯。", "應知父老沾堯化，長挈壺漿望翠華。"]'),
('7b5ab944-a46a-4025-8f83-0ffe4b283191','聞道卿途中授計司判官','楊億','宋','宋诗','song-poetry','','[]','幾年華省冠名曹，歸棹夤緣入海濤。',96,'全唐诗/poet.song.6000.json','["幾年華省冠名曹，歸棹夤緣入海濤。", "纔奉色難馨夕膳，便將心計析秋毫。", "政成婺女生祠在，地近明光伏奏勞。", "夜直乍諳綾被暖，晨趨頻見露盤高。", "共期晝日承三接，莫許秋風長二毛。", "爲郡今來最卑屑，勸君休更夢懸刀。"]'),
('5e1e3ba7-18c7-4a68-9d8f-cbbc36d64133','郡齋西亭夜坐','楊億','宋','宋诗','song-poetry','','[]','凉颸初拂衽，皓魄正當軒。',96,'全唐诗/poet.song.6000.json','["凉颸初拂衽，皓魄正當軒。", "宿鳥林間定，流螢草際翻。", "蒼茫迷野色，嘲哳辯方言。", "角罷重城掩，漁歸别浦喧。", "斷蛩吟壞壁，寒杵出遙村。", "樹影成帷密，灘聲激箭奔。", "夜長風露冷，川迥水煙昏。", "對景都無寐，冥心契混元。"]'),
('a1486f11-c180-4ba3-92d0-cc603da8a2e1','秋晚','楊億','宋','宋诗','song-poetry','','[]','秋晚彌岑寂，天空見泬寥。',96,'全唐诗/poet.song.6000.json','["秋晚彌岑寂，天空見泬寥。", "溪流拖白練，樹葉翦紅綃。", "露菊英初吐，霜鐘韻漸調。", "清光開旭旦，爽氣逐驚飈。", "鷹擊秦原迥，鴻歸楚水遙。", "星高漢將出，膠折虜兵驕。", "元亮田多廢，安仁鬢恐凋。", "功名殊未立，對景自無憀。"]'),
('f3d343df-077d-44dd-b41a-8b117f39247c','送温州聶從事赴闕','楊億','宋','宋诗','song-poetry','','[]','佩鞬來海上，七見歲星移。',96,'全唐诗/poet.song.6000.json','["佩鞬來海上，七見歲星移。", "務劇操刀割，書成插羽馳。", "詩傳百越徧，詔下九霄遲。", "束带朝閶闔，歸艎汎渺瀰。", "舊遊聊税駕，雅飲且軒眉。", "鄭驛歡相接，牙絃辱所知。", "病驚瓊樹瘦，醉露玉峰奇。", "上馬便西笑，何須訴酒巵。"]'),
('53e2cf49-0067-48e5-883b-be3a33059ae9','送章安世赴舉','楊億','宋','宋诗','song-poetry','','[]','螢燭辛勤十載餘，藹然高價滿州閭。',64,'全唐诗/poet.song.6000.json','["螢燭辛勤十載餘，藹然高價滿州閭。", "一枝未折仙人桂，千里又隨鄉老書。", "梁苑雪花成賦後，禹門雷鼓化鱗初。", "山城日日望春榜，莫遣南來音信疏。"]'),
('35a2f259-0f28-4e7a-afd8-896b3fec58c0','偶興','楊億','宋','宋诗','song-poetry','','[]','芳蘭滋九畹，蕭蒿亦旁植。',288,'全唐诗/poet.song.6000.json','["芳蘭滋九畹，蕭蒿亦旁植。", "威鳳翔丹山，鴟梟猶接翼。", "雅琴歌南風，蛙鳴不容息。", "驪珠媚清川，魚目光激射。", "薫蕕豈同器，雲壤自懸隔。", "咄咄來逼人，薨薨止于棘。", "發跡由屠沽，操心希桀跖。", "天形固殘毁，吏曹嘗擯斥。", "狠羊遠刀杌，黠馬委銜策。", "心同溪壑險，惡比邱山積。", "天聽本聰明，神道尤正直。", "當用禦魑魅，豈令爲鬼蜮。", "舂喉魯陽戈，鉤頸子雲戟。", "肉委餓虎蹊，屍投窮髪北。", "饑鷹礪吻啄，猰貐磨牙食。", "魂氣縶酆都，膏血塗荒磧。", "去草絕本根，决疽恣鍼石。", "所居必污潴，遺種盡刳剔。", "渠魁已殱殄，非類彌怵惕。", "稂莠既芟夷，善苗漸滋殖。", "君子益知命，視履如平昔。", "小人競革音，滅身在漏刻。", "堯民率可封，湯網從此釋。", "永躋仁壽期，共造華胥域。"]'),
('6f33b941-bccc-4e2b-b4d8-40c38c441141','到郡滿歲自遣','楊億','宋','宋诗','song-poetry','','[]','迢遞分符竹，因循度歲華。',72,'全唐诗/poet.song.6000.json','["迢遞分符竹，因循度歲華。", "地將鯨海接，路與鳳城賒。", "觸石雲頻起，銜山日易斜。", "潮平聚漁市，水落見人家。", "吏隱偏知幸，民謠豈敢誇。", "無嫌勾漏僻，且得養丹砂。"]'),
('08651cbd-6edc-401f-b9d2-4d7d7de4412a','己亥年十月十七日大雪','楊億','宋','宋诗','song-poetry','','[]','六出俄呈瑞，三農始告休。',96,'全唐诗/poet.song.6000.json','["六出俄呈瑞，三農始告休。", "兔園陳旨酒，金屋御重裘。", "壠麥青猶短，臯蘭紫尚稠。", "嚴飈一夕起，瑞霰滿空浮。", "林迥瓊花吐，峰孤玉笋抽。", "疏鱗鏤屋瓦，淨練曳溪流。", "北戶寒威盛，南方沴氣收。", "時和人富壽，卒歲好優游。"]'),
('5a2ec0f2-4b61-4cf8-8c5d-358fd439438b','郡中即事書懷','楊億','宋','宋诗','song-poetry','','[]','海隅爲郡真卑屑，簿領沉迷箠楚喧。',128,'全唐诗/poet.song.6000.json','["海隅爲郡真卑屑，簿領沉迷箠楚喧。", "王事更逾星火急，吏曹何啻米鹽煩。", "甘棠聽訟曾無倦，丹筆書刑幸不冤。", "境上送迎暫置驛，齋中宴喜懶開樽。", "逢人未免腰如磬，議政常防耳屬垣。", "鮑臭恐將羣小化，蟲疑難與俗流論。", "却思寂寞棲天禄，爭得逍遙似漆園。", "外地粗官如竹葦，一麾出守豈堪言。"]'),
('4cc0d670-b255-435c-802c-3dfa525f938c','次韻和潤州劉度支見寄之什','楊億','宋','宋诗','song-poetry','','[]','卜隱林泉未有期，春田耕事欲憑誰。',64,'全唐诗/poet.song.6000.json','["卜隱林泉未有期，春田耕事欲憑誰。", "一辭左掖鴛鸞侣，兩見南州橘柚垂。", "酌醴不妨留客醉，飲冰長是畏人知。", "頒條求瘼無他術，深恨期年報政遲。"]'),
('7270e3de-6efe-4694-9c51-8e6f629033ce','郡民以歲稔刑清相率爲齋以報善政永嘉聶從事賦詩紀其事因依韻足成一百言以謝之','楊億','宋','宋诗','song-poetry','','[]','爲郡臨甌越，雲泉興未乖。',120,'全唐诗/poet.song.6000.json','["爲郡臨甌越，雲泉興未乖。", "歡謠乏襦袴，歸思滿荆柴。", "偶遂豐年望，潛將樂土偕。", "流民爭襁負，兇黨絕椎埋。", "精力姦多露，清心政自諧。", "羣生不疵癘，比屋已綏懷。", "輙詣金人宇，同修香積齋。", "漫勞歌邵父，方待拍洪崖。", "治行非尤異，傳聞及等儕。", "雕章忽垂贈，屬和愧淫哇。"]'),
('7ddbfc3e-c8e3-4031-9fc7-cac349e16428','歲暮有懷','楊億','宋','宋诗','song-poetry','','[]','遠辭金虎觀，來守縉雲城。',96,'全唐诗/poet.song.6000.json','["遠辭金虎觀，來守縉雲城。", "鳴律行將盡，枯荄又向榮。", "匏瓜宣父歎，江海子牟情。", "求瘼曾無術，投虛豈有聲。", "帝鄉成久别，天吏苦遄征。", "漫貯青霞想，唯愁素髪生。", "澄清慵攬轡，蕪穢欲歸耕。", "簿領非吾事，丹臺有姓名。"]'),
('21c3668f-2c40-4c95-97b5-5326a8ee7c7c','次韻和酬永嘉聶從事除夜之什','楊億','宋','宋诗','song-poetry','','[]','三百六旬今夜盡，寥寥虛室獨凝神。',64,'全唐诗/poet.song.6000.json','["三百六旬今夜盡，寥寥虛室獨凝神。", "蓮城五鼓欲催曉，梅嶺一枝先報春。", "鄒律漸吹陰谷暖，堯蓂看傍土階新。", "海隅留滯年華長，坐對寒釭浩歎頻。"]'),
('31ce27f9-cfa4-4cc3-8530-9894f084bb65','章徵君見和所寄詩再次本韻酬贈','楊億','宋','宋诗','song-poetry','','[]','武夷山秀建溪清，身隱心閑事不縈。',128,'全唐诗/poet.song.6000.json','["武夷山秀建溪清，身隱心閑事不縈。", "前古是非爲己任，故鄉人物與誰評。", "勸農春壠巾頻折，逢客秋郊蓋暫傾。", "綵服趨翔娛壽母，絳帷談論誘諸生。", "潁流洗耳殊非達，谷口躬耕亦近名。", "博奕自堪銷永日，絲桐兼得助高情。", "莫嫌霜雪將侵鬢，須歎塵埃漸滿纓。", "早晚鳴騶催上道，聖君虛左欲相迎。"]'),
('2e8148c6-8ed0-4053-9ede-85be8ceac1a8','中春喜雨','楊億','宋','宋诗','song-poetry','','[]','土膏初脉起，東作向農時。',72,'全唐诗/poet.song.6000.json','["土膏初脉起，東作向農時。", "隱轔雷車轉，霏微雨足垂。", "龍蛇爭奮躍，桃李漸離披。", "流潤先從葉，餘波更及私。", "謳謠耕父喜，滲漉稻畦滋。", "連夜空階滴，愁吟水部詩。"]'),
('73162169-f53a-4441-beb5-1d074f03e1cf','聞北師克捷喜而成詠','楊億','宋','宋诗','song-poetry','','[]','歲晏增冰合，煙塵起羯陲。',72,'全唐诗/poet.song.6000.json','["歲晏增冰合，煙塵起羯陲。", "文昌先命將，羽檄便徵師。", "天迥星狼滅，宵寒月魄虧。", "前軍臨瀚海，後騎縳閼氏。", "薊北胡沙靜，河南露版馳。", "遼陽諸父老，重睹漢官儀。"]'),
('e23ec850-9d4c-4224-b810-747df926b22b','洞溪慶道人歸上都','楊億','宋','宋诗','song-poetry','','[]','精廬宴坐十經秋，瓶鉢近爲千里遊。',64,'全唐诗/poet.song.6000.json','["精廬宴坐十經秋，瓶鉢近爲千里遊。", "又是浮杯過滄海，便應飛錫入皇州。", "彌天談論降時彦，結社因緣背俗流。", "此去定知諸念息，只除魂夢到東甌。"]'),
('138680d5-a61a-4935-be8b-e2fbc5c1577b','春郊即事','楊億','宋','宋诗','song-poetry','','[]','黄鸝百囀宿煙疏，近郭行春獨駐車。',64,'全唐诗/poet.song.6000.json','["黄鸝百囀宿煙疏，近郭行春獨駐車。", "壠上勸耕聊問訊，棠陰聽訟且躊躇。", "遠林桑盡蠶成繭，野水萍開獺趁魚。", "幾處路旁垂苦李，游人不折意何如。"]'),
('7e2f2e23-8ea4-4935-95ee-f116d0ea7eef','偶書','楊億','宋','宋诗','song-poetry','','[]','朱輪遠守未成歡，薄宦令人意漸闌。',64,'全唐诗/poet.song.6000.json','["朱輪遠守未成歡，薄宦令人意漸闌。", "郡閣政清慵按吏，鄉園路近欲休官。", "梅花遶檻驚春早，布水當簷覺夏寒。", "已是三年不聞問，何如歸去把魚竿。"]'),
('878ceb6c-516c-44aa-8bbc-35c8dd7db621','太常李博士史館孫秘丞相繼奉使浙右博士至郡以孫侯詩三章示予且以致意因次韻和酬  其一','楊億','宋','宋诗','song-poetry','','[]','迅瀨拖舟上，危梯躡屐登。',48,'全唐诗/poet.song.6000.json','["迅瀨拖舟上，危梯躡屐登。", "山光翠欲滴，水氣熱如蒸。", "路轉藤蘿暗，天開物象澄。", "邱園足逋客，應得薦賢能。"]'),
('f39d55a7-2f08-438f-a19b-1994cf4f1437','太常李博士史館孫秘丞相繼奉使浙右博士至郡以孫侯詩三章示予且以致意因次韻和酬  其二','楊億','宋','宋诗','song-poetry','','[]','分憂從漢殿，捧詔出蕭墻。',48,'全唐诗/poet.song.6000.json','["分憂從漢殿，捧詔出蕭墻。", "路入三吳遠，舟浮一水長。", "詩題石門側，夢徹斗城傍。", "清曉見雲物，依依認帝鄉。"]'),
('3a505da3-e1f1-453d-8a25-6e28ae94a9f0','太常李博士史館孫秘丞相繼奉使浙右博士至郡以孫侯詩三章示予且以致意因次韻和酬  其三','楊億','宋','宋诗','song-poetry','','[]','北極分憂矚，東甌布惠和。',48,'全唐诗/poet.song.6000.json','["北極分憂矚，東甌布惠和。", "曾蒙傾蓋分，偶得枉帆過。", "鄭驛非常速，融樽復幾何。", "孫侯不假道，鄙我信爲多。"]'),
('b5996fa9-efdd-47a5-a4a6-5349c5c67105','麗水甄殿丞手植朱李繁實盈枝折以貺予感而成詠','楊億','宋','宋诗','song-poetry','','[]','五年爲邑鬢霜侵，吏隱由來得趣深。',64,'全唐诗/poet.song.6000.json','["五年爲邑鬢霜侵，吏隱由來得趣深。", "不獨絃歌長滿耳，兼聞桃李已成陰。", "晨昏我有南陔戀，江海君懷北闕心。", "早晚飛沉俱遂志，願將初服敵華簪。"]'),
('f4fb1b16-6c9e-461f-a249-3a53e304419e','聞揚州柴給事有弄璋之慶寄詩賀之','楊億','宋','宋诗','song-poetry','','[]','華堂何夕夢熊羆，衛氏如今有一兒。',64,'全唐诗/poet.song.6000.json','["華堂何夕夢熊羆，衛氏如今有一兒。", "三日懸弧應是喜，十年結實未爲遲。", "預知駟馬門閭盛，暗想天麟骨法奇。", "曾忝門牆攝齊者，待看孔鯉學聞詩。"]'),
('39ddc1ed-52d7-473d-af3b-9a1fe81ff2be','題張濬所居壁','楊億','宋','宋诗','song-poetry','','[]','三張舊族富英髦，仙墅重經散鬱陶。',64,'全唐诗/poet.song.6000.json','["三張舊族富英髦，仙墅重經散鬱陶。", "深喜太邱家法在，須知定國里門高。", "分題毎日搖雞距，合宴常時把蟹螯。", "獨感戴侯恩未報，徘徊不覺涕沾袍。"]'),
('41704c26-b05e-400f-b5bc-2a6ea3a1451c','留題南源院','楊億','宋','宋诗','song-poetry','','[]','路入藤蘿十里餘，松窗瀟灑竹房虛。',64,'全唐诗/poet.song.6000.json','["路入藤蘿十里餘，松窗瀟灑竹房虛。", "鷰巢新舊金人殿，蟲網縱横貝葉書。", "當晝風雷生洞穴，欲齋猿鳥下庭除。", "昔年曾此題詩句，猶拂流塵認魯魚。"]'),
('572aa75b-ea5d-40c0-830c-440f70184678','留題張彝憲池亭','楊億','宋','宋诗','song-poetry','','[]','瀟灑危亭枕碧池，昔年飛蓋此追隨。',64,'全唐诗/poet.song.6000.json','["瀟灑危亭枕碧池，昔年飛蓋此追隨。", "正逢五綵承顔日，兼是三荆並秀時。", "夜坐不知銀漢沒，春遊長訴玉杯遲。", "如今罷郡重登賞，喜見扶風舊白眉。"]'),
('fee41dc8-d29f-4f74-a9b0-6478984c3b1b','别聰道人歸縉雲','楊億','宋','宋诗','song-poetry','','[]','二年假守栝蒼城，郡榻唯師即送迎。',64,'全唐诗/poet.song.6000.json','["二年假守栝蒼城，郡榻唯師即送迎。", "擣藥幾憐春漏永，調琴長待夜蟾生。", "心猿已伏都無念，海鳥相逢自不驚。", "送别秋郊豈成恨，白雲青嶂是歸程。"]'),
('3b594feb-f1ac-4e75-80e3-2dda4ab65d8d','題張居士壁','楊億','宋','宋诗','song-poetry','','[]','疊巘參差翠遶門，雕梁賀燕自成羣。',64,'全唐诗/poet.song.6000.json','["疊巘參差翠遶門，雕梁賀燕自成羣。", "殺雞日夕期嘉客，種竹寒暄對此君。", "且向東臯輸黍稷，便應北闕降玄纁。", "子真漫說耕岩石，不奈聲名四遠聞。"]');
